/* AUTO-GENERATED — Oklahoma Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["OK"] = {"code":"OK","name":"Oklahoma","agency":"Oklahoma SOK","agencyShort":"SOK","handbook":"https://oklahoma.gov/service/popular-services/cdl.html","links":{},"en":[{"q":"On Oklahoma highways, what is the maximum total outside width of a vehicle, with or without load, before an over-width permit is required?","options":["96 inches","102 inches","108 inches","120 inches"],"answer":1,"explanation":"Oklahoma limits total outside width to 102 inches (8.5 ft); greater width requires an over-width permit. Source: 47 O.S. §14-103.","handbook":"","hbref":""},{"q":"What is the maximum legal height for a vehicle or load on an Oklahoma turnpike, interstate, U.S., or state highway without a special permit?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"answer":2,"explanation":"Oklahoma allows up to 14 feet in height on turnpikes, interstate, U.S., and state highways without a permit. Source: 47 O.S. §14-103.","handbook":"","hbref":""},{"q":"What is the maximum height for a vehicle or load on an Oklahoma COUNTY road without a special permit?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"answer":0,"explanation":"On county roads the height limit is 13.5 feet, lower than the 14-foot limit allowed on turnpikes, interstate, U.S., and state highways. Source: 47 O.S. §14-103.","handbook":"","hbref":""},{"q":"In Oklahoma, what is the maximum allowable weight on any single axle without an over-weight permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"Oklahoma's single-axle weight limit is 20,000 pounds. Source: 47 O.S. §14-109(A).","handbook":"","hbref":""},{"q":"What is the maximum weight Oklahoma allows on a set of tandem axles without a special permit?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"The maximum load on any set of tandem axles in Oklahoma is 34,000 pounds. Source: 47 O.S. §14-109(B).","handbook":"","hbref":""},{"q":"What is the general maximum gross vehicle weight on Oklahoma highways under the weight table without a special permit?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"answer":2,"explanation":"Oklahoma's weight table caps legal gross weight at 80,000 pounds, consistent with the federal limit. Source: 47 O.S. §14-109(A).","handbook":"","hbref":""},{"q":"Allowable gross and axle weights in Oklahoma are determined using a formula based on axle spacing. What is this formula commonly called?","options":["Federal Bridge Formula","Gross Combination Rule","Tare Weight Formula","Axle Spread Ratio"],"answer":0,"explanation":"Oklahoma uses the Federal Bridge Formula/weight table (23 U.S.C. §127), measuring distance between extreme axles to the nearest foot. Source: 47 O.S. §14-109; ODPS Troop S.","handbook":"","hbref":""},{"q":"What is the maximum overall length of a SINGLE truck (not a combination), including bumpers, on Oklahoma roads?","options":["40 feet","45 feet","53 feet","70 feet"],"answer":1,"explanation":"A single truck may not exceed 45 feet in overall length, including front and rear bumpers, in Oklahoma. Source: 47 O.S. §14-103.","handbook":"","hbref":""},{"q":"On the National Network, what is the maximum semitrailer length in a truck-tractor/semitrailer combination in Oklahoma (without a permit)?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"answer":1,"explanation":"A semitrailer in a truck-tractor/semitrailer combination may be up to 53 feet on the National Network; longer (to 59'6\") requires a permit. Source: 47 O.S. §14-103.","handbook":"","hbref":""},{"q":"What is the maximum overall length for combinations of vehicles OTHER than a truck-tractor/semitrailer on all Oklahoma roads and highways?","options":["65 feet","70 feet","75 feet","80 feet"],"answer":1,"explanation":"Other combinations of vehicles may not exceed 70 feet overall, including bumpers, on all Oklahoma roads and highways. Source: 47 O.S. §14-103.","handbook":"","hbref":""},{"q":"Which Oklahoma agency division issues oversize/overweight permits for travel on the state highway system?","options":["The Oklahoma Tax Commission","The ODOT Size and Weight Permit Division","The Corporation Commission","The county sheriff's office"],"answer":1,"explanation":"The ODOT Size and Weight Permit Division issues oversize/overweight permits (applied for online at swpermitsok.com). Source: ODOT; OAC 730:50-5.","handbook":"","hbref":""},{"q":"A truck and semitrailer combination may operate under a special ANNUAL over-width permit in Oklahoma up to what maximum width?","options":["108 inches","114 inches","120 inches","144 inches"],"answer":2,"explanation":"Combinations exceeding 102 but not exceeding 120 inches in width may operate under a special annual over-width permit. Source: OAC 730:50-5; 47 O.S. §14-103G.","handbook":"","hbref":""},{"q":"Under Oklahoma rules, a permitted load wider than 12 feet but not more than 14 feet must have which escort arrangement on a two-lane highway?","options":["No escort required","A front escort vehicle","A rear escort vehicle","Both front and rear escorts"],"answer":1,"explanation":"Loads over 12 ft but not over 14 ft wide need a front escort on two-lane/super two-lane highways (rear escort on multi-lane). Source: OAC 730:50-5-18(b).","handbook":"","hbref":""},{"q":"At what overall HEIGHT does an Oklahoma permitted load require TWO escort vehicles (one front, one rear) and advance notice to utilities and railroads?","options":["14 feet or more","14 feet 6 inches or more","15 feet or more","15 feet 9 inches or more"],"answer":3,"explanation":"Loads with an overall height of 15 feet 9 inches or more require two escorts and advance contact with affected utilities/railroads. Source: OAC 730:50-5-18(b).","handbook":"","hbref":""},{"q":"A truck-tractor/semitrailer combination of what overall length triggers a required front escort on Oklahoma two-lane highways?","options":["More than 70 feet","More than 75 feet","More than 80 feet","More than 100 feet"],"answer":2,"explanation":"A truck-tractor/semitrailer combination more than 80 feet overall requires a front escort on two-lane highways. Source: OAC 730:50-5-18(b)(4).","handbook":"","hbref":""},{"q":"Under Oklahoma's agricultural-products weight variance (per ODPS Troop S), what tolerances apply, and where is travel prohibited?","options":["5% over gross and 8% over axle limits; not on interstate highways","10% over gross and 10% over axle; not on turnpikes","8% over gross and 5% over axle; not on county roads","5% over gross and 5% over axle; interstate allowed"],"answer":0,"explanation":"Vehicles hauling agricultural products at max registration may run up to 5% over gross and 8% over axle limits, but not on the Interstate system. Source: ODPS Troop S; 47 O.S. §14-109.","handbook":"","hbref":""},{"q":"With an agricultural weight variance permit allowing about 8% over the axle limit, the single-axle figure of 20,000 pounds becomes approximately what?","options":["20,800 pounds","21,600 pounds","22,400 pounds","24,000 pounds"],"answer":1,"explanation":"With the variance (8% over axle), the 20,000-lb single-axle limit becomes 21,600 lbs; exceeding any category voids the permit for that trip. Source: ODPS Troop S axle table.","handbook":"","hbref":""},{"q":"Oklahoma's ODOT Annual Envelope Vehicle Permit authorizes a vehicle up to which maximum dimensions on the state highway system?","options":["10 ft wide, 13.5 ft high, 90 ft long","12 ft wide, 14 ft high, 110 ft long","14 ft wide, 15 ft high, 120 ft long","12 ft wide, 16 ft high, 100 ft long"],"answer":1,"explanation":"The Annual Envelope Vehicle Permit covers vehicles up to 12 ft wide, 14 ft high, and 110 ft long (fee $4,000), valid only on the state highway system. Source: OAC 730:50-5-13.","handbook":"","hbref":""},{"q":"Haulers of raw forest products in their natural state in Oklahoma may obtain a $25 annual agriculture permit, but with what route limitation?","options":["No travel on the Interstate system","No travel on any turnpike","No travel on county roads","No travel at night only"],"answer":0,"explanation":"Raw forest-products hauling under the $25 annual agriculture permit is not permitted on the National System of Interstate and Defense Highways. Source: OAC 730:50-5-22; 47 O.S. §14-118(e).","handbook":"","hbref":""},{"q":"In Oklahoma, which CDL class is required to operate any combination of vehicles with a gross combination weight rating (GCWR) of 26,001 or more pounds when the vehicle being towed has a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Oklahoma adopts the federal classification: a Class A CDL covers any combination of vehicles with a GCWR of 26,001+ lbs where the towed unit(s) exceed 10,000 lbs GVWR. Source: Oklahoma Statutes Title 47 Sec. 6-101 and the Oklahoma CDL Manual (Service Oklahoma).","handbook":"","hbref":""},{"q":"An Oklahoma driver operates a single straight truck with a GVWR of 30,000 pounds that tows no trailer. Which CDL class does this require?","options":["Class A","Class B","Class C","No CDL is required"],"answer":1,"explanation":"A Class B CDL covers any single vehicle with a GVWR of 26,001+ lbs (or such a vehicle towing a unit not over 10,000 lbs GVWR). A 30,000-lb straight truck falls under Class B. Source: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101.","handbook":"","hbref":""},{"q":"Under Oklahoma rules, a vehicle that does not meet the Class A or Class B weight thresholds still requires a Class C CDL if it does what?","options":["Has a GVWR over 16,000 pounds","Is designed to transport 16 or more people including the driver, or carries placardable hazardous materials","Tows any trailer rated over 5,000 pounds","Is operated for hire across county lines"],"answer":1,"explanation":"A Class C CDL applies to a vehicle not meeting Class A or B that is designed to transport 16 or more passengers (including the driver) or that carries hazardous materials requiring placards. Source: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101.","handbook":"","hbref":""},{"q":"Which endorsement code must be added to an Oklahoma CDL to transport materials designated as hazardous and requiring placarding?","options":["N","T","H","P"],"answer":2,"explanation":"The H (Hazardous Materials) endorsement is required to haul placardable hazardous materials. Source: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma).","handbook":"","hbref":""},{"q":"What is the federal/Oklahoma capacity threshold that defines a 'tank vehicle' requiring the N (Tanker) endorsement?","options":["A tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more","A tank with an individual rated capacity of more than 100 gallons","Any tank carrying 500 gallons or more total","A tank with an aggregate capacity of 2,000 gallons or more"],"answer":0,"explanation":"The N endorsement is required for vehicles transporting liquids or gases in a tank with an individual rated capacity over 119 gallons AND an aggregate rated capacity of 1,000 gallons or more. Source: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.5.","handbook":"","hbref":""},{"q":"Which Oklahoma CDL endorsement is required to pull double or triple trailers, and which CDL class must the driver already hold?","options":["T endorsement, held with a Class A CDL","T endorsement, held with a Class B CDL","N endorsement, held with a Class A CDL","P endorsement, held with a Class C CDL"],"answer":0,"explanation":"The T (Doubles/Triples) endorsement allows pulling multiple trailers and is added by Class A drivers, who must demonstrate the additional knowledge required. Source: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma).","handbook":"","hbref":""},{"q":"An Oklahoma driver wants to drive a vehicle designed to carry 16 or more people including the driver. Which endorsement is required?","options":["S (School Bus)","P (Passenger)","N (Tanker)","T (Doubles/Triples)"],"answer":1,"explanation":"The P (Passenger) endorsement is required to operate a vehicle designed to carry 16 or more people including the driver; it requires passing a knowledge test and a skills test in a representative vehicle. Source: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma).","handbook":"","hbref":""},{"q":"Before an Oklahoma driver can obtain the School Bus (S) endorsement, which other endorsement is a prerequisite?","options":["The H (HazMat) endorsement","The N (Tanker) endorsement","The P (Passenger) endorsement","The T (Doubles/Triples) endorsement"],"answer":2,"explanation":"The S (School Bus) endorsement requires the driver to first hold the P (Passenger) endorsement, then pass a school bus knowledge test and a skills test in a school bus. Source: Oklahoma CDL Manual / Endorsements (Service Oklahoma); 49 CFR 383.93.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Oklahoma CDL restricted to intrastate (within-Oklahoma) operation only?","options":["16","18","21","25"],"answer":1,"explanation":"A driver must be at least 18 to hold an intrastate-only Oklahoma CDL; drivers under 21 receive a 'K' intrastate-only restriction. Source: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101.","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a CDL vehicle in interstate commerce (across state lines) from Oklahoma?","options":["18","19","21","23"],"answer":2,"explanation":"Interstate CDL operation requires a minimum age of 21; drivers 18 to 20 are limited to intrastate operation within Oklahoma. Source: Oklahoma CDL Manual (Service Oklahoma); 49 CFR 391.11.","handbook":"","hbref":""},{"q":"After passing the required knowledge tests in Oklahoma, how long must an applicant hold a Commercial Learner Permit (CLP) before taking the CDL skills (drive) test?","options":["7 full days","10 full days","14 full days","30 full days"],"answer":2,"explanation":"Federal and Oklahoma rules require holding the CLP for 14 full days before the skills test; the test may be taken on the 15th day. Source: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"For how long is an Oklahoma Commercial Learner Permit (CLP) valid, and how may it be extended?","options":["90 days, non-renewable","180 days, renewable one time for an additional 180 days","1 year, renewable annually","60 days, renewable up to three times"],"answer":1,"explanation":"An Oklahoma CLP is issued for 180 days and may be renewed one time for an additional 180 days. Source: Oklahoma CDL Manual / Service Oklahoma; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which set of documents must a first-time Oklahoma CDL applicant present at a Service Oklahoma licensing office?","options":["Only a valid Class D license and a birth certificate","Proof of identity, proof of lawful presence, Social Security number, and proof of Oklahoma residency","Only a Social Security card and an employer letter","A passport and proof of vehicle insurance"],"answer":1,"explanation":"Service Oklahoma requires proof of identity, lawful presence, the applicant's SSN, and Oklahoma residency (one residency document standard, two for REAL ID), plus a valid Class D license. Source: Oklahoma CDL First-Time Applicants (Service Oklahoma).","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) for a first-time Oklahoma CDL applicant must be completed through which official system?","options":["The Oklahoma Department of Education portal","The FMCSA Training Provider Registry","The TSA Hazmat Threat Assessment Program","The Oklahoma Tax Commission registry"],"answer":1,"explanation":"ELDT must be provided by a school listed on the FMCSA Training Provider Registry, which reports completion electronically. Source: FMCSA ELDT rule (49 CFR Part 380); Oklahoma CDL First-Time Applicants (Service Oklahoma).","handbook":"","hbref":""},{"q":"Which of these requires ELDT (Entry-Level Driver Training) before the skills/knowledge test under FMCSA rules applied in Oklahoma?","options":["Obtaining the Tanker (N) endorsement","Obtaining the Doubles/Triples (T) endorsement","Obtaining the Passenger (P) or School Bus (S) endorsement for the first time","Renewing an existing Class A CDL"],"answer":2,"explanation":"ELDT is required for a first-time Class A or B CDL, a B-to-A upgrade, and first-time H, P, or S endorsements. The N and T endorsements are NOT ELDT-regulated. Source: FMCSA ELDT rule (49 CFR Part 380); Service Oklahoma.","handbook":"","hbref":""},{"q":"For the Hazardous Materials (H) endorsement, the ELDT requirement applied in Oklahoma consists of what?","options":["Theory instruction only","Behind-the-wheel instruction only","Both theory and behind-the-wheel instruction","No training at all"],"answer":0,"explanation":"ELDT for the H endorsement is theory-only; only Class A/B CDLs and the P and S endorsements require both theory and behind-the-wheel training. Source: FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"In addition to passing the HazMat knowledge test, what does an Oklahoma driver need to obtain or keep the H endorsement?","options":["A TSA security threat assessment (background check) that is valid for 5 years","A second skills test in a tank vehicle","A notarized employer sponsorship letter","A separate state HazMat permit renewed annually"],"answer":0,"explanation":"The H endorsement requires a TSA Hazmat Threat Assessment (background check/fingerprinting); clearance is valid for 5 years and must be renewed with the endorsement. Source: TSA HTAP; 49 CFR 1572; Service Oklahoma CDL.","handbook":"","hbref":""},{"q":"Which endorsement code is issued on an Oklahoma CDL for a driver authorized to operate a tank vehicle that carries placardable hazardous materials (combined HazMat and Tank)?","options":["HN","X","T","Z"],"answer":1,"explanation":"Oklahoma issues the combined endorsement code 'X' for drivers who hold both Tank (N) and Hazardous Materials (H) authority. Source: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.153.","handbook":"","hbref":""},{"q":"How many medical self-certification categories does an Oklahoma CDL applicant choose from, and which one requires a DOT medical examiner's certificate?","options":["Two categories; the Excepted Interstate category requires the medical card","Four categories; the Non-Excepted Interstate (NI) category requires the medical card","Three categories; the Non-Excepted Intrastate category requires the medical card","Four categories; the Excepted Intrastate (EA) category requires the medical card"],"answer":1,"explanation":"There are four self-certification categories (NI, EI, NA, EA). Only Non-Excepted Interstate (NI) drivers must provide and maintain a valid DOT medical examiner's certificate. Source: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"An Oklahoma CDL or CLP carries which restriction code when the holder may not operate commercial vehicles outside the state of Oklahoma?","options":["E","L","K","Z"],"answer":2,"explanation":"The 'K' restriction means intrastate only - the driver cannot leave Oklahoma in a CDL vehicle (commonly applied to drivers under 21). 'E' = no manual transmission, 'L' = no air brakes, 'Z' = no full air brakes. Source: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma).","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle (CMV) in Oklahoma, a driver is considered legally impaired and commits a major offense at what blood alcohol concentration (BAC)?","options":["0.02 or greater","0.04 or greater","0.08 or greater","0.10 or greater"],"answer":1,"explanation":"Oklahoma sets the CMV BAC limit at 0.04 or greater, half the 0.08 limit for non-commercial drivers. Operating a CMV at 0.04 or above is a major offense. Source: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 as adopted by Oklahoma.","handbook":"","hbref":""},{"q":"Under Oklahoma's implied consent law, by driving a commercial motor vehicle a CDL holder is deemed to have agreed to what?","options":["A vehicle inspection at any weigh station","Chemical testing for alcohol or drugs when lawfully requested","Random employer drug testing only","A waiver of the right to a hearing"],"answer":1,"explanation":"Oklahoma's implied consent law deems anyone operating a CMV to have consented to chemical (breath, blood, or urine) testing for alcohol or controlled substances when lawfully requested. Refusal results in disqualification. Source: Oklahoma CDL Driver Manual, Section 1; 47 O.S. Section 753 (implied consent).","handbook":"","hbref":""},{"q":"In Oklahoma, refusing to submit to alcohol or drug testing as required by the implied consent law while you hold a CDL is treated as what?","options":["A serious traffic violation","A minor administrative infraction","A major offense subject to disqualification","No CDL consequence, only a fine"],"answer":2,"explanation":"Refusing a required test is classified as a major offense in Oklahoma, carrying the same disqualification as a positive test. A first refusal results in a 1-year CDL disqualification. Source: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the Oklahoma CDL disqualification period for a driver's FIRST major offense (such as DUI in a CMV) when NOT transporting placarded hazardous materials?","options":["60 days","120 days","1 year","3 years"],"answer":2,"explanation":"A first major offense results in a 1-year CDL disqualification in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"If a driver commits a first major offense while operating a CMV that is required to be placarded for hazardous materials, the Oklahoma disqualification period increases to what?","options":["18 months","2 years","3 years","Lifetime"],"answer":2,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the Oklahoma CDL disqualification for a driver's SECOND major offense?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in a lifetime CDL disqualification in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Using a CMV in the commission of a felony involving manufacturing, distributing, or dispensing a controlled substance carries what Oklahoma CDL penalty?","options":["1-year disqualification","3-year disqualification","10-year disqualification","Lifetime disqualification with no reinstatement"],"answer":3,"explanation":"Using a CMV in a felony involving controlled-substance manufacturing or distribution carries a mandatory lifetime disqualification with no possibility of reinstatement in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period trigger the FIRST disqualification period in Oklahoma, and how long is it?","options":["1 violation; 30 days","2 violations; 60 days","2 violations; 90 days","3 violations; 60 days"],"answer":1,"explanation":"A second serious traffic violation within 3 years (committed in a CMV) results in a 60-day disqualification in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"What is the Oklahoma CDL disqualification for a THIRD serious traffic violation committed within a 3-year period?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"A third serious traffic violation within 3 years results in a 120-day disqualification in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of the following is a SERIOUS traffic violation for an Oklahoma CDL holder?","options":["Parking in a no-parking zone","Speeding 15 mph or more over the posted limit","Driving with an expired registration sticker","Failing to signal a lane change with no traffic present"],"answer":1,"explanation":"Excessive speeding (15 mph or more over the limit) is a listed serious traffic violation. Others include reckless driving, improper lane changes, following too closely, and texting/handheld phone use. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Texting or using a hand-held mobile phone while driving a CMV is classified in Oklahoma as which type of violation?","options":["A minor moving violation","A serious traffic violation","A major offense","An out-of-service order violation"],"answer":1,"explanation":"Texting and hand-held mobile phone use while driving a CMV are serious traffic violations that count toward the 2-or-3-in-3-years disqualification. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2, 392.80 and 392.82.","handbook":"","hbref":""},{"q":"A CMV driver in Oklahoma who is caught using a hand-held mobile phone while driving can face a federal civil penalty (driver fine) of up to what amount?","options":["$250","$1,000","$2,750","$11,000"],"answer":2,"explanation":"The driver fine for using a hand-held mobile phone while driving a CMV can be up to $2,750 (employers who allow it can be fined up to $11,000). Source: 49 CFR 392.82; FMCSA mobile phone rule applied in Oklahoma.","handbook":"","hbref":""},{"q":"What is the Oklahoma CDL disqualification for a FIRST railroad-highway grade crossing violation within a 3-year period?","options":["No less than 60 days","No less than 120 days","No less than 1 year","No less than 3 years"],"answer":0,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of no less than 60 days in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the Oklahoma CDL disqualification for a SECOND railroad-highway grade crossing violation within a 3-year period?","options":["60 days","No less than 120 days","No less than 1 year","No less than 2 years"],"answer":1,"explanation":"A second railroad-highway grade crossing violation within 3 years results in a disqualification of no less than 120 days in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the Oklahoma CDL disqualification for a THIRD or subsequent railroad-highway grade crossing violation within a 3-year period?","options":["120 days","180 days","No less than 1 year","Lifetime"],"answer":2,"explanation":"A third or subsequent railroad-highway grade crossing violation within 3 years results in a disqualification of no less than 1 year in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the Oklahoma CDL disqualification for a THIRD or subsequent out-of-service order violation within a 10-year period?","options":["1 year","2 years","No less than 3 years but not more than 5 years","Lifetime"],"answer":2,"explanation":"A third or subsequent out-of-service order violation within 10 years results in disqualification of no less than 3 years but not more than 5 years in Oklahoma. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"An Oklahoma CDL holder is convicted of leaving the scene of an accident involving a CMV they were driving. How is this classified for disqualification purposes?","options":["A serious traffic violation (60-day minimum)","A major offense (1-year minimum, 3 years if hazmat)","An out-of-service order violation","A railroad crossing violation"],"answer":1,"explanation":"Leaving the scene of an accident (hit-and-run) involving a CMV is a major offense, carrying a 1-year disqualification (3 years if placarded hazmat) for a first offense and lifetime for a second. Source: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"In Oklahoma, when a commercial vehicle that is required to stop approaches a railroad-highway grade crossing, where must the driver stop?","options":["No closer than 5 feet and no farther than 25 feet from the nearest rail","No closer than 15 feet and no farther than 50 feet from the nearest rail","No closer than 25 feet and no farther than 75 feet from the nearest rail","No closer than 10 feet and no farther than 100 feet from the nearest rail"],"answer":1,"explanation":"The Oklahoma CDL Manual (Sections 2.15 and 9.6.12) requires drivers who must stop at a railroad crossing to stop within 15 to 50 feet of the nearest rail, then proceed only when sure no train is coming. This mirrors 49 CFR 392.10 as applied in Oklahoma.","handbook":"","hbref":""},{"q":"Which of the following commercial vehicles is NOT required to make a stop at every railroad crossing under Oklahoma rules?","options":["A bus carrying passengers","An empty dry-van trailer carrying no hazardous materials and no passengers","A vehicle displaying hazardous materials placards","A cargo tank used for hazardous materials, whether loaded or empty"],"answer":1,"explanation":"The Oklahoma CDL Manual (Section 9.6.12) lists vehicles that must always stop: placarded vehicles, any vehicle carrying chlorine, cargo tanks used for hazardous materials (loaded or empty), and buses with passengers. A non-placarded freight van carrying no passengers is not on the mandatory-stop list.","handbook":"","hbref":""},{"q":"Under Oklahoma's Move Over law, what is a driver on a highway with two or more lanes in the same direction first required to do when approaching a stopped emergency vehicle or wrecker displaying flashing lights?","options":["Change lanes into a lane not adjacent to the stationary vehicle, if it can be done safely","Come to a complete stop until the emergency vehicle leaves","Sound the horn to warn the emergency personnel","Maintain speed but move within the same lane toward the center line"],"answer":0,"explanation":"Oklahoma's Move Over law (47 O.S. Section 11-314) requires a driver on a multilane road, when it is safe, to change into a lane not adjacent to the stationary emergency vehicle, licensed wrecker, or DOT/Turnpike maintenance vehicle displaying flashing lights.","handbook":"","hbref":""},{"q":"Under Oklahoma's Move Over law, when a driver cannot safely change lanes away from a stopped emergency vehicle, what must the driver do?","options":["Reduce speed to exactly 20 mph in all cases","Stop completely and wait for a signal to proceed","Continue at the posted speed limit but use four-way flashers","Reduce speed to a safe speed for the existing road, weather, and traffic conditions"],"answer":3,"explanation":"Oklahoma's Move Over law (47 O.S. Section 11-314) requires a driver who cannot change lanes to slow to a safe speed for existing conditions. The statute uses a conditions-based standard rather than a single fixed number.","handbook":"","hbref":""},{"q":"If a placarded commercial vehicle must stop on a one-way or divided highway in Oklahoma, at what distances toward approaching traffic must warning devices be placed?","options":["10 feet, 50 feet, and 150 feet","25 feet, 75 feet, and 250 feet","10 feet, 100 feet, and 200 feet","10 feet, 100 feet, and 500 feet"],"answer":2,"explanation":"The Oklahoma CDL Manual (Section 2, warning devices) requires that on a one-way or divided highway, warning devices be placed at 10 feet, 100 feet, and 200 feet toward approaching traffic.","handbook":"","hbref":""},{"q":"On a two-lane Oklahoma road carrying traffic in both directions (undivided), where must a stopped CMV place its three warning devices?","options":["At 10 feet, 100 feet, and 200 feet behind the vehicle only","Within 10 feet of the vehicle, and 100 feet behind and 100 feet ahead of the vehicle","At 50 feet, 100 feet, and 200 feet on the shoulder","Within 10 feet of the vehicle, and 200 feet behind and 200 feet ahead of the vehicle"],"answer":1,"explanation":"The Oklahoma CDL Manual states that on a two-lane two-way or undivided highway, one device goes within 10 feet of the vehicle to mark its location and one each 100 feet ahead of and 100 feet behind the vehicle.","handbook":"","hbref":""},{"q":"After stopping on a roadway or shoulder in Oklahoma, within how many minutes must a CMV driver set out the required warning devices?","options":["5 minutes","15 minutes","30 minutes","10 minutes"],"answer":3,"explanation":"The Oklahoma CDL Manual (Section 2) states that if you must stop on a road or the shoulder of any road, you must put out your emergency warning devices within ten minutes.","handbook":"","hbref":""},{"q":"How many warning devices must an Oklahoma CMV carry for use when the vehicle is parked or disabled?","options":["Two reflective triangles, or 4 fuses, or 2 liquid-burning flares","Four reflective triangles, or 8 fuses, or 4 liquid-burning flares","One reflective triangle, or 3 fuses, or 1 liquid-burning flare","Three reflective triangles, or 6 fuses, or 3 liquid-burning flares"],"answer":3,"explanation":"The Oklahoma CDL Manual lists required warning devices for parked vehicles as three red reflective triangles, or at least 6 fuses, or 3 liquid-burning flares.","handbook":"","hbref":""},{"q":"Under Oklahoma law (47 O.S. Section 11-705), when is a driver traveling in the opposite direction NOT required to stop for a school bus that is loading or unloading children with red lights flashing?","options":["When the bus is on the far side of any painted center line","When traffic is heavy and stopping would be inconvenient","When a center two-way left-turn lane separates the directions of travel","When the roadway is divided by a physical barrier or unpaved median separating the directions of travel"],"answer":3,"explanation":"Oklahoma Statute 47 O.S. Section 11-705 exempts opposing traffic from stopping only when a divided highway with a physical barrier or unpaved median separates the roadways. A painted line or a center turn lane does NOT qualify, so opposing traffic must still stop in those cases.","handbook":"","hbref":""},{"q":"On an undivided two-lane Oklahoma highway, what must a driver meeting a stopped school bus with flashing red lights and an extended stop arm do?","options":["Stop, regardless of the direction of travel, until the bus withdraws the stop arm and turns off the red lights","Slow to 25 mph and pass with caution","Stop only if traveling in the same direction as the bus","Proceed normally because only same-direction traffic must stop"],"answer":0,"explanation":"Under 47 O.S. Section 11-705, on an undivided highway both directions of traffic must stop for a school bus displaying flashing red lights and an extended stop arm, and remain stopped until the bus withdraws the signals.","handbook":"","hbref":""},{"q":"What is the fine for a first conviction of illegally passing a stopped Oklahoma school bus that is loading or unloading children?","options":["A flat $50","A minimum of $100 and up to $500","A minimum of $250 and up to $1,000","A flat $1,500 plus mandatory jail"],"answer":1,"explanation":"Oklahoma Statute 47 O.S. Section 11-705 sets a fine of not less than $100 and up to $500 for a first offense of unlawfully passing a stopped school bus, with escalating penalties (including possible license suspension) for repeat offenses.","handbook":"","hbref":""},{"q":"Under Oklahoma's lane-use law (47 O.S. Section 11-309), on a roadway with four or more lanes, when may a vehicle properly travel in the far-left lane?","options":["Only when overtaking and passing another vehicle, preparing for a left turn, or when traffic/road conditions require it","Any time, as long as the driver maintains the posted speed limit","Only when the right lanes are completely empty","Only between sunrise and sunset"],"answer":0,"explanation":"Oklahoma Statute 47 O.S. Section 11-309 restricts the left lane to passing, preparing for a left turn, or situations where traffic flow or road configuration requires it. A vehicle may not impede the normal flow of traffic by cruising in the left lane, even at the posted limit.","handbook":"","hbref":""},{"q":"What is the highest speed limit that may be posted on sections of Oklahoma turnpikes as authorized by statute?","options":["85 mph","75 mph","80 mph","70 mph"],"answer":2,"explanation":"Under 47 O.S. Section 11-801, the Oklahoma Turnpike Authority may set a speed limit up to 80 mph on approved sections of the turnpike system. Several stretches (for example portions of the Turner and Indian Nation Turnpikes) are posted at 80 mph.","handbook":"","hbref":""},{"q":"When approaching a railroad crossing in Oklahoma, when should the driver of a bus or placarded vehicle activate the four-way flashers?","options":["Approximately 200 feet before the crossing","Approximately 50 feet before the crossing","Approximately 500 feet before the crossing","Only after coming to a complete stop at the crossing"],"answer":0,"explanation":"The Oklahoma CDL Manual (Section 10.4, school bus crossing procedures) directs the driver to activate hazard lights approximately 200 feet before the crossing so following traffic is warned of the upcoming stop.","handbook":"","hbref":""},{"q":"While any part of an Oklahoma commercial vehicle is on a railroad crossing, which action is prohibited?","options":["Shifting or changing gears","Keeping both hands on the steering wheel","Looking and listening for trains","Maintaining a steady speed"],"answer":0,"explanation":"The Oklahoma CDL Manual instructs drivers not to shift gears while crossing the tracks, because a missed shift could leave the vehicle stalled on the crossing. Drivers should select a gear before the crossing and hold it across the tracks.","handbook":"","hbref":""},{"q":"When an Oklahoma school bus stops to discharge students, how far from the students at the stop should the bus be brought to a complete stop?","options":["At least 3 feet away from the students","At least 25 feet away from the students","At least 10 feet away from the students","At least 50 feet away from the students"],"answer":2,"explanation":"The Oklahoma CDL Manual (Section 13 skills test, student discharge) directs the driver to bring the school bus to a complete stop at least 10 feet away from the students at the stop, which keeps students in clear view of the driver.","handbook":"","hbref":""},{"q":"What is Oklahoma's standard legal maximum width for a vehicle and load before an oversize permit from ODOT is required?","options":["8 feet 0 inches","10 feet 0 inches","8 feet 6 inches","9 feet 6 inches"],"answer":2,"explanation":"Per ODOT size-and-weight rules, Oklahoma's legal width limit is 8 feet 6 inches; loads wider than that require an oversize permit. The legal height limit is 13 feet 6 inches.","handbook":"","hbref":""},{"q":"Oklahoma oversize-load movements are generally restricted to which time period?","options":["Only between 9:00 p.m. and 5:00 a.m.","Daylight hours, from 30 minutes before sunrise to 30 minutes after sunset","24 hours a day with no time restriction","Only on weekends and holidays"],"answer":1,"explanation":"ODOT oversize-permit rules limit movement to daylight hours, defined as 30 minutes before sunrise to 30 minutes after sunset, with additional restrictions for adverse weather and reduced visibility.","handbook":"","hbref":""},{"q":"Oklahoma restricts oversize loads on the Interstate System during weekday rush hours in which counties?","options":["Comanche, Garfield, and Payne counties","Muskogee, Pottawatomie, and Carter counties","Oklahoma, Tulsa, and Cleveland counties","Canadian, Rogers, and Wagoner counties"],"answer":2,"explanation":"ODOT oversize rules prohibit oversize loads on the Interstate System in Oklahoma, Tulsa, and Cleveland counties during the weekday rush-hour windows of 7:00-9:00 a.m. and 3:30-6:30 p.m. (Central Time), Monday through Friday.","handbook":"","hbref":""},{"q":"A conviction for a railroad-highway grade crossing violation in a commercial vehicle results in what minimum CDL disqualification in Oklahoma for a first offense?","options":["At least 30 days","At least 120 days","At least one year","At least 60 days"],"answer":3,"explanation":"The Oklahoma CDL Manual (Section 1.3.5) states a CDL holder is disqualified for at least 60 days for a first railroad-crossing violation, at least 120 days for a second within three years, and at least one year for a third within three years.","handbook":"","hbref":""},{"q":"Which Oklahoma state agency issues Commercial Driver Licenses and administers CDL knowledge and skills testing?","options":["Service Oklahoma","The Oklahoma Department of Transportation (ODOT)","The Oklahoma Corporation Commission","The Oklahoma Tax Commission"],"answer":0,"explanation":"Service Oklahoma (which assumed driver licensing duties formerly handled by the Department of Public Safety) issues CDLs and administers CDL testing at its Licensing Offices. Source: Service Oklahoma 'Commercial Driving CDL' and 'CDL First-Time Applicants' pages (oklahoma.gov).","handbook":"","hbref":""},{"q":"Where does an Oklahoma CDL applicant take the required vision and written knowledge tests?","options":["In person at a Service Oklahoma Licensing Office","Online through the Service Oklahoma portal from home","At any FMCSA Training Provider Registry school","At an Oklahoma Highway Patrol troop headquarters"],"answer":0,"explanation":"Applicants begin the CDL process by taking the vision and written knowledge tests in person at a Service Oklahoma Licensing Office; the vision and written tests are administered together at the same appointment. Source: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov).","handbook":"","hbref":""},{"q":"How many days must an Oklahoma applicant hold a Commercial Learner Permit (CLP) before being allowed to take the CDL skills (drive) test?","options":["14 full days, with testing allowed on the 15th day","30 full days, with testing allowed on the 31st day","7 full days, with testing allowed on the 8th day","10 full days, with testing allowed on the 11th day"],"answer":0,"explanation":"Oklahoma requires the CLP to be held for 14 full days before the skills test; the applicant may take the test on the 15th day. This mirrors the federal 14-day rule. Source: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The Oklahoma CDL skills test is a three-part exam. Which set correctly lists those three parts?","options":["Pre-trip vehicle inspection, basic control skills, and the on-road driving test","General knowledge test, air brakes test, and combination vehicles test","Vision test, written test, and a defensive driving course","Pre-trip inspection, hazardous materials test, and a backing test"],"answer":0,"explanation":"The Oklahoma CDL skills test consists of three parts: the pre-trip vehicle inspection, basic control skills (e.g., backing maneuvers), and the on-road driving test. Source: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.113.","handbook":"","hbref":""},{"q":"Under federal Entry-Level Driver Training (ELDT) rules that Oklahoma applies, a first-time Class A or Class B applicant must complete ELDT from an approved provider before doing what?","options":["Taking the state-administered CDL skills test","Receiving the Commercial Learner Permit","Taking the general knowledge written test","Completing the vision screening"],"answer":0,"explanation":"ELDT (theory and behind-the-wheel) for a first-time Class A or B CDL must be completed through an FMCSA Training Provider Registry provider before the applicant takes the state-administered skills test. Source: FMCSA ELDT rule (49 CFR Part 380); Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov).","handbook":"","hbref":""},{"q":"Where must an Oklahoma CDL applicant's Entry-Level Driver Training provider be listed for the training to count?","options":["FMCSA's Training Provider Registry (TPR)","The Oklahoma Department of Transportation school list","The Service Oklahoma approved-vendor directory","The National Registry of Certified Medical Examiners"],"answer":0,"explanation":"ELDT must be obtained from a provider listed on FMCSA's Training Provider Registry (TPR). Source: FMCSA ELDT rule; Service Oklahoma 'Commercial Driving CDL' (oklahoma.gov).","handbook":"","hbref":""},{"q":"Which CDL endorsement requires ELDT theory training to be completed BEFORE taking the knowledge test (not the skills test)?","options":["Hazardous Materials (H) endorsement","Passenger (P) endorsement","School Bus (S) endorsement","Doubles/Triples (T) endorsement"],"answer":0,"explanation":"For the Hazardous Materials (H) endorsement, ELDT is theory-only and must be completed before the state-administered knowledge test. The P and S endorsements require ELDT before their skills tests. Source: FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"How many self-certification categories must an Oklahoma CDL applicant choose from when declaring their type of driving?","options":["Four","Two","Three","Six"],"answer":0,"explanation":"Applicants must self-certify into one of four categories: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Source: Service Oklahoma 'CDL First-Time Applicants' and CDL Self-Certification SOP (oklahoma.gov).","handbook":"","hbref":""},{"q":"Which self-certification category REQUIRES the driver to maintain a DOT Medical Examiner's Certificate on file for licensing?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"answer":0,"explanation":"Only the Non-Excepted Interstate (NI) category requires a DOT Medical Card for licensing. The EI, NA, and EA categories do not require a medical card to be on file with Service Oklahoma. Source: Service Oklahoma 'CDL First-Time Applicants' / 'Commercial Driving CDL' (oklahoma.gov).","handbook":"","hbref":""},{"q":"How is a driver's DOT Medical Examiner's Certificate now transmitted to Service Oklahoma for record-keeping?","options":["Electronically from the FMCSA National Registry of Certified Medical Examiners","By the driver mailing a paper copy to Service Oklahoma headquarters","By the employer faxing it to the local Licensing Office","By the county tag agency forwarding a notarized copy"],"answer":0,"explanation":"The certified medical examiner electronically submits the certificate (Form MCSA-5876) to the FMCSA National Registry, which transmits the medical certification status electronically to Service Oklahoma. Source: Service Oklahoma CDL Self-Certification and Medical Certificates Processing SOP (oklahoma.gov); FMCSA National Registry.","handbook":"","hbref":""},{"q":"What form number is the federal Medical Examiner's Certificate that a certified examiner submits to the FMCSA National Registry?","options":["MCSA-5876","MCSA-5875","MCSA-5889","MCSA-5870"],"answer":0,"explanation":"The Medical Examiner's Certificate is FMCSA Form MCSA-5876; the related Medical Examination Report is MCSA-5875. The examiner submits the MCSA-5876 result to the National Registry. Source: Service Oklahoma Medical Certificates Processing SOP; FMCSA.","handbook":"","hbref":""},{"q":"An Oklahoma Non-Excepted Interstate (NI) CDL holder typically must provide a current DOT Medical Examiner's Certificate at least how often (the maximum interval between exams under FMCSA standards)?","options":["Every 24 months","Every 12 months","Every 36 months","Every 60 months"],"answer":0,"explanation":"A standard medical examiner's certificate is valid for a maximum of 24 months, so NI drivers must have a current certificate on file within that cycle (shorter intervals apply for certain conditions). Source: Service Oklahoma CDL medical guidance; 49 CFR 391.45.","handbook":"","hbref":""},{"q":"If Service Oklahoma is notified that a CDL holder's medical certification has expired or is no longer valid, within how many days must the agency downgrade the CDL under federal rule?","options":["Within 60 days","Within 10 days","Within 30 days","Within 90 days"],"answer":0,"explanation":"State driver licensing agencies, including Service Oklahoma, must downgrade a CDL within 60 days of learning the driver is no longer medically certified or that the medical certificate has expired and was not renewed. Source: Service Oklahoma downgrade guidance; 49 CFR 383.73(o).","handbook":"","hbref":""},{"q":"Under Oklahoma statute, for how long is a Commercial Learner Permit (CLP) initially valid?","options":["180 days","90 days","60 days","1 year"],"answer":0,"explanation":"Oklahoma issues the CLP for a period of 180 days; it may be renewed one time for an additional 180 days. Source: 47 O.S. Section 6-101; Service Oklahoma CLP guidance.","handbook":"","hbref":""},{"q":"An Oklahoma CLP may be renewed one time. For how long is that single renewal valid?","options":["An additional 180 days","An additional 30 days","An additional 1 year","An additional 90 days"],"answer":0,"explanation":"The CLP is valid for 180 days and may be renewed once for an additional 180 days, allowing up to one year total. Source: 47 O.S. Section 6-101; Service Oklahoma CLP guidance.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a CDL for INTRASTATE (Oklahoma-only) commercial driving?","options":["18 years old","21 years old","16 years old","19 years old"],"answer":0,"explanation":"An applicant must be at least 18 to operate a CMV intrastate (within Oklahoma) and at least 21 to drive interstate. Source: Service Oklahoma CDL guidance; 47 O.S. Section 6-101.","handbook":"","hbref":""},{"q":"A 19-year-old Oklahoma CDL holder who has not yet turned 21 is generally limited in what way?","options":["To intrastate (within-Oklahoma) commercial driving only","To driving only Class C commercial vehicles","To daytime commercial driving only","To driving only with a licensed CDL holder present"],"answer":0,"explanation":"Drivers age 18 to 20 may hold a CDL but are restricted to intrastate (within-Oklahoma) commercial operation; interstate operation requires age 21. Source: Service Oklahoma CDL guidance; 49 CFR 383.3 / 391.11.","handbook":"","hbref":""},{"q":"Which document is NOT among those a first-time Oklahoma CDL applicant is required to present at the Service Oklahoma Licensing Office?","options":["An employer's letter authorizing the road test","Proof of identity and lawful presence","Proof of Oklahoma residency (one proof of address)","A valid Oklahoma Class D driver license"],"answer":0,"explanation":"Required items include proof of identity and lawful presence, proof of residency/address, a valid Oklahoma Class D license, and a Social Security number; an employer authorization letter is not required. Source: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov).","handbook":"","hbref":""},{"q":"Regarding Oklahoma CDL renewal, which statement is accurate about the process?","options":["Eligible CDL holders may renew online, but Hazardous Materials (H) holders must renew in person and retake the HazMat written test plus the TSA background check","All CDL renewals, including HazMat, can be completed entirely online","CDLs cannot be renewed and must be re-tested from scratch each cycle","Renewal requires retaking the full three-part skills test every time"],"answer":0,"explanation":"Service Oklahoma offers online CDL renewal for eligible holders, but Hazardous Materials endorsement holders must renew in person, retake the HazMat knowledge test, and complete the TSA background check at each renewal. (Note: exact fees and chosen credential term, e.g., 4-year vs 8-year options, can change.) Source: Service Oklahoma 'CDL Renewal/Replacement Online' (oklahoma.gov).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая внешняя ширина транспортного средства на автомагистралях Оклахомы, с грузом или без него, при превышении которой требуется разрешение на негабаритную ширину?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"Оклахома ограничивает общую внешнюю ширину значением 102 inches (8.5 ft); большая ширина требует разрешения на негабаритную ширину. Источник: 47 O.S. §14-103."},"1":{"q":"Какова максимальная допустимая высота транспортного средства или груза на платной автодороге, межштатной, федеральной или штатной автомагистрали Оклахомы без специального разрешения?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"Оклахома допускает высоту до 14 feet на платных автодорогах, межштатных, федеральных и штатных автомагистралях без разрешения. Источник: 47 O.S. §14-103."},"2":{"q":"Какова максимальная высота транспортного средства или груза на ОКРУЖНОЙ дороге Оклахомы без специального разрешения?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"На окружных дорогах ограничение высоты составляет 13.5 feet, что ниже предела в 14 feet, допустимого на платных автодорогах, межштатных, федеральных и штатных автомагистралях. Источник: 47 O.S. §14-103."},"3":{"q":"Какова в Оклахоме максимально допустимая нагрузка на любую одиночную ось без разрешения на перегруз?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Предельная нагрузка на одиночную ось в Оклахоме составляет 20,000 pounds. Источник: 47 O.S. §14-109(A)."},"4":{"q":"Какую максимальную нагрузку Оклахома допускает на сдвоенную тележку осей без специального разрешения?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Максимальная нагрузка на любую сдвоенную тележку осей в Оклахоме составляет 34,000 pounds. Источник: 47 O.S. §14-109(B)."},"5":{"q":"Какова общая максимальная полная масса транспортного средства на автомагистралях Оклахомы согласно весовой таблице без специального разрешения?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"Весовая таблица Оклахомы ограничивает законную полную массу значением 80,000 pounds, что соответствует федеральному пределу. Источник: 47 O.S. §14-109(A)."},"6":{"q":"Допустимые значения полной массы и осевых нагрузок в Оклахоме определяются по формуле, основанной на расстоянии между осями. Как обычно называется эта формула?","options":["Federal Bridge Formula","Gross Combination Rule","Tare Weight Formula","Axle Spread Ratio"],"explanation":"Оклахома использует Federal Bridge Formula/весовую таблицу (23 U.S.C. §127), измеряя расстояние между крайними осями с округлением до ближайшего фута. Источник: 47 O.S. §14-109; ODPS Troop S."},"7":{"q":"Какова максимальная общая длина ОДИНОЧНОГО грузовика (не автопоезда), включая бамперы, на дорогах Оклахомы?","options":["40 feet","45 feet","53 feet","70 feet"],"explanation":"Одиночный грузовик не может превышать 45 feet общей длины, включая передний и задний бамперы, в Оклахоме. Источник: 47 O.S. §14-103."},"8":{"q":"Какова на National Network максимальная длина полуприцепа в составе автопоезда тягач/полуприцеп в Оклахоме (без разрешения)?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"Полуприцеп в составе автопоезда тягач/полуприцеп может иметь длину до 53 feet на National Network; большая длина (до 59'6\") требует разрешения. Источник: 47 O.S. §14-103."},"9":{"q":"Какова максимальная общая длина для составов транспортных средств, ИНЫХ, чем автопоезд тягач/полуприцеп, на всех дорогах и автомагистралях Оклахомы?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"Прочие составы транспортных средств не могут превышать 70 feet общей длины, включая бамперы, на всех дорогах и автомагистралях Оклахомы. Источник: 47 O.S. §14-103."},"10":{"q":"Какое подразделение ведомства Оклахомы выдает разрешения на негабаритные/тяжеловесные перевозки для движения по системе автомагистралей штата?","options":["The Oklahoma Tax Commission","The ODOT Size and Weight Permit Division","The Corporation Commission","Управление шерифа округа"],"explanation":"The ODOT Size and Weight Permit Division выдает разрешения на негабаритные/тяжеловесные перевозки (заявка подается онлайн на swpermitsok.com). Источник: ODOT; OAC 730:50-5."},"11":{"q":"До какой максимальной ширины может эксплуатироваться состав грузовик с полуприцепом по специальному ГОДОВОМУ разрешению на негабаритную ширину в Оклахоме?","options":["108 inches","114 inches","120 inches","144 inches"],"explanation":"Составы, превышающие 102, но не превышающие 120 inches по ширине, могут эксплуатироваться по специальному годовому разрешению на негабаритную ширину. Источник: OAC 730:50-5; 47 O.S. §14-103G."},"12":{"q":"Согласно правилам Оклахомы, груз с разрешением шириной более 12 feet, но не более 14 feet, должен иметь какое сопровождение на двухполосной автомагистрали?","options":["Сопровождение не требуется","Машину сопровождения спереди","Машину сопровождения сзади","Машины сопровождения как спереди, так и сзади"],"explanation":"Грузы шириной более 12 ft, но не более 14 ft, требуют машину сопровождения спереди на двухполосных/расширенных двухполосных автомагистралях (машину сопровождения сзади на многополосных). Источник: OAC 730:50-5-18(b)."},"13":{"q":"При какой общей ВЫСОТЕ груз с разрешением в Оклахоме требует ДВУХ машин сопровождения (одной спереди, одной сзади) и заблаговременного уведомления коммунальных служб и железных дорог?","options":["14 feet или более","14 feet 6 inches или более","15 feet или более","15 feet 9 inches или более"],"explanation":"Грузы с общей высотой 15 feet 9 inches или более требуют двух машин сопровождения и заблаговременного контакта с затрагиваемыми коммунальными службами/железными дорогами. Источник: OAC 730:50-5-18(b)."},"14":{"q":"При какой общей длине состава автопоезд тягач/полуприцеп требуется машина сопровождения спереди на двухполосных автомагистралях Оклахомы?","options":["Более 70 feet","Более 75 feet","Более 80 feet","Более 100 feet"],"explanation":"Состав автопоезд тягач/полуприцеп длиной более 80 feet общей длины требует машины сопровождения спереди на двухполосных автомагистралях. Источник: OAC 730:50-5-18(b)(4)."},"15":{"q":"Согласно весовому отклонению Оклахомы для сельскохозяйственной продукции (по ODPS Troop S), какие допуски применяются и где движение запрещено?","options":["5% сверх полной массы и 8% сверх осевых пределов; не по межштатным автомагистралям","10% сверх полной массы и 10% сверх осевого; не по платным автодорогам","8% сверх полной массы и 5% сверх осевого; не по окружным дорогам","5% сверх полной массы и 5% сверх осевого; движение по межштатным дорогам разрешено"],"explanation":"Транспортные средства, перевозящие сельскохозяйственную продукцию при максимальной регистрации, могут превышать пределы полной массы до 5% и осевые пределы до 8%, но не на системе Interstate. Источник: ODPS Troop S; 47 O.S. §14-109."},"16":{"q":"При разрешении на весовое отклонение для сельского хозяйства, допускающем около 8% сверх осевого предела, показатель одиночной оси в 20,000 pounds становится приблизительно каким?","options":["20,800 pounds","21,600 pounds","22,400 pounds","24,000 pounds"],"explanation":"С отклонением (8% сверх осевого) предел одиночной оси в 20,000 lb становится 21,600 lbs; превышение любой категории аннулирует разрешение для этой поездки. Источник: ODPS Troop S, таблица осей."},"17":{"q":"Годовое разрешение ODOT Annual Envelope Vehicle Permit допускает транспортное средство до каких максимальных габаритов на системе автомагистралей штата?","options":["10 ft в ширину, 13.5 ft в высоту, 90 ft в длину","12 ft в ширину, 14 ft в высоту, 110 ft в длину","14 ft в ширину, 15 ft в высоту, 120 ft в длину","12 ft в ширину, 16 ft в высоту, 100 ft в длину"],"explanation":"Annual Envelope Vehicle Permit охватывает транспортные средства до 12 ft в ширину, 14 ft в высоту и 110 ft в длину (сбор $4,000), действительно только на системе автомагистралей штата. Источник: OAC 730:50-5-13."},"18":{"q":"Перевозчики необработанной лесной продукции в естественном состоянии в Оклахоме могут получить годовое сельскохозяйственное разрешение за $25, но с каким ограничением по маршруту?","options":["Без движения по системе Interstate","Без движения по какой-либо платной автодороге","Без движения по окружным дорогам","Движение только не в ночное время"],"explanation":"Перевозка необработанной лесной продукции по годовому сельскохозяйственному разрешению за $25 не допускается на National System of Interstate and Defense Highways. Источник: OAC 730:50-5-22; 47 O.S. §14-118(e)."},"19":{"q":"Какой класс CDL требуется в Оклахоме для управления любым составом транспортных средств с полной массой автопоезда (GCWR) 26,001 фунтов или более, когда буксируемое транспортное средство имеет GVWR более 10,000 фунтов?","options":["Class A","Class B","Class C","Class D"],"explanation":"Оклахома принимает федеральную классификацию: Class A CDL охватывает любой состав транспортных средств с GCWR 26,001+ lbs, где буксируемое(ые) звено(звенья) превышает 10,000 lbs GVWR. Источник: Oklahoma Statutes Title 47 Sec. 6-101 и Oklahoma CDL Manual (Service Oklahoma)."},"20":{"q":"Водитель в Оклахоме управляет одиночным грузовиком с жесткой рамой с GVWR 30,000 фунтов, который не буксирует прицеп. Какой класс CDL это требует?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"Class B CDL охватывает любое одиночное транспортное средство с GVWR 26,001+ lbs (или такое транспортное средство, буксирующее звено не более 10,000 lbs GVWR). Грузовик с жесткой рамой массой 30,000 lb подпадает под Class B. Источник: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"21":{"q":"Согласно правилам Оклахомы, транспортное средство, не соответствующее весовым порогам Class A или Class B, все равно требует Class C CDL, если оно что делает?","options":["Имеет GVWR более 16,000 фунтов","Предназначено для перевозки 16 или более человек, включая водителя, или перевозит опасные материалы, требующие маркировки знаками","Буксирует любой прицеп с номинальной массой свыше 5,000 фунтов","Эксплуатируется по найму за пределами округа"],"explanation":"Class C CDL применяется к транспортному средству, не соответствующему Class A или B, которое предназначено для перевозки 16 или более пассажиров (включая водителя) или которое перевозит опасные материалы, требующие маркировки знаками. Источник: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"22":{"q":"Какой код подтверждения должен быть добавлен к CDL Оклахомы для перевозки материалов, признанных опасными и требующих маркировки знаками?","options":["N","T","H","P"],"explanation":"Подтверждение H (Hazardous Materials) требуется для перевозки опасных материалов, требующих маркировки знаками. Источник: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"23":{"q":"Каков федеральный/оклахомский порог емкости, определяющий 'цистерну' (tank vehicle), требующую подтверждения N (Tanker)?","options":["Цистерна с индивидуальной номинальной емкостью более 119 gallons и совокупной номинальной емкостью 1,000 gallons или более","Цистерна с индивидуальной номинальной емкостью более 100 gallons","Любая цистерна, перевозящая 500 gallons или более в общей сложности","Цистерна с совокупной емкостью 2,000 gallons или более"],"explanation":"Подтверждение N требуется для транспортных средств, перевозящих жидкости или газы в цистерне с индивидуальной номинальной емкостью более 119 gallons И совокупной номинальной емкостью 1,000 gallons или более. Источник: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.5."},"24":{"q":"Какое подтверждение CDL Оклахомы требуется для буксировки сдвоенных или строенных прицепов и какой класс CDL водитель уже должен иметь?","options":["Подтверждение T, имея Class A CDL","Подтверждение T, имея Class B CDL","Подтверждение N, имея Class A CDL","Подтверждение P, имея Class C CDL"],"explanation":"Подтверждение T (Doubles/Triples) позволяет буксировать несколько прицепов и добавляется водителями Class A, которые должны продемонстрировать требуемые дополнительные знания. Источник: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"25":{"q":"Водитель в Оклахоме хочет управлять транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя. Какое подтверждение требуется?","options":["S (School Bus)","P (Passenger)","N (Tanker)","T (Doubles/Triples)"],"explanation":"Подтверждение P (Passenger) требуется для управления транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя; оно требует сдачи теоретического теста и практического теста на представительном транспортном средстве. Источник: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"26":{"q":"Прежде чем водитель в Оклахоме сможет получить подтверждение School Bus (S), какое другое подтверждение является обязательным условием?","options":["Подтверждение H (HazMat)","Подтверждение N (Tanker)","Подтверждение P (Passenger)","Подтверждение T (Doubles/Triples)"],"explanation":"Подтверждение S (School Bus) требует, чтобы водитель сначала имел подтверждение P (Passenger), затем сдал теоретический тест по школьным автобусам и практический тест на школьном автобусе. Источник: Oklahoma CDL Manual / Endorsements (Service Oklahoma); 49 CFR 383.93."},"27":{"q":"Каков минимальный возраст для получения CDL Оклахомы с ограничением только внутриштатной (в пределах Оклахомы) эксплуатации?","options":["16","18","21","25"],"explanation":"Водителю должно быть не менее 18 лет, чтобы иметь CDL Оклахомы только для внутриштатной эксплуатации; водители до 21 года получают ограничение 'K' (только внутриштатное). Источник: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"28":{"q":"Каков минимальный возраст, требуемый для управления транспортным средством с CDL в межштатной торговле (через границы штатов) из Оклахомы?","options":["18","19","21","23"],"explanation":"Межштатная эксплуатация CDL требует минимального возраста 21 год; водители от 18 до 20 лет ограничены внутриштатной эксплуатацией в пределах Оклахомы. Источник: Oklahoma CDL Manual (Service Oklahoma); 49 CFR 391.11."},"29":{"q":"После сдачи требуемых теоретических тестов в Оклахоме, как долго заявитель должен иметь Commercial Learner Permit (CLP), прежде чем сдавать практический тест CDL (вождение)?","options":["7 полных дней","10 полных дней","14 полных дней","30 полных дней"],"explanation":"Федеральные правила и правила Оклахомы требуют наличия CLP в течение 14 полных дней перед практическим тестом; тест может быть сдан на 15-й день. Источник: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.25."},"30":{"q":"В течение какого срока действителен Commercial Learner Permit (CLP) Оклахомы и как он может быть продлен?","options":["90 дней, без продления","180 дней, с возможностью однократного продления на дополнительные 180 дней","1 год, с ежегодным продлением","60 дней, с продлением до трех раз"],"explanation":"CLP Оклахомы выдается на 180 дней и может быть продлен один раз на дополнительные 180 дней. Источник: Oklahoma CDL Manual / Service Oklahoma; 49 CFR 383.25."},"31":{"q":"Какой набор документов должен предъявить впервые подающий заявку на CDL в Оклахоме в офисе лицензирования Service Oklahoma?","options":["Только действительные водительские права Class D и свидетельство о рождении","Подтверждение личности, подтверждение законного присутствия, номер Social Security и подтверждение проживания в Оклахоме","Только карту Social Security и письмо работодателя","Паспорт и подтверждение страховки транспортного средства"],"explanation":"Service Oklahoma требует подтверждение личности, законного присутствия, SSN заявителя и проживания в Оклахоме (один документ о проживании по стандарту, два для REAL ID), плюс действительные права Class D. Источник: Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"32":{"q":"Подготовка водителей начального уровня (ELDT) для впервые подающего заявку на CDL в Оклахоме должна быть пройдена через какую официальную систему?","options":["Портал Oklahoma Department of Education","FMCSA Training Provider Registry","TSA Hazmat Threat Assessment Program","Реестр Oklahoma Tax Commission"],"explanation":"ELDT должна предоставляться школой, внесенной в FMCSA Training Provider Registry, которая сообщает о завершении в электронном виде. Источник: правило FMCSA ELDT (49 CFR Part 380); Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"33":{"q":"Что из перечисленного требует ELDT (Entry-Level Driver Training) перед практическим/теоретическим тестом согласно правилам FMCSA, применяемым в Оклахоме?","options":["Получение подтверждения Tanker (N)","Получение подтверждения Doubles/Triples (T)","Получение подтверждения Passenger (P) или School Bus (S) впервые","Продление существующего Class A CDL"],"explanation":"ELDT требуется для впервые получаемого Class A или B CDL, повышения с B до A и впервые получаемых подтверждений H, P или S. Подтверждения N и T НЕ регулируются ELDT. Источник: правило FMCSA ELDT (49 CFR Part 380); Service Oklahoma."},"34":{"q":"Для подтверждения Hazardous Materials (H) требование ELDT, применяемое в Оклахоме, состоит из чего?","options":["Только теоретическое обучение","Только практическое обучение за рулем","Как теоретическое, так и практическое обучение за рулем","Никакого обучения вообще"],"explanation":"ELDT для подтверждения H — только теоретическое; только Class A/B CDL и подтверждения P и S требуют как теоретического, так и практического обучения за рулем. Источник: правило FMCSA ELDT (49 CFR Part 380)."},"35":{"q":"В дополнение к сдаче теоретического теста по HazMat, что нужно водителю в Оклахоме для получения или сохранения подтверждения H?","options":["Оценку угрозы безопасности TSA (проверку биографии), действительную в течение 5 лет","Второй практический тест на цистерне","Нотариально заверенное письмо-поручительство работодателя","Отдельное штатное разрешение на HazMat, продлеваемое ежегодно"],"explanation":"Подтверждение H требует TSA Hazmat Threat Assessment (проверка биографии/снятие отпечатков пальцев); допуск действителен в течение 5 лет и должен продлеваться вместе с подтверждением. Источник: TSA HTAP; 49 CFR 1572; Service Oklahoma CDL."},"36":{"q":"Какой код подтверждения выдается на CDL Оклахомы для водителя, уполномоченного управлять цистерной, перевозящей опасные материалы, требующие маркировки знаками (объединенные HazMat и Tank)?","options":["HN","X","T","Z"],"explanation":"Оклахома выдает объединенный код подтверждения 'X' для водителей, имеющих полномочия как Tank (N), так и Hazardous Materials (H). Источник: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.153."},"37":{"q":"Из скольких категорий медицинской самосертификации выбирает заявитель на CDL в Оклахоме и какая из них требует медицинского сертификата эксперта DOT?","options":["Две категории; категория Excepted Interstate требует медицинской карты","Четыре категории; категория Non-Excepted Interstate (NI) требует медицинской карты","Три категории; категория Non-Excepted Intrastate требует медицинской карты","Четыре категории; категория Excepted Intrastate (EA) требует медицинской карты"],"explanation":"Существуют четыре категории самосертификации (NI, EI, NA, EA). Только водители Non-Excepted Interstate (NI) должны предоставлять и поддерживать действительный медицинский сертификат эксперта DOT. Источник: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.71."},"38":{"q":"Какой код ограничения имеет CDL или CLP Оклахомы, когда владелец не может управлять коммерческими транспортными средствами за пределами штата Оклахома?","options":["E","L","K","Z"],"explanation":"Ограничение 'K' означает только внутриштатное — водитель не может покидать Оклахому на транспортном средстве с CDL (обычно применяется к водителям до 21 года). 'E' = без механической коробки передач, 'L' = без пневматических тормозов, 'Z' = без полностью пневматических тормозов. Источник: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"39":{"q":"При управлении коммерческим автотранспортным средством (CMV) в Оклахоме водитель считается юридически в состоянии опьянения и совершает тяжкое нарушение при какой концентрации алкоголя в крови (BAC)?","options":["0.02 или более","0.04 или более","0.08 или более","0.10 или более"],"explanation":"Оклахома устанавливает предел BAC для CMV на уровне 0.04 или более, что вдвое меньше предела 0.08 для некоммерческих водителей. Управление CMV при 0.04 или выше является тяжким нарушением. Источник: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51, принятый Оклахомой."},"40":{"q":"Согласно закону Оклахомы о подразумеваемом согласии, управляя коммерческим автотранспортным средством, держатель CDL считается согласившимся на что?","options":["Осмотр транспортного средства на любой весовой станции","Химическое тестирование на алкоголь или наркотики по законному требованию","Только случайное тестирование на наркотики со стороны работодателя","Отказ от права на слушание"],"explanation":"Закон Оклахомы о подразумеваемом согласии считает любого, кто управляет CMV, согласившимся на химическое (дыхания, крови или мочи) тестирование на алкоголь или контролируемые вещества по законному требованию. Отказ влечет за собой дисквалификацию. Источник: Oklahoma CDL Driver Manual, Section 1; 47 O.S. Section 753 (implied consent)."},"41":{"q":"В Оклахоме отказ пройти тестирование на алкоголь или наркотики, требуемое законом о подразумеваемом согласии, пока вы держите CDL, рассматривается как что?","options":["Серьезное нарушение правил дорожного движения","Незначительное административное нарушение","Тяжкое нарушение, подлежащее дисквалификации","Без последствий для CDL, только штраф"],"explanation":"Отказ от требуемого теста классифицируется в Оклахоме как тяжкое нарушение и влечет ту же дисквалификацию, что и положительный тест. Первый отказ приводит к дисквалификации CDL на 1 год. Источник: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"42":{"q":"Каков срок дисквалификации CDL в Оклахоме за ПЕРВОЕ тяжкое нарушение водителя (например, DUI в CMV) при НЕ перевозке маркированных знаками опасных материалов?","options":["60 days","120 days","1 year","3 years"],"explanation":"Первое тяжкое нарушение приводит к дисквалификации CDL на 1 year в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"43":{"q":"Если водитель совершает первое тяжкое нарушение при управлении CMV, который обязан иметь маркировку знаками для опасных материалов, срок дисквалификации в Оклахоме увеличивается до чего?","options":["18 months","2 years","3 years","Пожизненно"],"explanation":"Первое тяжкое нарушение, совершенное при перевозке маркированных знаками опасных материалов, повышает дисквалификацию с 1 year до 3 years в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"44":{"q":"Какова дисквалификация CDL в Оклахоме за ВТОРОЕ тяжкое нарушение водителя?","options":["3 years","5 years","10 years","Пожизненно"],"explanation":"Второе тяжкое нарушение приводит к пожизненной дисквалификации CDL в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"45":{"q":"Использование CMV при совершении тяжкого преступления, связанного с изготовлением, распространением или сбытом контролируемого вещества, влечет какое наказание для CDL в Оклахоме?","options":["Дисквалификация на 1 год","Дисквалификация на 3 года","Дисквалификация на 10 лет","Пожизненная дисквалификация без восстановления"],"explanation":"Использование CMV в тяжком преступлении, связанном с изготовлением или распространением контролируемого вещества, влечет обязательную пожизненную дисквалификацию без возможности восстановления в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"46":{"q":"Сколько серьезных нарушений правил дорожного движения в течение 3-летнего периода влекут ПЕРВЫЙ срок дисквалификации в Оклахоме и какова его продолжительность?","options":["1 нарушение; 30 days","2 нарушения; 60 days","2 нарушения; 90 days","3 нарушения; 60 days"],"explanation":"Второе серьезное нарушение правил дорожного движения в течение 3 лет (совершенное в CMV) приводит к дисквалификации на 60 days в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"47":{"q":"Какова дисквалификация CDL в Оклахоме за ТРЕТЬЕ серьезное нарушение правил дорожного движения, совершенное в течение 3-летнего периода?","options":["60 days","90 days","120 days","1 year"],"explanation":"Третье серьезное нарушение правил дорожного движения в течение 3 лет приводит к дисквалификации на 120 days в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"48":{"q":"Что из перечисленного является СЕРЬЕЗНЫМ нарушением правил дорожного движения для держателя CDL в Оклахоме?","options":["Парковка в зоне, где парковка запрещена","Превышение скорости на 15 mph или более сверх установленного предела","Управление с просроченной регистрационной наклейкой","Несигнализирование о смене полосы при отсутствии встречного движения"],"explanation":"Чрезмерное превышение скорости (на 15 mph или более сверх предела) является указанным серьезным нарушением правил дорожного движения. Другие включают неосторожное вождение, неправильную смену полосы, слишком близкое следование и набор текста/использование телефона в руке. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"49":{"q":"Набор текста или использование мобильного телефона в руке при управлении CMV классифицируется в Оклахоме как какой тип нарушения?","options":["Незначительное нарушение при движении","Серьезное нарушение правил дорожного движения","Тяжкое нарушение","Нарушение предписания о выводе из эксплуатации (out-of-service order)"],"explanation":"Набор текста и использование мобильного телефона в руке при управлении CMV являются серьезными нарушениями правил дорожного движения, которые засчитываются в дисквалификацию по схеме 2-или-3-за-3-года. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2, 392.80 и 392.82."},"50":{"q":"Водитель CMV в Оклахоме, пойманный на использовании мобильного телефона в руке во время вождения, может столкнуться с федеральным гражданским штрафом (штрафом водителя) в размере до какой суммы?","options":["$250","$1,000","$2,750","$11,000"],"explanation":"Штраф водителя за использование мобильного телефона в руке при управлении CMV может составлять до $2,750 (работодатели, которые это допускают, могут быть оштрафованы на сумму до $11,000). Источник: 49 CFR 392.82; правило FMCSA о мобильных телефонах, применяемое в Оклахоме."},"51":{"q":"Какова дисквалификация CDL в Оклахоме за ПЕРВОЕ нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["Не менее 60 days","Не менее 120 days","Не менее 1 year","Не менее 3 years"],"explanation":"Первое нарушение на железнодорожном переезде приводит к дисквалификации не менее 60 days в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"52":{"q":"Какова дисквалификация CDL в Оклахоме за ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["60 days","Не менее 120 days","Не менее 1 year","Не менее 2 years"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет приводит к дисквалификации не менее 120 days в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"53":{"q":"Какова дисквалификация CDL в Оклахоме за ТРЕТЬЕ или последующее нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["120 days","180 days","Не менее 1 year","Пожизненно"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3 лет приводит к дисквалификации не менее 1 year в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"54":{"q":"Какова дисквалификация CDL в Оклахоме за ТРЕТЬЕ или последующее нарушение предписания о выводе из эксплуатации в течение 10-летнего периода?","options":["1 year","2 years","Не менее 3 years, но не более 5 years","Пожизненно"],"explanation":"Третье или последующее нарушение предписания о выводе из эксплуатации в течение 10 лет приводит к дисквалификации не менее 3 years, но не более 5 years в Оклахоме. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 4."},"55":{"q":"Держатель CDL в Оклахоме осужден за оставление места происшествия с участием CMV, которым он управлял. Как это классифицируется для целей дисквалификации?","options":["Серьезное нарушение правил дорожного движения (минимум 60 дней)","Тяжкое нарушение (минимум 1 год, 3 года при опасных грузах)","Нарушение предписания о выводе из эксплуатации","Нарушение на железнодорожном переезде"],"explanation":"Оставление места происшествия (наезд со скрытием) с участием CMV является тяжким нарушением, влекущим дисквалификацию на 1 год (3 года при маркированных знаками опасных грузах) за первое нарушение и пожизненно за второе. Источник: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"56":{"q":"В Оклахоме, когда коммерческий автомобиль, обязанный останавливаться, приближается к железнодорожному переезду в одном уровне с дорогой, где должен остановиться водитель?","options":["Не ближе 5 футов и не дальше 25 футов от ближайшего рельса","Не ближе 15 футов и не дальше 50 футов от ближайшего рельса","Не ближе 25 футов и не дальше 75 футов от ближайшего рельса","Не ближе 10 футов и не дальше 100 футов от ближайшего рельса"],"explanation":"Руководство CDL штата Оклахома (разделы 2.15 и 9.6.12) требует, чтобы водители, которые обязаны останавливаться на железнодорожном переезде, останавливались на расстоянии от 15 до 50 футов от ближайшего рельса, а затем продолжали движение, только убедившись, что поезд не приближается. Это соответствует 49 CFR 392.10 в применении к Оклахоме."},"57":{"q":"Какой из следующих коммерческих автомобилей НЕ обязан останавливаться на каждом железнодорожном переезде согласно правилам Оклахомы?","options":["Автобус, перевозящий пассажиров","Пустой фургон-прицеп (dry van), не перевозящий опасных грузов и пассажиров","Автомобиль с табличками (placards), обозначающими опасные грузы","Цистерна, используемая для перевозки опасных грузов, как загруженная, так и пустая"],"explanation":"Руководство CDL штата Оклахома (раздел 9.6.12) перечисляет автомобили, которые всегда обязаны останавливаться: автомобили с табличками опасных грузов, любые автомобили, перевозящие хлор, цистерны, используемые для опасных грузов (загруженные или пустые), и автобусы с пассажирами. Грузовой фургон без табличек, не перевозящий пассажиров, не входит в список обязательной остановки."},"58":{"q":"Согласно закону Оклахомы «Move Over» (об уступлении полосы), что в первую очередь обязан сделать водитель на шоссе с двумя или более полосами в одном направлении, приближаясь к стоящему автомобилю экстренных служб или эвакуатору с включёнными проблесковыми маячками?","options":["Перестроиться на полосу, не примыкающую к стоящему автомобилю, если это можно сделать безопасно","Полностью остановиться, пока автомобиль экстренных служб не уедет","Подать звуковой сигнал, чтобы предупредить персонал экстренных служб","Сохранять скорость, но сместиться в пределах своей полосы к осевой линии"],"explanation":"Закон Оклахомы «Move Over» (47 O.S. Section 11-314) требует, чтобы водитель на многополосной дороге, когда это безопасно, перестраивался на полосу, не примыкающую к стоящему автомобилю экстренных служб, лицензированному эвакуатору или автомобилю обслуживания DOT/платных дорог с включёнными проблесковыми маячками."},"59":{"q":"Согласно закону Оклахомы «Move Over», когда водитель не может безопасно перестроиться в сторону от стоящего автомобиля экстренных служб, что он должен сделать?","options":["Снизить скорость ровно до 20 mph во всех случаях","Полностью остановиться и ждать сигнала к продолжению движения","Продолжать движение с установленной максимальной скоростью, но включить аварийную сигнализацию","Снизить скорость до безопасной с учётом существующих дорожных, погодных условий и условий движения"],"explanation":"Закон Оклахомы «Move Over» (47 O.S. Section 11-314) требует, чтобы водитель, который не может перестроиться, снизил скорость до безопасной с учётом существующих условий. Закон использует стандарт, основанный на условиях, а не единое фиксированное число."},"60":{"q":"Если коммерческий автомобиль с табличками опасных грузов вынужден остановиться на дороге с односторонним движением или разделённом шоссе в Оклахоме, на каких расстояниях в сторону приближающегося транспорта должны быть установлены предупредительные знаки?","options":["10 футов, 50 футов и 150 футов","25 футов, 75 футов и 250 футов","10 футов, 100 футов и 200 футов","10 футов, 100 футов и 500 футов"],"explanation":"Руководство CDL штата Оклахома (раздел 2, предупредительные устройства) требует, чтобы на дороге с односторонним движением или разделённом шоссе предупредительные устройства были установлены на расстоянии 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта."},"61":{"q":"На двухполосной дороге Оклахомы с движением в обоих направлениях (неразделённой) где должен стоящий коммерческий автомобиль (CMV) установить свои три предупредительных устройства?","options":["На расстоянии 10 футов, 100 футов и 200 футов только позади автомобиля","В пределах 10 футов от автомобиля, а также 100 футов позади и 100 футов впереди автомобиля","На расстоянии 50 футов, 100 футов и 200 футов на обочине","В пределах 10 футов от автомобиля, а также 200 футов позади и 200 футов впереди автомобиля"],"explanation":"Руководство CDL штата Оклахома гласит, что на двухполосной дороге с двусторонним движением или неразделённом шоссе одно устройство устанавливается в пределах 10 футов от автомобиля для обозначения его местоположения, а ещё по одному — на 100 футов впереди и на 100 футов позади автомобиля."},"62":{"q":"После остановки на проезжей части или обочине в Оклахоме в течение скольких минут водитель коммерческого автомобиля (CMV) должен выставить необходимые предупредительные устройства?","options":["5 минут","15 минут","30 минут","10 минут"],"explanation":"Руководство CDL штата Оклахома (раздел 2) гласит, что если вы вынуждены остановиться на дороге или обочине любой дороги, вы должны выставить аварийные предупредительные устройства в течение десяти минут."},"63":{"q":"Сколько предупредительных устройств должен иметь при себе коммерческий автомобиль (CMV) в Оклахоме для использования, когда автомобиль припаркован или неисправен?","options":["Два светоотражающих треугольника, или 4 фальшфейера (fuses), или 2 жидкостных сигнальных огня (flares)","Четыре светоотражающих треугольника, или 8 фальшфейеров (fuses), или 4 жидкостных сигнальных огня (flares)","Один светоотражающий треугольник, или 3 фальшфейера (fuses), или 1 жидкостный сигнальный огонь (flare)","Три светоотражающих треугольника, или 6 фальшфейеров (fuses), или 3 жидкостных сигнальных огня (flares)"],"explanation":"Руководство CDL штата Оклахома перечисляет необходимые предупредительные устройства для припаркованных автомобилей: три красных светоотражающих треугольника, или не менее 6 фальшфейеров (fuses), или 3 жидкостных сигнальных огня (flares)."},"64":{"q":"Согласно закону Оклахомы (47 O.S. Section 11-705), когда водитель, движущийся в противоположном направлении, НЕ обязан останавливаться перед школьным автобусом, который высаживает или забирает детей с включёнными мигающими красными огнями?","options":["Когда автобус находится по другую сторону любой нарисованной осевой линии","Когда движение интенсивное и остановка была бы неудобна","Когда направления движения разделены центральной двусторонней полосой для левого поворота","Когда проезжая часть разделена физическим барьером или непокрытой грунтовой разделительной полосой (median), разделяющей направления движения"],"explanation":"Закон Оклахомы 47 O.S. Section 11-705 освобождает встречный транспорт от остановки только тогда, когда разделённое шоссе с физическим барьером или непокрытой грунтовой разделительной полосой (median) разделяет проезжие части. Нарисованная линия или центральная полоса для поворота НЕ подходят под это условие, поэтому в таких случаях встречный транспорт всё равно обязан останавливаться."},"65":{"q":"На неразделённом двухполосном шоссе Оклахомы что должен сделать водитель, встречающий стоящий школьный автобус с мигающими красными огнями и выдвинутым знаком «стоп» (stop arm)?","options":["Остановиться независимо от направления движения, пока автобус не уберёт знак «стоп» и не выключит красные огни","Снизить скорость до 25 mph и проехать с осторожностью","Остановиться, только если движется в том же направлении, что и автобус","Продолжать движение как обычно, потому что останавливаться обязан только транспорт, движущийся в том же направлении"],"explanation":"Согласно 47 O.S. Section 11-705, на неразделённом шоссе транспорт в обоих направлениях обязан останавливаться перед школьным автобусом с включёнными мигающими красными огнями и выдвинутым знаком «стоп» (stop arm) и оставаться остановленным, пока автобус не уберёт эти сигналы."},"66":{"q":"Каков штраф за первое осуждение за незаконный обгон стоящего школьного автобуса в Оклахоме, который высаживает или забирает детей?","options":["Фиксированно $50","Минимум $100 и до $500","Минимум $250 и до $1,000","Фиксированно $1,500 плюс обязательное тюремное заключение"],"explanation":"Закон Оклахомы 47 O.S. Section 11-705 устанавливает штраф не менее $100 и до $500 за первое нарушение в виде незаконного обгона стоящего школьного автобуса, с возрастающими наказаниями (включая возможное приостановление действия прав) за повторные нарушения."},"67":{"q":"Согласно закону Оклахомы об использовании полос (47 O.S. Section 11-309), на проезжей части с четырьмя или более полосами когда автомобиль может законно двигаться по крайней левой полосе?","options":["Только при обгоне и опережении другого автомобиля, при подготовке к левому повороту или когда этого требуют условия движения/дороги","В любое время, если водитель сохраняет установленную максимальную скорость","Только когда правые полосы полностью свободны","Только между восходом и закатом солнца"],"explanation":"Закон Оклахомы 47 O.S. Section 11-309 ограничивает использование левой полосы обгоном, подготовкой к левому повороту или ситуациями, когда этого требует поток движения или конфигурация дороги. Автомобиль не может препятствовать нормальному потоку движения, постоянно двигаясь по левой полосе, даже с установленной максимальной скоростью."},"68":{"q":"Какова наивысшая максимальная скорость, которая может быть установлена на участках платных дорог (turnpikes) Оклахомы в соответствии с законом?","options":["85 mph","75 mph","80 mph","70 mph"],"explanation":"Согласно 47 O.S. Section 11-801, Управление платных дорог Оклахомы (Oklahoma Turnpike Authority) может устанавливать максимальную скорость до 80 mph на утверждённых участках системы платных дорог. Несколько отрезков (например, части Turner и Indian Nation Turnpikes) имеют ограничение 80 mph."},"69":{"q":"При приближении к железнодорожному переезду в Оклахоме когда водитель автобуса или автомобиля с табличками опасных грузов должен включить аварийную сигнализацию?","options":["Примерно за 200 футов до переезда","Примерно за 50 футов до переезда","Примерно за 500 футов до переезда","Только после полной остановки на переезде"],"explanation":"Руководство CDL штата Оклахома (раздел 10.4, процедуры проезда переезда для школьных автобусов) предписывает водителю включать аварийную сигнализацию примерно за 200 футов до переезда, чтобы следующий за ним транспорт был предупреждён о предстоящей остановке."},"70":{"q":"Пока какая-либо часть коммерческого автомобиля в Оклахоме находится на железнодорожном переезде, какое действие запрещено?","options":["Переключение или смена передач","Держание обеих рук на рулевом колесе","Наблюдение и прислушивание к поездам","Поддержание постоянной скорости"],"explanation":"Руководство CDL штата Оклахома инструктирует водителей не переключать передачи во время проезда путей, потому что неудачное переключение может оставить автомобиль заглохшим на переезде. Водители должны выбрать передачу перед переездом и удерживать её на протяжении всего проезда путей."},"71":{"q":"Когда школьный автобус в Оклахоме останавливается для высадки учащихся, на каком расстоянии от учащихся на остановке автобус должен быть полностью остановлен?","options":["Не менее чем в 3 футах от учащихся","Не менее чем в 25 футах от учащихся","Не менее чем в 10 футах от учащихся","Не менее чем в 50 футах от учащихся"],"explanation":"Руководство CDL штата Оклахома (раздел 13, экзамен на навыки, высадка учащихся) предписывает водителю полностью останавливать школьный автобус не менее чем в 10 футах от учащихся на остановке, что позволяет водителю хорошо видеть учащихся."},"72":{"q":"Какова стандартная установленная законом максимальная ширина автомобиля с грузом в Оклахоме, прежде чем потребуется разрешение на негабаритный груз от ODOT?","options":["8 футов 0 дюймов","10 футов 0 дюймов","8 футов 6 дюймов","9 футов 6 дюймов"],"explanation":"Согласно правилам ODOT о габаритах и весе, установленный законом предел ширины в Оклахоме составляет 8 футов 6 дюймов; грузы шире этого требуют разрешения на негабаритный груз. Установленный законом предел высоты составляет 13 футов 6 дюймов."},"73":{"q":"Перемещение негабаритных грузов в Оклахоме, как правило, ограничено каким периодом времени?","options":["Только между 9:00 p.m. и 5:00 a.m.","Светлым временем суток, с 30 минут до восхода солнца до 30 минут после заката солнца","Круглосуточно, без ограничений по времени","Только по выходным и праздничным дням"],"explanation":"Правила ODOT о разрешениях на негабаритные грузы ограничивают перемещение светлым временем суток, которое определяется как с 30 минут до восхода солнца до 30 минут после заката солнца, с дополнительными ограничениями при неблагоприятной погоде и пониженной видимости."},"74":{"q":"Оклахома ограничивает движение негабаритных грузов по системе межштатных автомагистралей (Interstate System) в часы пик в будние дни в каких округах?","options":["Округа Comanche, Garfield и Payne","Округа Muskogee, Pottawatomie и Carter","Округа Oklahoma, Tulsa и Cleveland","Округа Canadian, Rogers и Wagoner"],"explanation":"Правила ODOT о негабаритных грузах запрещают негабаритные грузы на системе межштатных автомагистралей (Interstate System) в округах Oklahoma, Tulsa и Cleveland в часы пик в будние дни — с 7:00 до 9:00 a.m. и с 3:30 до 6:30 p.m. (центральное время), с понедельника по пятницу."},"75":{"q":"Осуждение за нарушение правил проезда железнодорожного переезда в одном уровне с дорогой на коммерческом автомобиле приводит к какой минимальной дисквалификации CDL в Оклахоме за первое нарушение?","options":["Не менее 30 дней","Не менее 120 дней","Не менее одного года","Не менее 60 дней"],"explanation":"Руководство CDL штата Оклахома (раздел 1.3.5) гласит, что владелец CDL дисквалифицируется не менее чем на 60 дней за первое нарушение правил проезда железнодорожного переезда, не менее чем на 120 дней за второе нарушение в течение трёх лет и не менее чем на один год за третье нарушение в течение трёх лет."},"76":{"q":"Какое государственное ведомство Оклахомы выдаёт коммерческие водительские права (CDL) и проводит тестирование знаний и навыков CDL?","options":["Service Oklahoma","Департамент транспорта Оклахомы (ODOT)","Корпоративная комиссия Оклахомы (Oklahoma Corporation Commission)","Налоговая комиссия Оклахомы (Oklahoma Tax Commission)"],"explanation":"Service Oklahoma (которое приняло на себя функции выдачи водительских прав, ранее выполнявшиеся Департаментом общественной безопасности) выдаёт CDL и проводит тестирование CDL в своих лицензионных офисах. Источник: страницы Service Oklahoma «Commercial Driving CDL» и «CDL First-Time Applicants» (oklahoma.gov)."},"77":{"q":"Где соискатель CDL в Оклахоме сдаёт необходимые тесты на зрение и письменный тест знаний?","options":["Лично в лицензионном офисе Service Oklahoma","Онлайн через портал Service Oklahoma из дома","В любой школе из реестра поставщиков обучения FMCSA (Training Provider Registry)","В штаб-квартире отряда дорожного патруля Оклахомы (Oklahoma Highway Patrol)"],"explanation":"Соискатели начинают процесс получения CDL со сдачи тестов на зрение и письменного теста знаний лично в лицензионном офисе Service Oklahoma; тест на зрение и письменный тест проводятся вместе на одном приёме. Источник: Service Oklahoma «CDL First-Time Applicants» (oklahoma.gov)."},"78":{"q":"В течение скольких дней соискатель в Оклахоме должен владеть коммерческим ученическим разрешением (CLP), прежде чем ему будет разрешено сдавать экзамен на навыки вождения CDL (drive test)?","options":["14 полных дней, с возможностью тестирования на 15-й день","30 полных дней, с возможностью тестирования на 31-й день","7 полных дней, с возможностью тестирования на 8-й день","10 полных дней, с возможностью тестирования на 11-й день"],"explanation":"Оклахома требует, чтобы CLP удерживалось в течение 14 полных дней до экзамена на навыки; соискатель может сдавать экзамен на 15-й день. Это соответствует федеральному правилу 14 дней. Источник: Service Oklahoma «CDL First-Time Applicants» (oklahoma.gov); 49 CFR 383.25."},"79":{"q":"Экзамен на навыки CDL в Оклахоме состоит из трёх частей. Какой набор правильно перечисляет эти три части?","options":["Предрейсовый осмотр автомобиля, базовые навыки управления и тест вождения по дороге","Тест общих знаний, тест пневматических тормозов и тест составных транспортных средств (combination vehicles)","Тест на зрение, письменный тест и курс безопасного вождения","Предрейсовый осмотр, тест на опасные грузы (hazardous materials) и тест на движение задним ходом"],"explanation":"Экзамен на навыки CDL в Оклахоме состоит из трёх частей: предрейсовый осмотр автомобиля, базовые навыки управления (например, манёвры задним ходом) и тест вождения по дороге. Источник: Service Oklahoma «CDL First-Time Applicants» (oklahoma.gov); 49 CFR 383.113."},"80":{"q":"Согласно федеральным правилам обучения водителей начального уровня (ELDT), которые применяет Оклахома, впервые подающий заявку на класс A или класс B соискатель должен пройти ELDT у утверждённого поставщика, прежде чем сделать что?","options":["Сдать проводимый штатом экзамен на навыки CDL","Получить коммерческое ученическое разрешение (CLP)","Сдать письменный тест общих знаний","Пройти проверку зрения"],"explanation":"ELDT (теория и практика за рулём) для впервые получаемого CDL класса A или B должно быть пройдено через поставщика из реестра поставщиков обучения FMCSA (Training Provider Registry), прежде чем соискатель сдаёт проводимый штатом экзамен на навыки. Источник: правило FMCSA ELDT (49 CFR Part 380); Service Oklahoma «CDL First-Time Applicants» (oklahoma.gov)."},"81":{"q":"Где должен быть указан поставщик обучения водителей начального уровня (ELDT) соискателя CDL в Оклахоме, чтобы обучение было засчитано?","options":["В реестре поставщиков обучения FMCSA (Training Provider Registry, TPR)","В списке школ Департамента транспорта Оклахомы","В справочнике утверждённых поставщиков Service Oklahoma","В Национальном реестре сертифицированных медицинских экспертов (National Registry of Certified Medical Examiners)"],"explanation":"ELDT должно быть получено у поставщика, указанного в реестре поставщиков обучения FMCSA (Training Provider Registry, TPR). Источник: правило FMCSA ELDT; Service Oklahoma «Commercial Driving CDL» (oklahoma.gov)."},"82":{"q":"Какое разрешение (endorsement) CDL требует прохождения теоретической части обучения ELDT ДО сдачи теста знаний (а не экзамена на навыки)?","options":["Разрешение на опасные грузы (Hazardous Materials, H)","Пассажирское разрешение (Passenger, P)","Разрешение на школьный автобус (School Bus, S)","Разрешение на сдвоенные/строенные прицепы (Doubles/Triples, T)"],"explanation":"Для разрешения на опасные грузы (Hazardous Materials, H) ELDT является только теоретическим и должно быть пройдено до проводимого штатом теста знаний. Разрешения P и S требуют ELDT до их экзаменов на навыки. Источник: правило FMCSA ELDT (49 CFR Part 380)."},"83":{"q":"Из скольких категорий самосертификации должен выбрать соискатель CDL в Оклахоме при декларировании своего типа вождения?","options":["Из четырёх","Из двух","Из трёх","Из шести"],"explanation":"Соискатели должны самостоятельно отнести себя к одной из четырёх категорий: межштатные перевозки без исключений (Non-Excepted Interstate, NI), межштатные перевозки с исключениями (Excepted Interstate, EI), внутриштатные перевозки без исключений (Non-Excepted Intrastate, NA) и внутриштатные перевозки с исключениями (Excepted Intrastate, EA). Источник: Service Oklahoma «CDL First-Time Applicants» и регламент самосертификации CDL (oklahoma.gov)."},"84":{"q":"Какая категория самосертификации ТРЕБУЕТ, чтобы водитель имел в деле действующий медицинский сертификат DOT (DOT Medical Examiner's Certificate) для лицензирования?","options":["Межштатные перевозки без исключений (Non-Excepted Interstate, NI)","Межштатные перевозки с исключениями (Excepted Interstate, EI)","Внутриштатные перевозки с исключениями (Excepted Intrastate, EA)","Внутриштатные перевозки без исключений (Non-Excepted Intrastate, NA)"],"explanation":"Только категория межштатных перевозок без исключений (Non-Excepted Interstate, NI) требует медицинской карты DOT для лицензирования. Категории EI, NA и EA не требуют наличия медицинской карты в деле Service Oklahoma. Источник: Service Oklahoma «CDL First-Time Applicants» / «Commercial Driving CDL» (oklahoma.gov)."},"85":{"q":"Как теперь передаётся медицинский сертификат DOT (DOT Medical Examiner's Certificate) водителя в Service Oklahoma для учёта?","options":["Электронно из Национального реестра сертифицированных медицинских экспертов FMCSA (FMCSA National Registry of Certified Medical Examiners)","Водитель отправляет бумажную копию по почте в штаб-квартиру Service Oklahoma","Работодатель отправляет его по факсу в местный лицензионный офис","Окружное агентство по выдаче номерных знаков (tag agency) пересылает нотариально заверенную копию"],"explanation":"Сертифицированный медицинский эксперт электронно подаёт сертификат (форма MCSA-5876) в Национальный реестр FMCSA, который электронно передаёт статус медицинской сертификации в Service Oklahoma. Источник: регламент Service Oklahoma по обработке самосертификации CDL и медицинских сертификатов (oklahoma.gov); Национальный реестр FMCSA."},"86":{"q":"Какой номер имеет федеральный медицинский сертификат (Medical Examiner's Certificate), который сертифицированный эксперт подаёт в Национальный реестр FMCSA?","options":["MCSA-5876","MCSA-5875","MCSA-5889","MCSA-5870"],"explanation":"Медицинский сертификат — это форма FMCSA MCSA-5876; связанный с ним отчёт о медицинском обследовании (Medical Examination Report) — это MCSA-5875. Эксперт подаёт результат MCSA-5876 в Национальный реестр. Источник: регламент Service Oklahoma по обработке медицинских сертификатов; FMCSA."},"87":{"q":"Владелец CDL категории межштатных перевозок без исключений (Non-Excepted Interstate, NI) в Оклахоме обычно должен предоставлять действующий медицинский сертификат DOT (DOT Medical Examiner's Certificate) как минимум с какой периодичностью (максимальный интервал между обследованиями согласно стандартам FMCSA)?","options":["Каждые 24 месяца","Каждые 12 месяцев","Каждые 36 месяцев","Каждые 60 месяцев"],"explanation":"Стандартный медицинский сертификат действителен максимум 24 месяца, поэтому водители категории NI должны иметь в деле действующий сертификат в пределах этого цикла (при определённых состояниях применяются более короткие интервалы). Источник: медицинские рекомендации Service Oklahoma по CDL; 49 CFR 391.45."},"88":{"q":"Если Service Oklahoma уведомлено о том, что медицинская сертификация владельца CDL истекла или больше недействительна, в течение скольких дней ведомство должно понизить класс CDL (downgrade) согласно федеральному правилу?","options":["В течение 60 дней","В течение 10 дней","В течение 30 дней","В течение 90 дней"],"explanation":"Государственные ведомства по лицензированию водителей, включая Service Oklahoma, должны понизить класс CDL (downgrade) в течение 60 дней после получения сведений о том, что водитель больше не имеет медицинской сертификации или что медицинский сертификат истёк и не был продлён. Источник: рекомендации Service Oklahoma по понижению класса; 49 CFR 383.73(o)."},"89":{"q":"Согласно закону Оклахомы, на какой срок изначально действительно коммерческое ученическое разрешение (CLP)?","options":["180 дней","90 дней","60 дней","1 год"],"explanation":"Оклахома выдаёт CLP на срок 180 дней; оно может быть продлено один раз ещё на 180 дней. Источник: 47 O.S. Section 6-101; рекомендации Service Oklahoma по CLP."},"90":{"q":"CLP в Оклахоме может быть продлено один раз. На какой срок действительно это единственное продление?","options":["Ещё на 180 дней","Ещё на 30 дней","Ещё на 1 год","Ещё на 90 дней"],"explanation":"CLP действительно 180 дней и может быть продлено один раз ещё на 180 дней, что в сумме допускает до одного года. Источник: 47 O.S. Section 6-101; рекомендации Service Oklahoma по CLP."},"91":{"q":"Каков минимальный возраст для получения CDL для ВНУТРИШТАТНОГО (только в пределах Оклахомы) коммерческого вождения?","options":["18 лет","21 год","16 лет","19 лет"],"explanation":"Соискателю должно быть не менее 18 лет для управления коммерческим автомобилем (CMV) внутри штата (в пределах Оклахомы) и не менее 21 года для межштатного вождения. Источник: рекомендации Service Oklahoma по CDL; 47 O.S. Section 6-101."},"92":{"q":"19-летний владелец CDL в Оклахоме, которому ещё не исполнился 21 год, как правило, ограничен каким образом?","options":["Только внутриштатным (в пределах Оклахомы) коммерческим вождением","Вождением только коммерческих автомобилей класса C","Только дневным коммерческим вождением","Вождением только в присутствии лицензированного владельца CDL"],"explanation":"Водители в возрасте от 18 до 20 лет могут иметь CDL, но ограничены внутриштатными (в пределах Оклахомы) коммерческими перевозками; межштатные перевозки требуют возраста 21 год. Источник: рекомендации Service Oklahoma по CDL; 49 CFR 383.3 / 391.11."},"93":{"q":"Какой документ НЕ входит в число тех, что впервые подающий заявку соискатель CDL в Оклахоме обязан предъявить в лицензионном офисе Service Oklahoma?","options":["Письмо от работодателя, разрешающее дорожный тест","Подтверждение личности и законного пребывания","Подтверждение проживания в Оклахоме (одно подтверждение адреса)","Действующие водительские права класса D штата Оклахома"],"explanation":"К необходимым документам относятся подтверждение личности и законного пребывания, подтверждение проживания/адреса, действующие права класса D штата Оклахома и номер социального страхования; письмо-разрешение от работодателя не требуется. Источник: Service Oklahoma «CDL First-Time Applicants» (oklahoma.gov)."},"94":{"q":"Что касается продления CDL в Оклахоме, какое утверждение точно описывает этот процесс?","options":["Имеющие право владельцы CDL могут продлить онлайн, но владельцы разрешения на опасные грузы (Hazardous Materials, H) должны продлевать лично и повторно сдавать письменный тест по опасным грузам (HazMat), а также проходить проверку биографии TSA","Все продления CDL, включая HazMat, могут быть полностью выполнены онлайн","CDL нельзя продлить, и их необходимо пересдавать с нуля каждый цикл","Продление требует повторной сдачи полного трёхчастного экзамена на навыки каждый раз"],"explanation":"Service Oklahoma предлагает онлайн-продление CDL для имеющих право владельцев, но владельцы разрешения на опасные грузы (HazMat) должны продлевать лично, повторно сдавать тест знаний по опасным грузам (HazMat) и проходить проверку биографии TSA при каждом продлении. (Примечание: точные сборы и выбранный срок действия документа, например варианты 4 года против 8 лет, могут меняться.) Источник: Service Oklahoma «CDL Renewal/Replacement Online» (oklahoma.gov)."}},"tr":{"0":{"q":"Oklahoma karayollarında, yüklü veya yüksüz bir aracın, aşırı genişlik izni gerekmeden sahip olabileceği maksimum toplam dış genişlik nedir?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"Oklahoma, toplam dış genişliği 102 inches (8,5 ft) ile sınırlar; daha fazla genişlik için aşırı genişlik izni gerekir. Kaynak: 47 O.S. §14-103."},"1":{"q":"Bir Oklahoma paralı yolunda (turnpike), eyaletler arası (interstate), ABD veya eyalet karayolunda, özel izin olmadan bir araç veya yükün maksimum yasal yüksekliği nedir?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"Oklahoma, paralı yollarda, eyaletler arası, ABD ve eyalet karayollarında izin olmadan 14 feet'e kadar yüksekliğe izin verir. Kaynak: 47 O.S. §14-103."},"2":{"q":"Oklahoma'da bir İLÇE (county) yolunda, özel izin olmadan bir araç veya yük için maksimum yükseklik nedir?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"İlçe yollarında yükseklik sınırı 13,5 feet'tir; bu, paralı yollarda, eyaletler arası, ABD ve eyalet karayollarında izin verilen 14 feet'lik sınırdan daha düşüktür. Kaynak: 47 O.S. §14-103."},"3":{"q":"Oklahoma'da, aşırı ağırlık izni olmadan tek bir aks üzerine izin verilen maksimum ağırlık nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Oklahoma'nın tek aks ağırlık sınırı 20,000 pounds'tur. Kaynak: 47 O.S. §14-109(A)."},"4":{"q":"Oklahoma'nın özel izin olmadan bir tandem aks grubuna izin verdiği maksimum ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Oklahoma'da herhangi bir tandem aks grubu üzerindeki maksimum yük 34,000 pounds'tur. Kaynak: 47 O.S. §14-109(B)."},"5":{"q":"Oklahoma karayollarında, ağırlık tablosuna göre özel izin olmadan genel maksimum brüt araç ağırlığı nedir?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"Oklahoma'nın ağırlık tablosu, yasal brüt ağırlığı federal sınıra uygun olarak 80,000 pounds ile sınırlar. Kaynak: 47 O.S. §14-109(A)."},"6":{"q":"Oklahoma'da izin verilen brüt ve aks ağırlıkları, aks aralığına dayalı bir formül kullanılarak belirlenir. Bu formül genellikle ne olarak adlandırılır?","options":["Federal Bridge Formula","Gross Combination Rule","Tare Weight Formula","Axle Spread Ratio"],"explanation":"Oklahoma, en uç akslar arasındaki mesafeyi en yakın feet'e kadar ölçen Federal Bridge Formula/ağırlık tablosunu (23 U.S.C. §127) kullanır. Kaynak: 47 O.S. §14-109; ODPS Troop S."},"7":{"q":"Oklahoma yollarında, tamponlar dahil TEK bir kamyonun (kombinasyon değil) maksimum toplam uzunluğu nedir?","options":["40 feet","45 feet","53 feet","70 feet"],"explanation":"Oklahoma'da tek bir kamyon, ön ve arka tamponlar dahil toplam uzunlukta 45 feet'i aşamaz. Kaynak: 47 O.S. §14-103."},"8":{"q":"National Network üzerinde, Oklahoma'da bir çekici/yarı römork kombinasyonunda (izin olmadan) maksimum yarı römork uzunluğu nedir?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"Bir çekici/yarı römork kombinasyonundaki yarı römork, National Network üzerinde 53 feet'e kadar olabilir; daha uzun (59'6\"'a kadar) için izin gerekir. Kaynak: 47 O.S. §14-103."},"9":{"q":"Tüm Oklahoma yollarında ve karayollarında, çekici/yarı römork DIŞINDAKİ araç kombinasyonları için maksimum toplam uzunluk nedir?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"Diğer araç kombinasyonları, tüm Oklahoma yollarında ve karayollarında tamponlar dahil toplam 70 feet'i aşamaz. Kaynak: 47 O.S. §14-103."},"10":{"q":"Hangi Oklahoma kurum birimi, eyalet karayolu sisteminde seyahat için aşırı boyut/aşırı ağırlık izinlerini düzenler?","options":["Oklahoma Vergi Komisyonu (Oklahoma Tax Commission)","ODOT Size and Weight Permit Division (Boyut ve Ağırlık İzin Birimi)","Corporation Commission (Şirket Komisyonu)","İlçe şerifinin ofisi"],"explanation":"ODOT Size and Weight Permit Division, aşırı boyut/aşırı ağırlık izinlerini düzenler (swpermitsok.com adresinden çevrimiçi başvuru yapılır). Kaynak: ODOT; OAC 730:50-5."},"11":{"q":"Oklahoma'da bir kamyon ve yarı römork kombinasyonu, özel bir YILLIK aşırı genişlik izni altında hangi maksimum genişliğe kadar çalışabilir?","options":["108 inches","114 inches","120 inches","144 inches"],"explanation":"Genişliği 102 inches'i aşan ancak 120 inches'i geçmeyen kombinasyonlar, özel bir yıllık aşırı genişlik izni altında çalışabilir. Kaynak: OAC 730:50-5; 47 O.S. §14-103G."},"12":{"q":"Oklahoma kurallarına göre, 12 feet'ten geniş ancak 14 feet'ten fazla olmayan izinli bir yük, iki şeritli bir karayolunda hangi refakat düzenlemesine sahip olmalıdır?","options":["Refakat gerekmez","Bir ön refakat aracı","Bir arka refakat aracı","Hem ön hem de arka refakat araçları"],"explanation":"12 ft'ten geniş ancak 14 ft'ten geniş olmayan yükler, iki şeritli/süper iki şeritli karayollarında ön refakat aracına ihtiyaç duyar (çok şeritlide arka refakat). Kaynak: OAC 730:50-5-18(b)."},"13":{"q":"Oklahoma'da izinli bir yük, hangi toplam YÜKSEKLİKTE İKİ refakat aracı (biri ön, biri arka) ve hizmet kuruluşlarına ve demiryollarına önceden bildirim gerektirir?","options":["14 feet veya daha fazla","14 feet 6 inches veya daha fazla","15 feet veya daha fazla","15 feet 9 inches veya daha fazla"],"explanation":"Toplam yüksekliği 15 feet 9 inches veya daha fazla olan yükler, iki refakat aracı ve etkilenen hizmet kuruluşları/demiryolları ile önceden iletişim gerektirir. Kaynak: OAC 730:50-5-18(b)."},"14":{"q":"Hangi toplam uzunluktaki bir çekici/yarı römork kombinasyonu, Oklahoma'nın iki şeritli karayollarında zorunlu bir ön refakat aracı gerektirir?","options":["70 feet'ten fazla","75 feet'ten fazla","80 feet'ten fazla","100 feet'ten fazla"],"explanation":"Toplam 80 feet'ten fazla olan bir çekici/yarı römork kombinasyonu, iki şeritli karayollarında bir ön refakat aracı gerektirir. Kaynak: OAC 730:50-5-18(b)(4)."},"15":{"q":"Oklahoma'nın tarım ürünleri ağırlık varyansı kapsamında (ODPS Troop S'e göre), hangi toleranslar geçerlidir ve seyahat nerede yasaktır?","options":["Brüt üzerinde %5 ve aks sınırları üzerinde %8; eyaletler arası karayollarında değil","Brüt üzerinde %10 ve aks üzerinde %10; paralı yollarda değil","Brüt üzerinde %8 ve aks üzerinde %5; ilçe yollarında değil","Brüt üzerinde %5 ve aks üzerinde %5; eyaletler arası izinli"],"explanation":"Maksimum kayıtla tarım ürünleri taşıyan araçlar, brüt sınırın %5 ve aks sınırlarının %8 üzerine kadar çalışabilir, ancak Interstate sistemde değil. Kaynak: ODPS Troop S; 47 O.S. §14-109."},"16":{"q":"Aks sınırının yaklaşık %8 üzerine izin veren bir tarımsal ağırlık varyans izniyle, 20,000 pounds'luk tek aks değeri yaklaşık olarak ne olur?","options":["20,800 pounds","21,600 pounds","22,400 pounds","24,000 pounds"],"explanation":"Varyansla (aks üzerinde %8), 20,000-lb'lik tek aks sınırı 21,600 lbs olur; herhangi bir kategoriyi aşmak, o sefer için izni geçersiz kılar. Kaynak: ODPS Troop S aks tablosu."},"17":{"q":"Oklahoma'nın ODOT Annual Envelope Vehicle Permit'i (Yıllık Zarf Aracı İzni), eyalet karayolu sisteminde bir araca hangi maksimum boyutlara kadar yetki verir?","options":["10 ft genişlik, 13,5 ft yükseklik, 90 ft uzunluk","12 ft genişlik, 14 ft yükseklik, 110 ft uzunluk","14 ft genişlik, 15 ft yükseklik, 120 ft uzunluk","12 ft genişlik, 16 ft yükseklik, 100 ft uzunluk"],"explanation":"Annual Envelope Vehicle Permit, 12 ft genişliğe, 14 ft yüksekliğe ve 110 ft uzunluğa kadar araçları kapsar (ücret 4.000 dolar), yalnızca eyalet karayolu sisteminde geçerlidir. Kaynak: OAC 730:50-5-13."},"18":{"q":"Oklahoma'da doğal halindeki ham orman ürünlerini taşıyanlar, 25 dolarlık yıllık tarım izni alabilir, ancak hangi güzergah kısıtlamasıyla?","options":["Interstate sisteminde seyahat yok","Hiçbir paralı yolda seyahat yok","İlçe yollarında seyahat yok","Yalnızca geceleri seyahat yok"],"explanation":"25 dolarlık yıllık tarım izni kapsamında ham orman ürünleri taşımacılığına, National System of Interstate and Defense Highways üzerinde izin verilmez. Kaynak: OAC 730:50-5-22; 47 O.S. §14-118(e)."},"19":{"q":"Oklahoma'da, çekilen aracın GVWR'si 10,000 pounds'tan fazla olduğunda, 26,001 veya daha fazla pound brüt kombinasyon ağırlık derecesine (GCWR) sahip herhangi bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Oklahoma federal sınıflandırmayı benimser: bir Class A CDL, çekilen birim(ler)in 10,000 lbs GVWR'yi aştığı, GCWR'si 26,001+ lbs olan herhangi bir araç kombinasyonunu kapsar. Kaynak: Oklahoma Statutes Title 47 Sec. 6-101 ve Oklahoma CDL Manual (Service Oklahoma)."},"20":{"q":"Bir Oklahoma sürücüsü, römork çekmeyen, GVWR'si 30,000 pounds olan tek bir düz kasa kamyon kullanıyor. Bu hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"Bir Class B CDL, GVWR'si 26,001+ lbs olan herhangi bir tek aracı (veya 10,000 lbs GVWR'yi geçmeyen bir birimi çeken böyle bir aracı) kapsar. 30,000-lb'lik bir düz kasa kamyon Class B kapsamına girer. Kaynak: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"21":{"q":"Oklahoma kurallarına göre, Class A veya Class B ağırlık eşiklerini karşılamayan bir araç, ne yaptığı takdirde yine de bir Class C CDL gerektirir?","options":["16,000 pounds'tan fazla GVWR'ye sahipse","Sürücü dahil 16 veya daha fazla kişiyi taşımak üzere tasarlanmışsa veya plaka (placard) gerektiren tehlikeli maddeler taşıyorsa","5,000 pounds'tan fazla dereceli herhangi bir römork çekiyorsa","İlçe sınırları boyunca ücret karşılığı çalıştırılıyorsa"],"explanation":"Bir Class C CDL, Class A veya B'yi karşılamayan, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış ya da plaka gerektiren tehlikeli maddeler taşıyan bir araç için geçerlidir. Kaynak: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"22":{"q":"Tehlikeli olarak tanımlanan ve plaka (placard) gerektiren maddeleri taşımak için bir Oklahoma CDL'ye hangi onay (endorsement) kodu eklenmelidir?","options":["N","T","H","P"],"explanation":"Plaka gerektiren tehlikeli maddeleri taşımak için H (HazMat) onayı gereklidir. Kaynak: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"23":{"q":"N (Tanker) onayını gerektiren bir 'tank aracını' tanımlayan federal/Oklahoma kapasite eşiği nedir?","options":["119 galondan fazla bireysel dereceli kapasiteye ve 1,000 galon veya daha fazla toplam dereceli kapasiteye sahip bir tank","100 galondan fazla bireysel dereceli kapasiteye sahip bir tank","Toplamda 500 galon veya daha fazla taşıyan herhangi bir tank","2,000 galon veya daha fazla toplam kapasiteye sahip bir tank"],"explanation":"N onayı, 119 galondan fazla bireysel dereceli kapasiteye VE 1,000 galon veya daha fazla toplam dereceli kapasiteye sahip bir tankta sıvı veya gaz taşıyan araçlar için gereklidir. Kaynak: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.5."},"24":{"q":"İkili veya üçlü römorkları çekmek için hangi Oklahoma CDL onayı gereklidir ve sürücünün halihazırda hangi CDL sınıfına sahip olması gerekir?","options":["T onayı, bir Class A CDL ile birlikte","T onayı, bir Class B CDL ile birlikte","N onayı, bir Class A CDL ile birlikte","P onayı, bir Class C CDL ile birlikte"],"explanation":"T (Doubles/Triples) onayı, birden fazla römork çekilmesine izin verir ve gerekli ek bilgiyi göstermesi gereken Class A sürücüleri tarafından eklenir. Kaynak: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"25":{"q":"Bir Oklahoma sürücüsü, sürücü dahil 16 veya daha fazla kişiyi taşımak üzere tasarlanmış bir aracı kullanmak istiyor. Hangi onay gereklidir?","options":["S (School Bus)","P (Passenger)","N (Tanker)","T (Doubles/Triples)"],"explanation":"Sürücü dahil 16 veya daha fazla kişiyi taşımak üzere tasarlanmış bir aracı kullanmak için P (Passenger) onayı gereklidir; bir bilgi testini ve temsili bir araçta bir beceri testini geçmeyi gerektirir. Kaynak: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"26":{"q":"Bir Oklahoma sürücüsü School Bus (S) onayını alabilmeden önce, ön koşul olarak hangi diğer onay gereklidir?","options":["H (HazMat) onayı","N (Tanker) onayı","P (Passenger) onayı","T (Doubles/Triples) onayı"],"explanation":"S (School Bus) onayı, sürücünün önce P (Passenger) onayına sahip olmasını, ardından bir okul otobüsü bilgi testini ve bir okul otobüsünde bir beceri testini geçmesini gerektirir. Kaynak: Oklahoma CDL Manual / Endorsements (Service Oklahoma); 49 CFR 383.93."},"27":{"q":"Yalnızca eyalet içi (Oklahoma içi) çalışmayla sınırlı bir Oklahoma CDL'si almak için minimum yaş nedir?","options":["16","18","21","25"],"explanation":"Bir sürücünün yalnızca eyalet içi bir Oklahoma CDL'sine sahip olabilmesi için en az 18 yaşında olması gerekir; 21 yaşın altındaki sürücüler bir 'K' yalnızca eyalet içi kısıtlaması alır. Kaynak: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"28":{"q":"Oklahoma'dan eyaletler arası ticarette (eyalet sınırları boyunca) bir CDL aracı kullanmak için gereken minimum yaş nedir?","options":["18","19","21","23"],"explanation":"Eyaletler arası CDL çalışması minimum 21 yaş gerektirir; 18 ila 20 yaşındaki sürücüler Oklahoma içinde eyalet içi çalışmayla sınırlıdır. Kaynak: Oklahoma CDL Manual (Service Oklahoma); 49 CFR 391.11."},"29":{"q":"Oklahoma'da gerekli bilgi testlerini geçtikten sonra, bir başvuru sahibinin CDL beceri (sürüş) testine girmeden önce bir Commercial Learner Permit (CLP) tutması ne kadar süre gerekir?","options":["7 tam gün","10 tam gün","14 tam gün","30 tam gün"],"explanation":"Federal ve Oklahoma kuralları, beceri testinden önce CLP'nin 14 tam gün tutulmasını gerektirir; test 15. günde alınabilir. Kaynak: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.25."},"30":{"q":"Bir Oklahoma Commercial Learner Permit (CLP) ne kadar süre geçerlidir ve nasıl uzatılabilir?","options":["90 gün, yenilenemez","180 gün, ek 180 gün için bir kez yenilenebilir","1 yıl, yıllık yenilenebilir","60 gün, üç kez yenilenebilir"],"explanation":"Bir Oklahoma CLP, 180 gün için verilir ve ek 180 gün için bir kez yenilenebilir. Kaynak: Oklahoma CDL Manual / Service Oklahoma; 49 CFR 383.25."},"31":{"q":"İlk kez başvuran bir Oklahoma CDL adayının bir Service Oklahoma ehliyet ofisinde hangi belge setini sunması gerekir?","options":["Yalnızca geçerli bir Class D ehliyeti ve bir doğum belgesi","Kimlik kanıtı, yasal varlık kanıtı, Social Security numarası ve Oklahoma ikamet kanıtı","Yalnızca bir Social Security kartı ve bir işveren mektubu","Bir pasaport ve araç sigortası kanıtı"],"explanation":"Service Oklahoma; kimlik kanıtı, yasal varlık, başvuru sahibinin SSN'i ve Oklahoma ikametini (standart için bir ikamet belgesi, REAL ID için iki) ve geçerli bir Class D ehliyetini gerektirir. Kaynak: Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"32":{"q":"İlk kez başvuran bir Oklahoma CDL adayı için Entry-Level Driver Training (ELDT) hangi resmi sistem aracılığıyla tamamlanmalıdır?","options":["Oklahoma Department of Education portalı","FMCSA Training Provider Registry","TSA Hazmat Threat Assessment Program","Oklahoma Tax Commission kaydı"],"explanation":"ELDT, tamamlanmayı elektronik olarak bildiren FMCSA Training Provider Registry'de listelenmiş bir okul tarafından sağlanmalıdır. Kaynak: FMCSA ELDT rule (49 CFR Part 380); Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"33":{"q":"Oklahoma'da uygulanan FMCSA kurallarına göre, beceri/bilgi testinden önce aşağıdakilerden hangisi ELDT (Entry-Level Driver Training) gerektirir?","options":["Tanker (N) onayını almak","Doubles/Triples (T) onayını almak","İlk kez Passenger (P) veya School Bus (S) onayını almak","Mevcut bir Class A CDL'yi yenilemek"],"explanation":"ELDT; ilk kez bir Class A veya B CDL için, bir B'den A'ya yükseltme için ve ilk kez H, P veya S onayları için gereklidir. N ve T onayları ELDT ile düzenlenmemiştir. Kaynak: FMCSA ELDT rule (49 CFR Part 380); Service Oklahoma."},"34":{"q":"Hazardous Materials (H) onayı için, Oklahoma'da uygulanan ELDT gerekliliği neden oluşur?","options":["Yalnızca teori eğitimi","Yalnızca direksiyon başında eğitim","Hem teori hem de direksiyon başında eğitim","Hiç eğitim yok"],"explanation":"H onayı için ELDT yalnızca teoriktir; yalnızca Class A/B CDL'leri ve P ile S onayları hem teori hem de direksiyon başında eğitim gerektirir. Kaynak: FMCSA ELDT rule (49 CFR Part 380)."},"35":{"q":"HazMat bilgi testini geçmenin yanı sıra, bir Oklahoma sürücüsünün H onayını alması veya korumasi için neye ihtiyacı vardır?","options":["5 yıl geçerli olan bir TSA güvenlik tehdidi değerlendirmesi (geçmiş kontrolü)","Bir tank aracında ikinci bir beceri testi","Noter onaylı bir işveren sponsorluk mektubu","Yıllık yenilenen ayrı bir eyalet HazMat izni"],"explanation":"H onayı, bir TSA Hazmat Threat Assessment (geçmiş kontrolü/parmak izi) gerektirir; onay 5 yıl geçerlidir ve onayla birlikte yenilenmelidir. Kaynak: TSA HTAP; 49 CFR 1572; Service Oklahoma CDL."},"36":{"q":"Plaka (placard) gerektiren tehlikeli maddeler taşıyan bir tank aracını kullanmaya yetkili bir sürücü için bir Oklahoma CDL'sinde hangi onay kodu verilir (birleşik HazMat ve Tank)?","options":["HN","X","T","Z"],"explanation":"Oklahoma, hem Tank (N) hem de Hazardous Materials (H) yetkisine sahip sürücüler için birleşik onay kodu 'X' verir. Kaynak: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.153."},"37":{"q":"Bir Oklahoma CDL adayı kaç tıbbi öz-sertifikasyon kategorisi arasından seçim yapar ve bunlardan hangisi bir DOT tıbbi muayene memurunun belgesini gerektirir?","options":["İki kategori; Excepted Interstate kategorisi tıbbi kartı gerektirir","Dört kategori; Non-Excepted Interstate (NI) kategorisi tıbbi kartı gerektirir","Üç kategori; Non-Excepted Intrastate kategorisi tıbbi kartı gerektirir","Dört kategori; Excepted Intrastate (EA) kategorisi tıbbi kartı gerektirir"],"explanation":"Dört öz-sertifikasyon kategorisi vardır (NI, EI, NA, EA). Yalnızca Non-Excepted Interstate (NI) sürücüleri geçerli bir DOT tıbbi muayene memuru belgesi sunmalı ve korumalıdır. Kaynak: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.71."},"38":{"q":"Bir Oklahoma CDL veya CLP, sahibinin Oklahoma eyaleti dışında ticari araçları kullanamadığı durumda hangi kısıtlama kodunu taşır?","options":["E","L","K","Z"],"explanation":"'K' kısıtlaması yalnızca eyalet içi anlamına gelir - sürücü bir CDL aracında Oklahoma'dan ayrılamaz (genellikle 21 yaşın altındaki sürücülere uygulanır). 'E' = manuel şanzıman yok, 'L' = hava freni yok, 'Z' = tam hava freni yok. Kaynak: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"39":{"q":"Oklahoma'da bir ticari motorlu araç (CMV) kullanırken, bir sürücü hangi kandaki alkol konsantrasyonunda (BAC) yasal olarak ehliyetsiz sayılır ve büyük bir suç işlemiş olur?","options":["0.02 veya daha fazla","0.04 veya daha fazla","0.08 veya daha fazla","0.10 veya daha fazla"],"explanation":"Oklahoma, CMV BAC sınırını, ticari olmayan sürücüler için olan 0.08 sınırının yarısı olan 0.04 veya daha fazla olarak belirler. Bir CMV'yi 0.04 veya üzerinde kullanmak büyük bir suçtur. Kaynak: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51, Oklahoma tarafından benimsendiği şekliyle."},"40":{"q":"Oklahoma'nın zımni rıza (implied consent) yasasına göre, bir CDL sahibi bir ticari motorlu aracı kullanarak neyi kabul etmiş sayılır?","options":["Herhangi bir tartı istasyonunda bir araç muayenesi","Yasal olarak talep edildiğinde alkol veya uyuşturucu için kimyasal test","Yalnızca rastgele işveren uyuşturucu testi","Bir duruşma hakkından feragat"],"explanation":"Oklahoma'nın zımni rıza yasası, bir CMV kullanan herkesi, yasal olarak talep edildiğinde alkol veya kontrollü maddeler için kimyasal (nefes, kan veya idrar) testine rıza göstermiş sayar. Reddetme, ehliyetsizlikle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 47 O.S. Section 753 (implied consent)."},"41":{"q":"Oklahoma'da, bir CDL sahibi olduğunuz sırada zımni rıza yasasının gerektirdiği şekilde alkol veya uyuşturucu testine girmeyi reddetmek ne olarak değerlendirilir?","options":["Ciddi bir trafik ihlali","Küçük bir idari kabahat","Ehliyetsizliğe tabi büyük bir suç","CDL sonucu yok, yalnızca para cezası"],"explanation":"Gerekli bir testi reddetmek, Oklahoma'da büyük bir suç olarak sınıflandırılır ve pozitif bir testle aynı ehliyetsizliği taşır. İlk reddetme, 1 yıllık CDL ehliyetsizliğiyle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"42":{"q":"Plaka (placard) gerektiren tehlikeli maddeler taşımazken bir sürücünün İLK büyük suçu (örneğin bir CMV'de DUI) için Oklahoma CDL ehliyetsizlik süresi nedir?","options":["60 gün","120 gün","1 yıl","3 yıl"],"explanation":"İlk büyük suç, Oklahoma'da 1 yıllık CDL ehliyetsizliğiyle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"43":{"q":"Bir sürücü, tehlikeli maddeler için plaka (placard) gerektiren bir CMV kullanırken ilk büyük suçu işlerse, Oklahoma ehliyetsizlik süresi neye yükselir?","options":["18 ay","2 yıl","3 yıl","Ömür boyu"],"explanation":"Plaka gerektiren tehlikeli maddeler taşırken işlenen ilk büyük suç, Oklahoma'da ehliyetsizliği 1 yıldan 3 yıla yükseltir. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"44":{"q":"Bir sürücünün İKİNCİ büyük suçu için Oklahoma CDL ehliyetsizliği nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"İkinci büyük suç, Oklahoma'da ömür boyu CDL ehliyetsizliğiyle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"45":{"q":"Kontrollü bir maddeyi üretme, dağıtma veya tedarik etmeyi içeren bir suçun işlenmesinde bir CMV kullanmak, hangi Oklahoma CDL cezasını taşır?","options":["1 yıllık ehliyetsizlik","3 yıllık ehliyetsizlik","10 yıllık ehliyetsizlik","Yeniden alma imkanı olmaksızın ömür boyu ehliyetsizlik"],"explanation":"Kontrollü madde üretimi veya dağıtımını içeren bir suçta bir CMV kullanmak, Oklahoma'da yeniden alma imkanı olmaksızın zorunlu ömür boyu ehliyetsizlik taşır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"46":{"q":"Oklahoma'da 3 yıllık bir süre içinde kaç ciddi trafik ihlali İLK ehliyetsizlik süresini tetikler ve süresi ne kadardır?","options":["1 ihlal; 30 gün","2 ihlal; 60 gün","2 ihlal; 90 gün","3 ihlal; 60 gün"],"explanation":"3 yıl içinde (bir CMV'de işlenen) ikinci bir ciddi trafik ihlali, Oklahoma'da 60 günlük bir ehliyetsizlikle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"47":{"q":"3 yıllık bir süre içinde işlenen ÜÇÜNCÜ bir ciddi trafik ihlali için Oklahoma CDL ehliyetsizliği nedir?","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde üçüncü bir ciddi trafik ihlali, Oklahoma'da 120 günlük bir ehliyetsizlikle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"48":{"q":"Aşağıdakilerden hangisi bir Oklahoma CDL sahibi için CİDDİ bir trafik ihlalidir?","options":["Park yasağı bölgesinde park etmek","Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak","Süresi dolmuş bir tescil etiketiyle araç kullanmak","Trafik yokken bir şerit değişikliğini sinyalle bildirmemek"],"explanation":"Aşırı hız yapmak (sınırın 15 mph veya daha fazla üzerinde) listelenmiş bir ciddi trafik ihlalidir. Diğerleri arasında dikkatsiz sürüş, hatalı şerit değişiklikleri, çok yakın takip ve mesajlaşma/elde tutulan telefon kullanımı bulunur. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"49":{"q":"Bir CMV kullanırken mesajlaşmak veya elde tutulan bir cep telefonu kullanmak, Oklahoma'da hangi tür ihlal olarak sınıflandırılır?","options":["Küçük bir hareketli ihlal","Ciddi bir trafik ihlali","Büyük bir suç","Bir hizmet dışı (out-of-service) emri ihlali"],"explanation":"Bir CMV kullanırken mesajlaşma ve elde tutulan cep telefonu kullanımı, 3 yılda 2-veya-3 ehliyetsizliğine doğru sayılan ciddi trafik ihlalleridir. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2, 392.80 ve 392.82."},"50":{"q":"Oklahoma'da araç kullanırken elde tutulan bir cep telefonu kullanırken yakalanan bir CMV sürücüsü, ne kadara kadar federal hukuki ceza (sürücü para cezası) ile karşılaşabilir?","options":["$250","$1,000","$2,750","$11,000"],"explanation":"Bir CMV kullanırken elde tutulan bir cep telefonu kullanmaya yönelik sürücü para cezası $2,750'ye kadar olabilir (buna izin veren işverenlere $11,000'a kadar ceza verilebilir). Kaynak: 49 CFR 392.82; Oklahoma'da uygulanan FMCSA cep telefonu kuralı."},"51":{"q":"3 yıllık bir süre içinde İLK demiryolu-karayolu hemzemin geçit ihlali için Oklahoma CDL ehliyetsizliği nedir?","options":["60 günden az olmamak","120 günden az olmamak","1 yıldan az olmamak","3 yıldan az olmamak"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, Oklahoma'da 60 günden az olmayan bir ehliyetsizlikle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"52":{"q":"3 yıllık bir süre içinde İKİNCİ demiryolu-karayolu hemzemin geçit ihlali için Oklahoma CDL ehliyetsizliği nedir?","options":["60 gün","120 günden az olmamak","1 yıldan az olmamak","2 yıldan az olmamak"],"explanation":"3 yıl içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, Oklahoma'da 120 günden az olmayan bir ehliyetsizlikle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"53":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki demiryolu-karayolu hemzemin geçit ihlali için Oklahoma CDL ehliyetsizliği nedir?","options":["120 gün","180 gün","1 yıldan az olmamak","Ömür boyu"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu-karayolu hemzemin geçit ihlali, Oklahoma'da 1 yıldan az olmayan bir ehliyetsizlikle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"54":{"q":"10 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki hizmet dışı (out-of-service) emir ihlali için Oklahoma CDL ehliyetsizliği nedir?","options":["1 yıl","2 yıl","3 yıldan az ancak 5 yıldan fazla olmamak","Ömür boyu"],"explanation":"10 yıl içinde üçüncü veya sonraki bir hizmet dışı emir ihlali, Oklahoma'da 3 yıldan az ancak 5 yıldan fazla olmayan bir ehliyetsizlikle sonuçlanır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 4."},"55":{"q":"Bir Oklahoma CDL sahibi, kullandığı bir CMV ile ilgili bir kazanın olay yerinden kaçmaktan suçlu bulunur. Bu, ehliyetsizlik amaçları açısından nasıl sınıflandırılır?","options":["Ciddi bir trafik ihlali (60 gün minimum)","Büyük bir suç (1 yıl minimum, hazmat ise 3 yıl)","Bir hizmet dışı (out-of-service) emir ihlali","Bir demiryolu geçit ihlali"],"explanation":"Bir CMV ile ilgili bir kazanın olay yerinden kaçmak (vur-kaç) büyük bir suçtur ve ilk suç için 1 yıllık ehliyetsizlik (plaka gerektiren hazmat ise 3 yıl) ve ikinci suç için ömür boyu ehliyetsizlik taşır. Kaynak: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"56":{"q":"Oklahoma'da, durması gereken bir ticari araç bir demiryolu-karayolu hemzemin geçidine yaklaştığında, sürücü nerede durmalıdır?","options":["En yakın raya 5 feet'ten yakın ve 25 feet'ten uzak olmayacak şekilde","En yakın raya 15 feet'ten yakın ve 50 feet'ten uzak olmayacak şekilde","En yakın raya 25 feet'ten yakın ve 75 feet'ten uzak olmayacak şekilde","En yakın raya 10 feet'ten yakın ve 100 feet'ten uzak olmayacak şekilde"],"explanation":"Oklahoma CDL Kılavuzu (Bölüm 2.15 ve 9.6.12), bir demiryolu geçidinde durmak zorunda olan sürücülerin en yakın raya 15 ila 50 feet mesafede durmasını ve ancak hiçbir tren gelmediğinden emin olduktan sonra ilerlemesini gerektirir. Bu, Oklahoma'da uygulandığı şekliyle 49 CFR 392.10 ile örtüşmektedir."},"57":{"q":"Oklahoma kurallarına göre aşağıdaki ticari araçlardan hangisinin her demiryolu geçidinde durması GEREKMEZ?","options":["Yolcu taşıyan bir otobüs","Tehlikeli madde ve yolcu taşımayan boş bir kapalı kasa (dry-van) römork","Tehlikeli madde plakartları sergileyen bir araç","Yüklü ya da boş, tehlikeli maddeler için kullanılan bir tanker (cargo tank)"],"explanation":"Oklahoma CDL Kılavuzu (Bölüm 9.6.12), her zaman durması gereken araçları listeler: plakartlı araçlar, klor taşıyan herhangi bir araç, tehlikeli maddeler için kullanılan tankerler (yüklü ya da boş) ve yolcu taşıyan otobüsler. Yolcu taşımayan, plakartsız bir yük kamyonu zorunlu durma listesinde yer almaz."},"58":{"q":"Oklahoma'nın Şerit Değiştir (Move Over) yasası kapsamında, aynı yönde iki veya daha fazla şeride sahip bir karayolundaki bir sürücü, yanıp sönen ışıklar sergileyen duran bir acil durum aracına veya çekiciye (wrecker) yaklaşırken önce ne yapmakla yükümlüdür?","options":["Güvenli bir şekilde yapılabiliyorsa, duran araca bitişik olmayan bir şeride geçmek","Acil durum aracı ayrılana kadar tamamen durmak","Acil durum personelini uyarmak için korna çalmak","Hızı korumak ama aynı şerit içinde orta çizgiye doğru kaymak"],"explanation":"Oklahoma'nın Şerit Değiştir (Move Over) yasası (47 O.S. Section 11-314), çok şeritli bir yoldaki bir sürücünün, güvenli olduğunda, yanıp sönen ışıklar sergileyen duran acil durum aracına, lisanslı çekiciye veya DOT/Turnpike bakım aracına bitişik olmayan bir şeride geçmesini gerektirir."},"59":{"q":"Oklahoma'nın Şerit Değiştir (Move Over) yasası kapsamında, bir sürücü duran bir acil durum aracından güvenli bir şekilde uzaklaşacak şekilde şerit değiştiremediğinde, sürücü ne yapmalıdır?","options":["Her durumda hızı tam olarak 20 mph'ye düşürmek","Tamamen durup ilerlemek için bir işaret beklemek","Belirtilen hız limitinde devam etmek ama dörtlü flaşörleri kullanmak","Hızı mevcut yol, hava ve trafik koşulları için güvenli bir hıza düşürmek"],"explanation":"Oklahoma'nın Şerit Değiştir (Move Over) yasası (47 O.S. Section 11-314), şerit değiştiremeyen bir sürücünün hızını mevcut koşullar için güvenli bir hıza düşürmesini gerektirir. Yasa, tek bir sabit sayı yerine koşullara dayalı bir ölçüt kullanır."},"60":{"q":"Oklahoma'da plakartlı bir ticari araç tek yönlü veya bölünmüş bir karayolunda durmak zorunda kalırsa, yaklaşan trafiğe doğru hangi mesafelerde uyarı cihazları yerleştirilmelidir?","options":["10 feet, 50 feet ve 150 feet","25 feet, 75 feet ve 250 feet","10 feet, 100 feet ve 200 feet","10 feet, 100 feet ve 500 feet"],"explanation":"Oklahoma CDL Kılavuzu (Bölüm 2, uyarı cihazları), tek yönlü veya bölünmüş bir karayolunda uyarı cihazlarının yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet mesafelerde yerleştirilmesini gerektirir."},"61":{"q":"Her iki yönde de trafik taşıyan (bölünmemiş) iki şeritli bir Oklahoma yolunda, duran bir CMV üç uyarı cihazını nereye yerleştirmelidir?","options":["Yalnızca aracın arkasında 10 feet, 100 feet ve 200 feet mesafelerde","Aracın 10 feet'i içinde ve aracın 100 feet arkasında ve 100 feet önünde","Banket üzerinde 50 feet, 100 feet ve 200 feet mesafelerde","Aracın 10 feet'i içinde ve aracın 200 feet arkasında ve 200 feet önünde"],"explanation":"Oklahoma CDL Kılavuzu, iki şeritli iki yönlü veya bölünmemiş bir karayolunda, aracın konumunu işaretlemek için bir cihazın aracın 10 feet'i içine, ve birer cihazın aracın 100 feet önüne ve 100 feet arkasına yerleştirileceğini belirtir."},"62":{"q":"Oklahoma'da bir yol veya banket üzerinde durduktan sonra, bir CMV sürücüsü gerekli uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["5 dakika","15 dakika","30 dakika","10 dakika"],"explanation":"Oklahoma CDL Kılavuzu (Bölüm 2), herhangi bir yol veya yolun banketi üzerinde durmak zorunda kalırsanız, acil durum uyarı cihazlarınızı on dakika içinde yerleştirmeniz gerektiğini belirtir."},"63":{"q":"Bir Oklahoma CMV'si, araç park edildiğinde veya arıza yaptığında kullanılmak üzere kaç uyarı cihazı bulundurmalıdır?","options":["İki yansıtıcı üçgen, veya 4 fünye, veya 2 sıvı yanan işaret fişeği (flare)","Dört yansıtıcı üçgen, veya 8 fünye, veya 4 sıvı yanan işaret fişeği (flare)","Bir yansıtıcı üçgen, veya 3 fünye, veya 1 sıvı yanan işaret fişeği (flare)","Üç yansıtıcı üçgen, veya 6 fünye, veya 3 sıvı yanan işaret fişeği (flare)"],"explanation":"Oklahoma CDL Kılavuzu, park edilmiş araçlar için gerekli uyarı cihazlarını üç kırmızı yansıtıcı üçgen, veya en az 6 fünye, veya 3 sıvı yanan işaret fişeği (flare) olarak listeler."},"64":{"q":"Oklahoma yasasına göre (47 O.S. Section 11-705), ters yönde seyahat eden bir sürücünün, kırmızı ışıkları yanıp sönerken çocuk indirip bindiren bir okul otobüsü için durması NE ZAMAN gerekmez?","options":["Otobüs herhangi bir boyalı orta çizginin uzak tarafında olduğunda","Trafik yoğun olduğunda ve durmak rahatsızlık verici olduğunda","Yön yönlerini bir orta iki yönlü sola dönüş şeridi ayırdığında","Yol, yön yönlerini ayıran fiziksel bir bariyer veya asfaltlanmamış refüjle bölündüğünde"],"explanation":"Oklahoma Statüsü 47 O.S. Section 11-705, karşı yöndeki trafiği yalnızca fiziksel bir bariyer veya asfaltlanmamış refüjle bölünmüş bir karayolu yolları ayırdığında durmaktan muaf tutar. Boyalı bir çizgi veya bir orta dönüş şeridi bu niteliği taşımaz, bu nedenle karşı yöndeki trafiğin bu durumlarda yine de durması gerekir."},"65":{"q":"Bölünmemiş iki şeritli bir Oklahoma karayolunda, yanıp sönen kırmızı ışıkları ve açılmış dur kolu (stop arm) bulunan duran bir okul otobüsüyle karşılaşan bir sürücü ne yapmalıdır?","options":["Seyahat yönünden bağımsız olarak, otobüs dur kolunu geri çekip kırmızı ışıkları kapatana kadar durmak","25 mph'ye yavaşlayıp dikkatlice geçmek","Yalnızca otobüsle aynı yönde seyahat ediyorsa durmak","Normal şekilde ilerlemek çünkü yalnızca aynı yöndeki trafiğin durması gerekir"],"explanation":"47 O.S. Section 11-705 kapsamında, bölünmemiş bir karayolunda her iki yöndeki trafik de yanıp sönen kırmızı ışıklar ve açılmış dur kolu sergileyen bir okul otobüsü için durmalı ve otobüs işaretleri geri çekene kadar durmaya devam etmelidir."},"66":{"q":"Çocuk indirip bindiren, duran bir Oklahoma okul otobüsünü yasa dışı şekilde geçmenin ilk mahkumiyeti için ceza nedir?","options":["Sabit $50","En az $100 ve en fazla $500","En az $250 ve en fazla $1,000","Sabit $1,500 artı zorunlu hapis"],"explanation":"Oklahoma Statüsü 47 O.S. Section 11-705, duran bir okul otobüsünü yasa dışı şekilde geçmenin ilk suçu için $100'dan az ve en fazla $500 ceza belirler; tekrar eden suçlar için artan cezalar (olası ehliyet askıya alınması dahil) uygulanır."},"67":{"q":"Oklahoma'nın şerit kullanım yasası (47 O.S. Section 11-309) kapsamında, dört veya daha fazla şeride sahip bir yolda, bir araç en sol şeritte ne zaman uygun şekilde seyahat edebilir?","options":["Yalnızca başka bir aracı geçerken, sola dönüşe hazırlanırken veya trafik/yol koşulları gerektirdiğinde","Sürücü belirtilen hız limitini koruduğu sürece her zaman","Yalnızca sağdaki şeritler tamamen boş olduğunda","Yalnızca gün doğumu ile gün batımı arasında"],"explanation":"Oklahoma Statüsü 47 O.S. Section 11-309, sol şeridi geçişe, sola dönüşe hazırlanmaya veya trafik akışı ya da yol yapılandırmasının gerektirdiği durumlara kısıtlar. Bir araç, belirtilen limitte olsa bile, sol şeritte seyahat ederek trafiğin normal akışını engelleyemez."},"68":{"q":"Statüyle yetkilendirildiği üzere, Oklahoma otoyollarının (turnpike) belirli kesimlerinde belirtilebilecek en yüksek hız limiti nedir?","options":["85 mph","75 mph","80 mph","70 mph"],"explanation":"47 O.S. Section 11-801 kapsamında, Oklahoma Turnpike Authority, otoyol sisteminin onaylı kesimlerinde 80 mph'ye kadar bir hız limiti belirleyebilir. Bazı kesimler (örneğin Turner ve Indian Nation Turnpike'ların bölümleri) 80 mph olarak işaretlenmiştir."},"69":{"q":"Oklahoma'da bir demiryolu geçidine yaklaşırken, bir otobüs veya plakartlı araç sürücüsü dörtlü flaşörleri ne zaman çalıştırmalıdır?","options":["Geçitten yaklaşık 200 feet önce","Geçitten yaklaşık 50 feet önce","Geçitten yaklaşık 500 feet önce","Yalnızca geçitte tamamen durduktan sonra"],"explanation":"Oklahoma CDL Kılavuzu (Bölüm 10.4, okul otobüsü geçiş prosedürleri), arkadan gelen trafiğin yaklaşan durma konusunda uyarılması için sürücünün geçitten yaklaşık 200 feet önce dörtlü flaşörleri çalıştırmasını yönlendirir."},"70":{"q":"Bir Oklahoma ticari aracının herhangi bir parçası bir demiryolu geçidinin üzerindeyken, hangi eylem yasaktır?","options":["Vites değiştirmek (vites geçişi)","Her iki eli direksiyonda tutmak","Trenleri izlemek ve dinlemek","Sabit bir hız korumak"],"explanation":"Oklahoma CDL Kılavuzu, sürücülere rayların üzerinden geçerken vites değiştirmemelerini söyler, çünkü kaçırılan bir vites geçişi aracı geçitte stop ettirebilir. Sürücüler geçitten önce bir vites seçmeli ve rayların üzerinden geçerken o viteste kalmalıdır."},"71":{"q":"Bir Oklahoma okul otobüsü öğrencileri indirmek için durduğunda, otobüs duraktaki öğrencilerden ne kadar uzaklıkta tamamen durdurulmalıdır?","options":["Öğrencilerden en az 3 feet uzakta","Öğrencilerden en az 25 feet uzakta","Öğrencilerden en az 10 feet uzakta","Öğrencilerden en az 50 feet uzakta"],"explanation":"Oklahoma CDL Kılavuzu (Bölüm 13 beceri testi, öğrenci indirme), sürücünün okul otobüsünü duraktaki öğrencilerden en az 10 feet uzakta tamamen durdurmasını yönlendirir; bu, öğrencileri sürücünün net görüş alanında tutar."},"72":{"q":"ODOT'tan bir gabari aşımı (oversize) izni gerekmeden önce, bir araç ve yük için Oklahoma'nın standart yasal azami genişliği nedir?","options":["8 feet 0 inches","10 feet 0 inches","8 feet 6 inches","9 feet 6 inches"],"explanation":"ODOT boyut ve ağırlık kurallarına göre, Oklahoma'nın yasal genişlik limiti 8 feet 6 inches'tır; bundan daha geniş yükler bir gabari aşımı izni gerektirir. Yasal yükseklik limiti 13 feet 6 inches'tır."},"73":{"q":"Oklahoma'da gabari aşımı (oversize) yük taşımaları genellikle hangi zaman dilimiyle kısıtlanır?","options":["Yalnızca 21:00 ile 05:00 arası","Gün ışığı saatleri, gün doğumundan 30 dakika önce ile gün batımından 30 dakika sonrasına kadar","Günde 24 saat, herhangi bir zaman kısıtlaması olmadan","Yalnızca hafta sonları ve tatillerde"],"explanation":"ODOT gabari aşımı izni kuralları, taşımayı gün ışığı saatleriyle (gün doğumundan 30 dakika önce ile gün batımından 30 dakika sonrası olarak tanımlanır) sınırlar; olumsuz hava ve azalan görüş için ek kısıtlamalar geçerlidir."},"74":{"q":"Oklahoma, hafta içi yoğun saatlerde Interstate Sistemi üzerinde gabari aşımı (oversize) yüklerini hangi ilçelerde (counties) kısıtlar?","options":["Comanche, Garfield ve Payne ilçeleri","Muskogee, Pottawatomie ve Carter ilçeleri","Oklahoma, Tulsa ve Cleveland ilçeleri","Canadian, Rogers ve Wagoner ilçeleri"],"explanation":"ODOT gabari aşımı kuralları, Oklahoma, Tulsa ve Cleveland ilçelerindeki Interstate Sistemi üzerinde, Pazartesi'den Cuma'ya kadar hafta içi yoğun saat dilimlerinde (07:00-09:00 ve 15:30-18:30, Central Time) gabari aşımı yükleri yasaklar."},"75":{"q":"Bir ticari araçta demiryolu-karayolu hemzemin geçit ihlali nedeniyle mahkumiyet, Oklahoma'da ilk suç için asgari ne kadar CDL diskalifiyesiyle sonuçlanır?","options":["En az 30 gün","En az 120 gün","En az bir yıl","En az 60 gün"],"explanation":"Oklahoma CDL Kılavuzu (Bölüm 1.3.5), bir CDL sahibinin ilk demiryolu geçit ihlali için en az 60 gün, üç yıl içinde ikincisi için en az 120 gün ve üç yıl içinde üçüncüsü için en az bir yıl diskalifiye edileceğini belirtir."},"76":{"q":"Hangi Oklahoma eyalet kurumu Ticari Sürücü Belgesi (Commercial Driver License) verir ve CDL bilgi ve beceri testlerini yürütür?","options":["Service Oklahoma","Oklahoma Ulaştırma Departmanı (ODOT)","Oklahoma Corporation Commission","Oklahoma Tax Commission"],"explanation":"Service Oklahoma (eskiden Department of Public Safety tarafından yürütülen sürücü belgelendirme görevlerini üstlenmiştir) CDL'leri verir ve Belgelendirme Ofislerinde (Licensing Offices) CDL testlerini yürütür. Kaynak: Service Oklahoma 'Commercial Driving CDL' ve 'CDL First-Time Applicants' sayfaları (oklahoma.gov)."},"77":{"q":"Bir Oklahoma CDL başvuru sahibi, gerekli görme ve yazılı bilgi testlerini nerede yapar?","options":["Bir Service Oklahoma Belgelendirme Ofisinde (Licensing Office) yüz yüze","Service Oklahoma portalı üzerinden evden çevrimiçi olarak","Herhangi bir FMCSA Training Provider Registry okulunda","Bir Oklahoma Highway Patrol birlik merkezinde"],"explanation":"Başvuru sahipleri CDL sürecine, görme ve yazılı bilgi testlerini bir Service Oklahoma Belgelendirme Ofisinde yüz yüze yaparak başlar; görme ve yazılı testler aynı randevuda birlikte uygulanır. Kaynak: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"78":{"q":"Bir Oklahoma başvuru sahibinin, CDL beceri (sürüş) testini yapmasına izin verilmeden önce bir Ticari Öğrenci Belgesini (Commercial Learner Permit, CLP) kaç gün elinde bulundurması gerekir?","options":["14 tam gün, 15. günde teste izin verilerek","30 tam gün, 31. günde teste izin verilerek","7 tam gün, 8. günde teste izin verilerek","10 tam gün, 11. günde teste izin verilerek"],"explanation":"Oklahoma, beceri testinden önce CLP'nin 14 tam gün elde tutulmasını gerektirir; başvuru sahibi testi 15. günde yapabilir. Bu, federal 14 günlük kuralla örtüşmektedir. Kaynak: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.25."},"79":{"q":"Oklahoma CDL beceri testi üç bölümlü bir sınavdır. Hangi grup bu üç bölümü doğru şekilde listeler?","options":["Sefer öncesi araç muayenesi, temel kontrol becerileri ve yol üzerindeki sürüş testi","Genel bilgi testi, hava frenleri testi ve kombine araçlar testi","Görme testi, yazılı test ve bir savunmacı sürüş kursu","Sefer öncesi muayene, tehlikeli maddeler testi ve bir geri manevra testi"],"explanation":"Oklahoma CDL beceri testi üç bölümden oluşur: sefer öncesi araç muayenesi, temel kontrol becerileri (örneğin geri manevralar) ve yol üzerindeki sürüş testi. Kaynak: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.113."},"80":{"q":"Oklahoma'nın uyguladığı federal Giriş Seviyesi Sürücü Eğitimi (Entry-Level Driver Training, ELDT) kuralları kapsamında, ilk kez başvuran bir Class A veya Class B başvuru sahibi, ne yapmadan önce onaylı bir sağlayıcıdan ELDT'yi tamamlamalıdır?","options":["Eyalet tarafından yürütülen CDL beceri testini yapmadan önce","Ticari Öğrenci Belgesini (Commercial Learner Permit) almadan önce","Genel bilgi yazılı testini yapmadan önce","Görme taramasını tamamlamadan önce"],"explanation":"İlk kez alınacak bir Class A veya B CDL için ELDT (teorik ve direksiyon başında), başvuru sahibi eyalet tarafından yürütülen beceri testini yapmadan önce bir FMCSA Training Provider Registry sağlayıcısı aracılığıyla tamamlanmalıdır. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380); Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"81":{"q":"Bir Oklahoma CDL başvuru sahibinin Giriş Seviyesi Sürücü Eğitimi sağlayıcısının, eğitimin geçerli sayılması için nerede listelenmiş olması gerekir?","options":["FMCSA'nın Training Provider Registry (TPR) kaydında","Oklahoma Ulaştırma Departmanı okul listesinde","Service Oklahoma onaylı satıcı dizininde","National Registry of Certified Medical Examiners kaydında"],"explanation":"ELDT, FMCSA'nın Training Provider Registry (TPR) kaydında listelenen bir sağlayıcıdan alınmalıdır. Kaynak: FMCSA ELDT kuralı; Service Oklahoma 'Commercial Driving CDL' (oklahoma.gov)."},"82":{"q":"Hangi CDL onayı (endorsement), ELDT teorik eğitiminin (beceri testinden değil) bilgi testinden ÖNCE tamamlanmasını gerektirir?","options":["Tehlikeli Maddeler (H) onayı","Yolcu (P) onayı","Okul Otobüsü (S) onayı","Çiftli/Üçlü (T) onayı"],"explanation":"Tehlikeli Maddeler (H) onayı için ELDT yalnızca teoriktir ve eyalet tarafından yürütülen bilgi testinden önce tamamlanmalıdır. P ve S onayları, beceri testlerinden önce ELDT gerektirir. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380)."},"83":{"q":"Bir Oklahoma CDL başvuru sahibi, sürüş türünü beyan ederken kaç öz-belgelendirme (self-certification) kategorisi arasından seçim yapmalıdır?","options":["Dört","İki","Üç","Altı"],"explanation":"Başvuru sahipleri dört kategoriden birine öz-belgelendirme yapmalıdır: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Kaynak: Service Oklahoma 'CDL First-Time Applicants' ve CDL Self-Certification SOP (oklahoma.gov)."},"84":{"q":"Hangi öz-belgelendirme (self-certification) kategorisi, belgelendirme için sürücünün dosyada bir DOT Medical Examiner's Certificate bulundurmasını GEREKTİRİR?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"Yalnızca Non-Excepted Interstate (NI) kategorisi, belgelendirme için bir DOT Medical Card gerektirir. EI, NA ve EA kategorileri, Service Oklahoma'nın dosyasında bir sağlık kartı bulundurmayı gerektirmez. Kaynak: Service Oklahoma 'CDL First-Time Applicants' / 'Commercial Driving CDL' (oklahoma.gov)."},"85":{"q":"Bir sürücünün DOT Medical Examiner's Certificate belgesi, kayıt tutma amacıyla artık Service Oklahoma'ya nasıl iletilir?","options":["FMCSA National Registry of Certified Medical Examiners kaydından elektronik olarak","Sürücünün Service Oklahoma genel merkezine bir kağıt kopya postalamasıyla","İşverenin bunu yerel Belgelendirme Ofisine fakslamasıyla","İlçe plaka acentesinin (tag agency) noter onaylı bir kopya iletmesiyle"],"explanation":"Belgelendirilmiş sağlık muayene uzmanı, belgeyi (Form MCSA-5876) elektronik olarak FMCSA National Registry'ye gönderir; bu da sağlık belgelendirme durumunu elektronik olarak Service Oklahoma'ya iletir. Kaynak: Service Oklahoma CDL Self-Certification and Medical Certificates Processing SOP (oklahoma.gov); FMCSA National Registry."},"86":{"q":"Belgelendirilmiş bir muayene uzmanının FMCSA National Registry'ye gönderdiği federal Medical Examiner's Certificate'in form numarası nedir?","options":["MCSA-5876","MCSA-5875","MCSA-5889","MCSA-5870"],"explanation":"Medical Examiner's Certificate, FMCSA Form MCSA-5876'dır; ilgili Medical Examination Report ise MCSA-5875'tir. Muayene uzmanı MCSA-5876 sonucunu National Registry'ye gönderir. Kaynak: Service Oklahoma Medical Certificates Processing SOP; FMCSA."},"87":{"q":"Bir Oklahoma Non-Excepted Interstate (NI) CDL sahibi, genellikle en az hangi sıklıkla güncel bir DOT Medical Examiner's Certificate sunmalıdır (FMCSA standartları kapsamında muayeneler arasındaki azami aralık)?","options":["Her 24 ayda bir","Her 12 ayda bir","Her 36 ayda bir","Her 60 ayda bir"],"explanation":"Standart bir sağlık muayene uzmanı belgesi en fazla 24 ay geçerlidir, bu nedenle NI sürücülerinin bu döngü içinde dosyada güncel bir belge bulundurması gerekir (belirli durumlar için daha kısa aralıklar geçerlidir). Kaynak: Service Oklahoma CDL sağlık rehberi; 49 CFR 391.45."},"88":{"q":"Service Oklahoma'ya bir CDL sahibinin sağlık belgelendirmesinin sona erdiği veya artık geçerli olmadığı bildirilirse, kurum federal kural uyarınca CDL'yi kaç gün içinde alt sınıfa düşürmelidir (downgrade)?","options":["60 gün içinde","10 gün içinde","30 gün içinde","90 gün içinde"],"explanation":"Service Oklahoma dahil eyalet sürücü belgelendirme kurumları, sürücünün artık sağlık açısından belgeli olmadığını veya sağlık belgesinin sona erdiğini ve yenilenmediğini öğrendikten sonra 60 gün içinde bir CDL'yi alt sınıfa düşürmelidir. Kaynak: Service Oklahoma alt sınıfa düşürme rehberi; 49 CFR 383.73(o)."},"89":{"q":"Oklahoma statüsü kapsamında, bir Ticari Öğrenci Belgesi (Commercial Learner Permit, CLP) başlangıçta ne kadar süreyle geçerlidir?","options":["180 gün","90 gün","60 gün","1 yıl"],"explanation":"Oklahoma, CLP'yi 180 günlük bir süre için verir; ek bir 180 gün için bir kez yenilenebilir. Kaynak: 47 O.S. Section 6-101; Service Oklahoma CLP rehberi."},"90":{"q":"Bir Oklahoma CLP bir kez yenilenebilir. Bu tek yenileme ne kadar süreyle geçerlidir?","options":["Ek 180 gün","Ek 30 gün","Ek 1 yıl","Ek 90 gün"],"explanation":"CLP 180 gün geçerlidir ve ek bir 180 gün için bir kez yenilenebilir, böylece toplamda bir yıla kadar süre tanır. Kaynak: 47 O.S. Section 6-101; Service Oklahoma CLP rehberi."},"91":{"q":"INTRASTATE (yalnızca Oklahoma içi) ticari sürüş için bir CDL almanın asgari yaşı nedir?","options":["18 yaşında","21 yaşında","16 yaşında","19 yaşında"],"explanation":"Bir başvuru sahibinin bir CMV'yi intrastate (Oklahoma içinde) kullanması için en az 18, interstate sürmek için en az 21 yaşında olması gerekir. Kaynak: Service Oklahoma CDL rehberi; 47 O.S. Section 6-101."},"92":{"q":"Henüz 21 yaşına girmemiş 19 yaşındaki bir Oklahoma CDL sahibi genellikle hangi şekilde sınırlandırılır?","options":["Yalnızca intrastate (Oklahoma içi) ticari sürüşle","Yalnızca Class C ticari araçları kullanmakla","Yalnızca gündüz ticari sürüşle","Yalnızca belgeli bir CDL sahibi yanında bulunmasıyla sürmekle"],"explanation":"18 ila 20 yaşındaki sürücüler bir CDL bulundurabilir, ancak intrastate (Oklahoma içi) ticari faaliyetle sınırlıdır; interstate faaliyet 21 yaş gerektirir. Kaynak: Service Oklahoma CDL rehberi; 49 CFR 383.3 / 391.11."},"93":{"q":"İlk kez başvuran bir Oklahoma CDL başvuru sahibinin Service Oklahoma Belgelendirme Ofisinde sunması gerekenler arasında hangi belge YER ALMAZ?","options":["İşverenin yol testine yetki veren bir mektubu","Kimlik ve yasal varlık (lawful presence) kanıtı","Oklahoma ikamet kanıtı (bir adres kanıtı)","Geçerli bir Oklahoma Class D sürücü belgesi"],"explanation":"Gerekli belgeler arasında kimlik ve yasal varlık kanıtı, ikamet/adres kanıtı, geçerli bir Oklahoma Class D belgesi ve bir Social Security numarası bulunur; bir işveren yetki mektubu gerekli değildir. Kaynak: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"94":{"q":"Oklahoma CDL yenilemesiyle ilgili olarak, süreç hakkında hangi ifade doğrudur?","options":["Uygun CDL sahipleri çevrimiçi yenileyebilir, ancak Tehlikeli Maddeler (H) sahipleri yüz yüze yenilemeli ve HazMat yazılı testini tekrar girmeli ile birlikte TSA arka plan kontrolünü yaptırmalıdır","HazMat dahil tüm CDL yenilemeleri tamamen çevrimiçi olarak yapılabilir","CDL'ler yenilenemez ve her döngüde sıfırdan yeniden test edilmelidir","Yenileme, her seferinde tam üç bölümlü beceri testinin yeniden girilmesini gerektirir"],"explanation":"Service Oklahoma, uygun sahipler için çevrimiçi CDL yenilemesi sunar, ancak Tehlikeli Maddeler onayı sahipleri yüz yüze yenilemeli, HazMat bilgi testini tekrar girmeli ve her yenilemede TSA arka plan kontrolünü tamamlamalıdır. (Not: kesin ücretler ve seçilen belge süresi, örneğin 4 yıl ve 8 yıl seçenekleri, değişebilir.) Kaynak: Service Oklahoma 'CDL Renewal/Replacement Online' (oklahoma.gov)."}},"es":{"0":{"q":"En las carreteras de Oklahoma, ¿cuál es el ancho exterior total máximo de un vehículo, con o sin carga, antes de que se requiera un permiso de sobreancho?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"Oklahoma limita el ancho exterior total a 102 inches (8.5 ft); un ancho mayor requiere un permiso de sobreancho. Fuente: 47 O.S. §14-103."},"1":{"q":"¿Cuál es la altura máxima legal para un vehículo o carga en una autopista de peaje, interestatal, carretera federal (U.S.) o estatal de Oklahoma sin un permiso especial?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"Oklahoma permite hasta 14 feet de altura en autopistas de peaje, interestatales, carreteras federales (U.S.) y estatales sin un permiso. Fuente: 47 O.S. §14-103."},"2":{"q":"¿Cuál es la altura máxima para un vehículo o carga en un camino de CONDADO de Oklahoma sin un permiso especial?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"En los caminos de condado el límite de altura es de 13.5 feet, menor que el límite de 14 feet permitido en autopistas de peaje, interestatales, carreteras federales (U.S.) y estatales. Fuente: 47 O.S. §14-103."},"3":{"q":"En Oklahoma, ¿cuál es el peso máximo permitido en cualquier eje simple sin un permiso de sobrepeso?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"El límite de peso por eje simple de Oklahoma es de 20,000 pounds. Fuente: 47 O.S. §14-109(A)."},"4":{"q":"¿Cuál es el peso máximo que Oklahoma permite en un conjunto de ejes en tándem sin un permiso especial?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"La carga máxima en cualquier conjunto de ejes en tándem en Oklahoma es de 34,000 pounds. Fuente: 47 O.S. §14-109(B)."},"5":{"q":"¿Cuál es el peso bruto vehicular máximo general en las carreteras de Oklahoma según la tabla de pesos sin un permiso especial?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"La tabla de pesos de Oklahoma limita el peso bruto legal a 80,000 pounds, en concordancia con el límite federal. Fuente: 47 O.S. §14-109(A)."},"6":{"q":"Los pesos brutos y por eje permitidos en Oklahoma se determinan mediante una fórmula basada en la separación entre ejes. ¿Cómo se le llama comúnmente a esta fórmula?","options":["Federal Bridge Formula","Gross Combination Rule","Tare Weight Formula","Axle Spread Ratio"],"explanation":"Oklahoma utiliza la Federal Bridge Formula/tabla de pesos (23 U.S.C. §127), midiendo la distancia entre los ejes extremos hasta el pie más cercano. Fuente: 47 O.S. §14-109; ODPS Troop S."},"7":{"q":"¿Cuál es la longitud total máxima de un camión SIMPLE (no una combinación), incluyendo los parachoques, en los caminos de Oklahoma?","options":["40 feet","45 feet","53 feet","70 feet"],"explanation":"Un camión simple no puede exceder los 45 feet de longitud total, incluyendo los parachoques delantero y trasero, en Oklahoma. Fuente: 47 O.S. §14-103."},"8":{"q":"En la National Network, ¿cuál es la longitud máxima del semirremolque en una combinación de camión-tractor/semirremolque en Oklahoma (sin un permiso)?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"Un semirremolque en una combinación de camión-tractor/semirremolque puede medir hasta 53 feet en la National Network; una longitud mayor (hasta 59'6\") requiere un permiso. Fuente: 47 O.S. §14-103."},"9":{"q":"¿Cuál es la longitud total máxima para combinaciones de vehículos DISTINTAS a un camión-tractor/semirremolque en todos los caminos y carreteras de Oklahoma?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"Otras combinaciones de vehículos no pueden exceder los 70 feet en total, incluyendo los parachoques, en todos los caminos y carreteras de Oklahoma. Fuente: 47 O.S. §14-103."},"10":{"q":"¿Qué división de agencia de Oklahoma emite los permisos de exceso de tamaño/sobrepeso para circular por el sistema de carreteras estatales?","options":["La Oklahoma Tax Commission","La ODOT Size and Weight Permit Division","La Corporation Commission","La oficina del alguacil del condado"],"explanation":"La ODOT Size and Weight Permit Division emite los permisos de exceso de tamaño/sobrepeso (se solicitan en línea en swpermitsok.com). Fuente: ODOT; OAC 730:50-5."},"11":{"q":"Una combinación de camión y semirremolque puede operar bajo un permiso ANUAL especial de sobreancho en Oklahoma hasta qué ancho máximo?","options":["108 inches","114 inches","120 inches","144 inches"],"explanation":"Las combinaciones que exceden 102 pero no exceden 120 inches de ancho pueden operar bajo un permiso anual especial de sobreancho. Fuente: OAC 730:50-5; 47 O.S. §14-103G."},"12":{"q":"Según las reglas de Oklahoma, una carga con permiso más ancha de 12 feet pero no más de 14 feet debe tener qué disposición de escolta en una carretera de dos carriles?","options":["No se requiere escolta","Un vehículo escolta delantero","Un vehículo escolta trasero","Escoltas tanto delantera como trasera"],"explanation":"Las cargas de más de 12 ft pero no más de 14 ft de ancho necesitan una escolta delantera en carreteras de dos carriles/super dos carriles (escolta trasera en carreteras de varios carriles). Fuente: OAC 730:50-5-18(b)."},"13":{"q":"¿A qué ALTURA total una carga con permiso de Oklahoma requiere DOS vehículos escolta (uno delante, uno detrás) y aviso previo a las empresas de servicios públicos y ferrocarriles?","options":["14 feet o más","14 feet 6 inches o más","15 feet o más","15 feet 9 inches o más"],"explanation":"Las cargas con una altura total de 15 feet 9 inches o más requieren dos escoltas y contacto previo con las empresas de servicios públicos/ferrocarriles afectados. Fuente: OAC 730:50-5-18(b)."},"14":{"q":"¿Una combinación de camión-tractor/semirremolque de qué longitud total exige una escolta delantera obligatoria en las carreteras de dos carriles de Oklahoma?","options":["Más de 70 feet","Más de 75 feet","Más de 80 feet","Más de 100 feet"],"explanation":"Una combinación de camión-tractor/semirremolque de más de 80 feet en total requiere una escolta delantera en las carreteras de dos carriles. Fuente: OAC 730:50-5-18(b)(4)."},"15":{"q":"Según la variación de peso para productos agrícolas de Oklahoma (según ODPS Troop S), ¿qué tolerancias aplican y dónde está prohibido circular?","options":["5% sobre el peso bruto y 8% sobre los límites por eje; no en las carreteras interestatales","10% sobre el peso bruto y 10% sobre el eje; no en autopistas de peaje","8% sobre el peso bruto y 5% sobre el eje; no en caminos de condado","5% sobre el peso bruto y 5% sobre el eje; se permite la interestatal"],"explanation":"Los vehículos que transportan productos agrícolas con registro máximo pueden circular hasta un 5% por encima del peso bruto y un 8% por encima de los límites por eje, pero no en el sistema interestatal. Fuente: ODPS Troop S; 47 O.S. §14-109."},"16":{"q":"Con un permiso de variación de peso agrícola que permite aproximadamente un 8% por encima del límite por eje, la cifra de eje simple de 20,000 pounds pasa a ser aproximadamente cuánto?","options":["20,800 pounds","21,600 pounds","22,400 pounds","24,000 pounds"],"explanation":"Con la variación (8% sobre el eje), el límite de eje simple de 20,000 lb pasa a ser 21,600 lbs; exceder cualquier categoría anula el permiso para ese viaje. Fuente: tabla de ejes de ODPS Troop S."},"17":{"q":"El Annual Envelope Vehicle Permit de la ODOT de Oklahoma autoriza un vehículo hasta qué dimensiones máximas en el sistema de carreteras estatales?","options":["10 ft de ancho, 13.5 ft de alto, 90 ft de largo","12 ft de ancho, 14 ft de alto, 110 ft de largo","14 ft de ancho, 15 ft de alto, 120 ft de largo","12 ft de ancho, 16 ft de alto, 100 ft de largo"],"explanation":"El Annual Envelope Vehicle Permit cubre vehículos de hasta 12 ft de ancho, 14 ft de alto y 110 ft de largo (tarifa de $4,000), válido únicamente en el sistema de carreteras estatales. Fuente: OAC 730:50-5-13."},"18":{"q":"Los transportistas de productos forestales en bruto en su estado natural en Oklahoma pueden obtener un permiso agrícola anual de $25, pero ¿con qué limitación de ruta?","options":["No se permite circular por el sistema interestatal","No se permite circular por ninguna autopista de peaje","No se permite circular por caminos de condado","No se permite circular únicamente de noche"],"explanation":"El transporte de productos forestales en bruto bajo el permiso agrícola anual de $25 no está permitido en el National System of Interstate and Defense Highways. Fuente: OAC 730:50-5-22; 47 O.S. §14-118(e)."},"19":{"q":"En Oklahoma, ¿qué clase de CDL se requiere para operar cualquier combinación de vehículos con una calificación de peso bruto combinado (GCWR) de 26,001 libras o más cuando el vehículo remolcado tiene un GVWR de más de 10,000 libras?","options":["Class A","Class B","Class C","Class D"],"explanation":"Oklahoma adopta la clasificación federal: una CDL Class A cubre cualquier combinación de vehículos con un GCWR de 26,001+ lbs en la que la(s) unidad(es) remolcada(s) exceda(n) los 10,000 lbs de GVWR. Fuente: Oklahoma Statutes Title 47 Sec. 6-101 y el Oklahoma CDL Manual (Service Oklahoma)."},"20":{"q":"Un conductor de Oklahoma opera un camión rígido simple con un GVWR de 30,000 libras que no remolca ningún remolque. ¿Qué clase de CDL requiere esto?","options":["Class A","Class B","Class C","No se requiere CDL"],"explanation":"Una CDL Class B cubre cualquier vehículo simple con un GVWR de 26,001+ lbs (o ese mismo vehículo remolcando una unidad de no más de 10,000 lbs de GVWR). Un camión rígido de 30,000 lb cae bajo la Class B. Fuente: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"21":{"q":"Según las reglas de Oklahoma, un vehículo que no cumple con los umbrales de peso de la Class A o Class B aún requiere una CDL Class C si hace qué?","options":["Tiene un GVWR de más de 16,000 libras","Está diseñado para transportar 16 o más personas incluido el conductor, o transporta materiales peligrosos que requieren letreros (placards)","Remolca cualquier remolque con una calificación de más de 5,000 libras","Se opera por contrato cruzando límites de condado"],"explanation":"Una CDL Class C aplica a un vehículo que no cumple con la Class A o B que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que transporta materiales peligrosos que requieren letreros (placards). Fuente: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"22":{"q":"¿Qué código de endoso debe agregarse a una CDL de Oklahoma para transportar materiales designados como peligrosos y que requieren letreros (placards)?","options":["N","T","H","P"],"explanation":"El endoso H (Hazardous Materials) se requiere para transportar materiales peligrosos que requieren letreros (placards). Fuente: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"23":{"q":"¿Cuál es el umbral de capacidad federal/de Oklahoma que define un 'vehículo cisterna' que requiere el endoso N (Tanker)?","options":["Una cisterna con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de 1,000 galones o más","Una cisterna con una capacidad nominal individual de más de 100 galones","Cualquier cisterna que transporte 500 galones o más en total","Una cisterna con una capacidad agregada de 2,000 galones o más"],"explanation":"El endoso N se requiere para vehículos que transportan líquidos o gases en una cisterna con una capacidad nominal individual de más de 119 galones Y una capacidad nominal agregada de 1,000 galones o más. Fuente: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.5."},"24":{"q":"¿Qué endoso de CDL de Oklahoma se requiere para tirar de remolques dobles o triples, y qué clase de CDL debe tener ya el conductor?","options":["Endoso T, con una CDL Class A","Endoso T, con una CDL Class B","Endoso N, con una CDL Class A","Endoso P, con una CDL Class C"],"explanation":"El endoso T (Doubles/Triples) permite tirar de múltiples remolques y lo agregan los conductores Class A, quienes deben demostrar el conocimiento adicional requerido. Fuente: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"25":{"q":"Un conductor de Oklahoma quiere conducir un vehículo diseñado para transportar 16 o más personas incluido el conductor. ¿Qué endoso se requiere?","options":["S (School Bus)","P (Passenger)","N (Tanker)","T (Doubles/Triples)"],"explanation":"El endoso P (Passenger) se requiere para operar un vehículo diseñado para transportar 16 o más personas incluido el conductor; requiere aprobar un examen de conocimientos y un examen de destrezas en un vehículo representativo. Fuente: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"26":{"q":"Antes de que un conductor de Oklahoma pueda obtener el endoso de School Bus (S), ¿qué otro endoso es un requisito previo?","options":["El endoso H (HazMat)","El endoso N (Tanker)","El endoso P (Passenger)","El endoso T (Doubles/Triples)"],"explanation":"El endoso S (School Bus) requiere que el conductor tenga primero el endoso P (Passenger), y luego apruebe un examen de conocimientos de autobús escolar y un examen de destrezas en un autobús escolar. Fuente: Oklahoma CDL Manual / Endorsements (Service Oklahoma); 49 CFR 383.93."},"27":{"q":"¿Cuál es la edad mínima para obtener una CDL de Oklahoma restringida únicamente a operación intraestatal (dentro de Oklahoma)?","options":["16","18","21","25"],"explanation":"Un conductor debe tener al menos 18 años para tener una CDL de Oklahoma solo intraestatal; los conductores menores de 21 reciben una restricción 'K' de solo intraestatal. Fuente: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"28":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo con CDL en el comercio interestatal (cruzando líneas estatales) desde Oklahoma?","options":["18","19","21","23"],"explanation":"La operación interestatal con CDL requiere una edad mínima de 21 años; los conductores de 18 a 20 están limitados a la operación intraestatal dentro de Oklahoma. Fuente: Oklahoma CDL Manual (Service Oklahoma); 49 CFR 391.11."},"29":{"q":"Después de aprobar los exámenes de conocimientos requeridos en Oklahoma, ¿cuánto tiempo debe tener un solicitante un Commercial Learner Permit (CLP) antes de presentar el examen de destrezas (manejo) de la CDL?","options":["7 días completos","10 días completos","14 días completos","30 días completos"],"explanation":"Las reglas federales y de Oklahoma requieren tener el CLP durante 14 días completos antes del examen de destrezas; el examen puede presentarse en el día 15. Fuente: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.25."},"30":{"q":"¿Por cuánto tiempo es válido un Commercial Learner Permit (CLP) de Oklahoma, y cómo se puede extender?","options":["90 días, no renovable","180 días, renovable una vez por 180 días adicionales","1 año, renovable anualmente","60 días, renovable hasta tres veces"],"explanation":"Un CLP de Oklahoma se emite por 180 días y puede renovarse una vez por 180 días adicionales. Fuente: Oklahoma CDL Manual / Service Oklahoma; 49 CFR 383.25."},"31":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de CDL por primera vez en Oklahoma en una oficina de licencias de Service Oklahoma?","options":["Solo una licencia Class D válida y un certificado de nacimiento","Comprobante de identidad, comprobante de presencia legal, número de Social Security y comprobante de residencia en Oklahoma","Solo una tarjeta de Social Security y una carta del empleador","Un pasaporte y comprobante de seguro del vehículo"],"explanation":"Service Oklahoma requiere comprobante de identidad, presencia legal, el SSN del solicitante y residencia en Oklahoma (un documento de residencia como estándar, dos para REAL ID), además de una licencia Class D válida. Fuente: Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"32":{"q":"El Entry-Level Driver Training (ELDT) para un solicitante de CDL por primera vez en Oklahoma debe completarse a través de qué sistema oficial?","options":["El portal del Oklahoma Department of Education","El FMCSA Training Provider Registry","El TSA Hazmat Threat Assessment Program","El registro de la Oklahoma Tax Commission"],"explanation":"El ELDT debe ser impartido por una escuela incluida en el FMCSA Training Provider Registry, que reporta la finalización de forma electrónica. Fuente: FMCSA ELDT rule (49 CFR Part 380); Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"33":{"q":"¿Cuál de estos requiere ELDT (Entry-Level Driver Training) antes del examen de destrezas/conocimientos según las reglas de la FMCSA aplicadas en Oklahoma?","options":["Obtener el endoso de Tanker (N)","Obtener el endoso de Doubles/Triples (T)","Obtener el endoso de Passenger (P) o School Bus (S) por primera vez","Renovar una CDL Class A existente"],"explanation":"El ELDT se requiere para una CDL Class A o B por primera vez, una actualización de B a A, y los endosos H, P o S por primera vez. Los endosos N y T NO están regulados por el ELDT. Fuente: FMCSA ELDT rule (49 CFR Part 380); Service Oklahoma."},"34":{"q":"Para el endoso de Hazardous Materials (H), ¿en qué consiste el requisito de ELDT aplicado en Oklahoma?","options":["Instrucción teórica únicamente","Instrucción detrás del volante únicamente","Instrucción tanto teórica como detrás del volante","Ninguna capacitación en absoluto"],"explanation":"El ELDT para el endoso H es solo teórico; únicamente las CDL Class A/B y los endosos P y S requieren capacitación tanto teórica como detrás del volante. Fuente: FMCSA ELDT rule (49 CFR Part 380)."},"35":{"q":"Además de aprobar el examen de conocimientos de HazMat, ¿qué necesita un conductor de Oklahoma para obtener o mantener el endoso H?","options":["Una evaluación de amenaza de seguridad de la TSA (verificación de antecedentes) que sea válida por 5 años","Un segundo examen de destrezas en un vehículo cisterna","Una carta notariada de patrocinio del empleador","Un permiso estatal de HazMat aparte renovado anualmente"],"explanation":"El endoso H requiere una TSA Hazmat Threat Assessment (verificación de antecedentes/toma de huellas dactilares); la autorización es válida por 5 años y debe renovarse junto con el endoso. Fuente: TSA HTAP; 49 CFR 1572; Service Oklahoma CDL."},"36":{"q":"¿Qué código de endoso se emite en una CDL de Oklahoma para un conductor autorizado a operar un vehículo cisterna que transporta materiales peligrosos que requieren letreros (placards) (HazMat y Tank combinados)?","options":["HN","X","T","Z"],"explanation":"Oklahoma emite el código de endoso combinado 'X' para los conductores que tienen autoridad tanto de Tank (N) como de Hazardous Materials (H). Fuente: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.153."},"37":{"q":"¿Entre cuántas categorías de autocertificación médica elige un solicitante de CDL de Oklahoma, y cuál requiere un certificado de examinador médico del DOT?","options":["Dos categorías; la categoría Excepted Interstate requiere la tarjeta médica","Cuatro categorías; la categoría Non-Excepted Interstate (NI) requiere la tarjeta médica","Tres categorías; la categoría Non-Excepted Intrastate requiere la tarjeta médica","Cuatro categorías; la categoría Excepted Intrastate (EA) requiere la tarjeta médica"],"explanation":"Hay cuatro categorías de autocertificación (NI, EI, NA, EA). Solo los conductores Non-Excepted Interstate (NI) deben proporcionar y mantener un certificado válido de examinador médico del DOT. Fuente: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.71."},"38":{"q":"¿Qué código de restricción lleva una CDL o CLP de Oklahoma cuando el titular no puede operar vehículos comerciales fuera del estado de Oklahoma?","options":["E","L","K","Z"],"explanation":"La restricción 'K' significa solo intraestatal: el conductor no puede salir de Oklahoma en un vehículo con CDL (se aplica comúnmente a conductores menores de 21 años). 'E' = sin transmisión manual, 'L' = sin frenos de aire, 'Z' = sin frenos de aire completos. Fuente: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"39":{"q":"Al operar un vehículo motorizado comercial (CMV) en Oklahoma, ¿con qué concentración de alcohol en la sangre (BAC) se considera que un conductor está legalmente incapacitado y comete una infracción mayor?","options":["0.02 o más","0.04 o más","0.08 o más","0.10 o más"],"explanation":"Oklahoma establece el límite de BAC para CMV en 0.04 o más, la mitad del límite de 0.08 para conductores no comerciales. Operar un CMV con 0.04 o más es una infracción mayor. Fuente: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 según lo adoptado por Oklahoma."},"40":{"q":"Según la ley de consentimiento implícito de Oklahoma, al conducir un vehículo motorizado comercial se considera que un titular de CDL ha aceptado qué?","options":["Una inspección del vehículo en cualquier estación de pesaje","Pruebas químicas para detectar alcohol o drogas cuando se solicite legalmente","Únicamente pruebas de drogas aleatorias del empleador","Una renuncia al derecho a una audiencia"],"explanation":"La ley de consentimiento implícito de Oklahoma considera que cualquier persona que opera un CMV ha consentido a pruebas químicas (de aliento, sangre u orina) para detectar alcohol o sustancias controladas cuando se solicite legalmente. La negativa resulta en descalificación. Fuente: Oklahoma CDL Driver Manual, Section 1; 47 O.S. Section 753 (implied consent)."},"41":{"q":"En Oklahoma, negarse a someterse a las pruebas de alcohol o drogas requeridas por la ley de consentimiento implícito mientras se tiene una CDL se trata como qué?","options":["Una infracción de tránsito grave","Una infracción administrativa menor","Una infracción mayor sujeta a descalificación","Sin consecuencia para la CDL, solo una multa"],"explanation":"Negarse a una prueba requerida se clasifica como una infracción mayor en Oklahoma, conllevando la misma descalificación que una prueba positiva. Una primera negativa resulta en una descalificación de la CDL de 1 año. Fuente: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"42":{"q":"¿Cuál es el período de descalificación de la CDL de Oklahoma para la PRIMERA infracción mayor de un conductor (como DUI en un CMV) cuando NO se transportan materiales peligrosos con letreros (placards)?","options":["60 días","120 días","1 año","3 años"],"explanation":"Una primera infracción mayor resulta en una descalificación de la CDL de 1 año en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"43":{"q":"Si un conductor comete una primera infracción mayor mientras opera un CMV que debe llevar letreros (placards) por materiales peligrosos, ¿a cuánto aumenta el período de descalificación de Oklahoma?","options":["18 meses","2 años","3 años","De por vida"],"explanation":"Una primera infracción mayor cometida mientras se transportan materiales peligrosos con letreros (placards) eleva la descalificación de 1 año a 3 años en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"44":{"q":"¿Cuál es la descalificación de la CDL de Oklahoma para la SEGUNDA infracción mayor de un conductor?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda infracción mayor resulta en una descalificación de la CDL de por vida en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"45":{"q":"Usar un CMV en la comisión de un delito grave que implique la fabricación, distribución o dispensación de una sustancia controlada conlleva qué penalización de CDL en Oklahoma?","options":["Descalificación de 1 año","Descalificación de 3 años","Descalificación de 10 años","Descalificación de por vida sin reincorporación"],"explanation":"Usar un CMV en un delito grave que implique la fabricación o distribución de sustancias controladas conlleva una descalificación obligatoria de por vida sin posibilidad de reincorporación en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"46":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años activan el PRIMER período de descalificación en Oklahoma, y cuánto dura?","options":["1 infracción; 30 días","2 infracciones; 60 días","2 infracciones; 90 días","3 infracciones; 60 días"],"explanation":"Una segunda infracción de tránsito grave dentro de 3 años (cometida en un CMV) resulta en una descalificación de 60 días en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"47":{"q":"¿Cuál es la descalificación de la CDL de Oklahoma para una TERCERA infracción de tránsito grave cometida dentro de un período de 3 años?","options":["60 días","90 días","120 días","1 año"],"explanation":"Una tercera infracción de tránsito grave dentro de 3 años resulta en una descalificación de 120 días en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"48":{"q":"¿Cuál de las siguientes es una infracción de tránsito GRAVE para un titular de CDL de Oklahoma?","options":["Estacionarse en una zona de no estacionamiento","Exceder la velocidad en 15 mph o más sobre el límite señalado","Conducir con una calcomanía de registro vencida","No señalizar un cambio de carril sin tránsito presente"],"explanation":"El exceso de velocidad (15 mph o más por encima del límite) es una infracción de tránsito grave listada. Otras incluyen conducción imprudente, cambios de carril indebidos, seguir demasiado de cerca y enviar mensajes de texto/uso de teléfono de mano. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"49":{"q":"Enviar mensajes de texto o usar un teléfono móvil de mano mientras se conduce un CMV se clasifica en Oklahoma como qué tipo de infracción?","options":["Una infracción de movimiento menor","Una infracción de tránsito grave","Una infracción mayor","Una infracción de orden de fuera de servicio"],"explanation":"Enviar mensajes de texto y usar un teléfono móvil de mano mientras se conduce un CMV son infracciones de tránsito graves que cuentan para la descalificación de 2 o 3 en 3 años. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2, 392.80 y 392.82."},"50":{"q":"Un conductor de CMV en Oklahoma que sea sorprendido usando un teléfono móvil de mano mientras conduce puede enfrentar una penalización civil federal (multa al conductor) de hasta qué monto?","options":["$250","$1,000","$2,750","$11,000"],"explanation":"La multa al conductor por usar un teléfono móvil de mano mientras conduce un CMV puede ser de hasta $2,750 (los empleadores que lo permiten pueden ser multados hasta con $11,000). Fuente: 49 CFR 392.82; regla de teléfonos móviles de la FMCSA aplicada en Oklahoma."},"51":{"q":"¿Cuál es la descalificación de la CDL de Oklahoma para una PRIMERA infracción de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["No menos de 60 días","No menos de 120 días","No menos de 1 año","No menos de 3 años"],"explanation":"Una primera infracción de cruce a nivel de ferrocarril y carretera resulta en una descalificación de no menos de 60 días en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"52":{"q":"¿Cuál es la descalificación de la CDL de Oklahoma para una SEGUNDA infracción de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["60 días","No menos de 120 días","No menos de 1 año","No menos de 2 años"],"explanation":"Una segunda infracción de cruce a nivel de ferrocarril y carretera dentro de 3 años resulta en una descalificación de no menos de 120 días en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"53":{"q":"¿Cuál es la descalificación de la CDL de Oklahoma para una TERCERA o subsiguiente infracción de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["120 días","180 días","No menos de 1 año","De por vida"],"explanation":"Una tercera o subsiguiente infracción de cruce a nivel de ferrocarril y carretera dentro de 3 años resulta en una descalificación de no menos de 1 año en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"54":{"q":"¿Cuál es la descalificación de la CDL de Oklahoma para una TERCERA o subsiguiente violación de una orden de fuera de servicio dentro de un período de 10 años?","options":["1 año","2 años","No menos de 3 años pero no más de 5 años","De por vida"],"explanation":"Una tercera o subsiguiente violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de no menos de 3 años pero no más de 5 años en Oklahoma. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 4."},"55":{"q":"Un titular de CDL de Oklahoma es condenado por abandonar el lugar de un accidente que involucra un CMV que conducía. ¿Cómo se clasifica esto para fines de descalificación?","options":["Una infracción de tránsito grave (mínimo de 60 días)","Una infracción mayor (mínimo de 1 año, 3 años si hay materiales peligrosos)","Una violación de orden de fuera de servicio","Una infracción de cruce de ferrocarril"],"explanation":"Abandonar el lugar de un accidente (darse a la fuga) que involucra un CMV es una infracción mayor, conllevando una descalificación de 1 año (3 años si hay materiales peligrosos con letreros/placards) para una primera infracción y de por vida para una segunda. Fuente: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"56":{"q":"En Oklahoma, cuando un vehículo comercial que está obligado a detenerse se aproxima a un cruce a nivel entre vía férrea y carretera, ¿dónde debe detenerse el conductor?","options":["A no menos de 5 feet y a no más de 25 feet del riel más cercano","A no menos de 15 feet y a no más de 50 feet del riel más cercano","A no menos de 25 feet y a no más de 75 feet del riel más cercano","A no menos de 10 feet y a no más de 100 feet del riel más cercano"],"explanation":"El Manual de CDL de Oklahoma (Secciones 2.15 y 9.6.12) exige que los conductores que deben detenerse en un cruce ferroviario lo hagan a una distancia de 15 a 50 feet del riel más cercano, y luego avancen solo cuando estén seguros de que no viene ningún tren. Esto refleja lo dispuesto en 49 CFR 392.10 tal como se aplica en Oklahoma."},"57":{"q":"¿Cuál de los siguientes vehículos comerciales NO está obligado a detenerse en cada cruce ferroviario según las normas de Oklahoma?","options":["Un autobús que transporta pasajeros","Un remolque de caja seca vacío que no lleva materiales peligrosos ni pasajeros","Un vehículo que exhibe carteles (placards) de materiales peligrosos","Un tanque de carga utilizado para materiales peligrosos, ya sea cargado o vacío"],"explanation":"El Manual de CDL de Oklahoma (Sección 9.6.12) enumera los vehículos que siempre deben detenerse: vehículos con carteles (placards), cualquier vehículo que transporte cloro, tanques de carga utilizados para materiales peligrosos (cargados o vacíos) y autobuses con pasajeros. Una caja de carga sin carteles que no lleva pasajeros no está en la lista de parada obligatoria."},"58":{"q":"Según la ley Move Over (Cámbiate de carril) de Oklahoma, ¿qué debe hacer primero un conductor en una carretera con dos o más carriles en la misma dirección cuando se aproxima a un vehículo de emergencia o una grúa detenidos que exhiben luces intermitentes?","options":["Cambiarse a un carril que no esté adyacente al vehículo detenido, si puede hacerse de manera segura","Detenerse por completo hasta que el vehículo de emergencia se retire","Tocar la bocina para advertir al personal de emergencia","Mantener la velocidad pero moverse dentro del mismo carril hacia la línea central"],"explanation":"La ley Move Over de Oklahoma (47 O.S. Section 11-314) exige que un conductor en una vía de varios carriles, cuando sea seguro, se cambie a un carril que no esté adyacente al vehículo de emergencia detenido, la grúa autorizada o el vehículo de mantenimiento de DOT/Turnpike que exhiba luces intermitentes."},"59":{"q":"Según la ley Move Over de Oklahoma, cuando un conductor no puede cambiarse de carril de manera segura para alejarse de un vehículo de emergencia detenido, ¿qué debe hacer el conductor?","options":["Reducir la velocidad a exactamente 20 mph en todos los casos","Detenerse por completo y esperar una señal para continuar","Continuar al límite de velocidad indicado pero usar las cuatro luces intermitentes","Reducir la velocidad a una velocidad segura para las condiciones existentes de la vía, el clima y el tránsito"],"explanation":"La ley Move Over de Oklahoma (47 O.S. Section 11-314) exige que un conductor que no puede cambiarse de carril reduzca la velocidad a una velocidad segura para las condiciones existentes. El estatuto utiliza un criterio basado en las condiciones en lugar de una sola cifra fija."},"60":{"q":"Si un vehículo comercial con carteles (placards) debe detenerse en una carretera de un solo sentido o dividida en Oklahoma, ¿a qué distancias en dirección al tránsito que se aproxima deben colocarse los dispositivos de advertencia?","options":["10 feet, 50 feet y 150 feet","25 feet, 75 feet y 250 feet","10 feet, 100 feet y 200 feet","10 feet, 100 feet y 500 feet"],"explanation":"El Manual de CDL de Oklahoma (Sección 2, dispositivos de advertencia) exige que en una carretera de un solo sentido o dividida, los dispositivos de advertencia se coloquen a 10 feet, 100 feet y 200 feet en dirección al tránsito que se aproxima."},"61":{"q":"En una carretera de Oklahoma de dos carriles que lleva tránsito en ambas direcciones (sin dividir), ¿dónde debe colocar un CMV detenido sus tres dispositivos de advertencia?","options":["A 10 feet, 100 feet y 200 feet solo detrás del vehículo","A no más de 10 feet del vehículo, y a 100 feet detrás y 100 feet delante del vehículo","A 50 feet, 100 feet y 200 feet sobre el acotamiento","A no más de 10 feet del vehículo, y a 200 feet detrás y 200 feet delante del vehículo"],"explanation":"El Manual de CDL de Oklahoma establece que en una carretera de dos carriles de doble sentido o sin dividir, un dispositivo se coloca a no más de 10 feet del vehículo para marcar su ubicación y uno a cada lado, a 100 feet delante y 100 feet detrás del vehículo."},"62":{"q":"Después de detenerse en una vía o en el acotamiento en Oklahoma, ¿dentro de cuántos minutos debe un conductor de CMV colocar los dispositivos de advertencia requeridos?","options":["5 minutos","15 minutos","30 minutos","10 minutos"],"explanation":"El Manual de CDL de Oklahoma (Sección 2) establece que si debe detenerse en una vía o en el acotamiento de cualquier camino, debe colocar sus dispositivos de advertencia de emergencia dentro de diez minutos."},"63":{"q":"¿Cuántos dispositivos de advertencia debe llevar un CMV de Oklahoma para usarse cuando el vehículo está estacionado o averiado?","options":["Dos triángulos reflectantes, o 4 bengalas de combustión (fuses), o 2 bengalas de combustible líquido","Cuatro triángulos reflectantes, o 8 bengalas de combustión (fuses), o 4 bengalas de combustible líquido","Un triángulo reflectante, o 3 bengalas de combustión (fuses), o 1 bengala de combustible líquido","Tres triángulos reflectantes, o 6 bengalas de combustión (fuses), o 3 bengalas de combustible líquido"],"explanation":"El Manual de CDL de Oklahoma enumera los dispositivos de advertencia requeridos para vehículos estacionados como tres triángulos reflectantes rojos, o al menos 6 bengalas de combustión (fuses), o 3 bengalas de combustible líquido."},"64":{"q":"Según la ley de Oklahoma (47 O.S. Section 11-705), ¿cuándo NO está obligado a detenerse un conductor que viaja en sentido contrario ante un autobús escolar que está cargando o descargando niños con las luces rojas intermitentes encendidas?","options":["Cuando el autobús está al otro lado de cualquier línea central pintada","Cuando el tránsito es intenso y detenerse sería inconveniente","Cuando un carril central de giro a la izquierda de doble sentido separa las direcciones de circulación","Cuando la calzada está dividida por una barrera física o un camellón sin pavimentar que separa las direcciones de circulación"],"explanation":"El estatuto de Oklahoma 47 O.S. Section 11-705 exime al tránsito en sentido contrario de detenerse solo cuando una carretera dividida con una barrera física o un camellón sin pavimentar separa las calzadas. Una línea pintada o un carril central de giro NO califica, por lo que el tránsito en sentido contrario aún debe detenerse en esos casos."},"65":{"q":"En una carretera de Oklahoma de dos carriles sin dividir, ¿qué debe hacer un conductor que se encuentra con un autobús escolar detenido con las luces rojas intermitentes encendidas y el brazo de parada extendido?","options":["Detenerse, sin importar la dirección de circulación, hasta que el autobús retraiga el brazo de parada y apague las luces rojas","Reducir la velocidad a 25 mph y pasar con precaución","Detenerse solo si circula en la misma dirección que el autobús","Continuar normalmente porque solo el tránsito en la misma dirección debe detenerse"],"explanation":"Según 47 O.S. Section 11-705, en una carretera sin dividir el tránsito en ambas direcciones debe detenerse ante un autobús escolar que exhibe luces rojas intermitentes y el brazo de parada extendido, y permanecer detenido hasta que el autobús retraiga las señales."},"66":{"q":"¿Cuál es la multa por una primera condena por rebasar ilegalmente un autobús escolar detenido en Oklahoma que está cargando o descargando niños?","options":["Una cantidad fija de $50","Un mínimo de $100 y hasta $500","Un mínimo de $250 y hasta $1,000","Una cantidad fija de $1,500 más cárcel obligatoria"],"explanation":"El estatuto de Oklahoma 47 O.S. Section 11-705 establece una multa de no menos de $100 y hasta $500 por una primera infracción por rebasar ilegalmente un autobús escolar detenido, con sanciones que aumentan (incluida la posible suspensión de la licencia) para infracciones reincidentes."},"67":{"q":"Según la ley de uso de carriles de Oklahoma (47 O.S. Section 11-309), en una calzada con cuatro o más carriles, ¿cuándo puede un vehículo circular correctamente por el carril del extremo izquierdo?","options":["Solo al alcanzar y rebasar a otro vehículo, al prepararse para un giro a la izquierda, o cuando las condiciones del tránsito o de la vía lo requieran","En cualquier momento, siempre que el conductor mantenga el límite de velocidad indicado","Solo cuando los carriles de la derecha están completamente vacíos","Solo entre el amanecer y el atardecer"],"explanation":"El estatuto de Oklahoma 47 O.S. Section 11-309 restringe el carril izquierdo para rebasar, prepararse para un giro a la izquierda o situaciones en las que el flujo del tránsito o la configuración de la vía lo requieran. Un vehículo no puede impedir el flujo normal del tránsito circulando por el carril izquierdo, incluso al límite de velocidad indicado."},"68":{"q":"¿Cuál es el límite de velocidad máximo que puede señalizarse en tramos de las autopistas de peaje (turnpikes) de Oklahoma según lo autorizado por el estatuto?","options":["85 mph","75 mph","80 mph","70 mph"],"explanation":"Según 47 O.S. Section 11-801, la Oklahoma Turnpike Authority puede establecer un límite de velocidad de hasta 80 mph en tramos aprobados del sistema de autopistas de peaje. Varios tramos (por ejemplo, partes de las Turner y Indian Nation Turnpikes) están señalizados a 80 mph."},"69":{"q":"Al aproximarse a un cruce ferroviario en Oklahoma, ¿cuándo debe el conductor de un autobús o de un vehículo con carteles (placards) activar las cuatro luces intermitentes?","options":["Aproximadamente 200 feet antes del cruce","Aproximadamente 50 feet antes del cruce","Aproximadamente 500 feet antes del cruce","Solo después de detenerse por completo en el cruce"],"explanation":"El Manual de CDL de Oklahoma (Sección 10.4, procedimientos de cruce para autobuses escolares) indica al conductor que active las luces de emergencia aproximadamente 200 feet antes del cruce para que el tránsito que viene detrás sea advertido de la parada que se aproxima."},"70":{"q":"Mientras cualquier parte de un vehículo comercial de Oklahoma se encuentra sobre un cruce ferroviario, ¿cuál de las siguientes acciones está prohibida?","options":["Cambiar de marcha (velocidad)","Mantener ambas manos en el volante","Mirar y escuchar para detectar trenes","Mantener una velocidad constante"],"explanation":"El Manual de CDL de Oklahoma indica a los conductores que no cambien de marcha al cruzar las vías, porque un cambio mal hecho podría dejar el vehículo detenido sobre el cruce. Los conductores deben seleccionar una marcha antes del cruce y mantenerla mientras cruzan las vías."},"71":{"q":"Cuando un autobús escolar de Oklahoma se detiene para bajar a los estudiantes, ¿a qué distancia de los estudiantes que están en la parada debe detenerse por completo el autobús?","options":["Al menos a 3 feet de los estudiantes","Al menos a 25 feet de los estudiantes","Al menos a 10 feet de los estudiantes","Al menos a 50 feet de los estudiantes"],"explanation":"El Manual de CDL de Oklahoma (Sección 13, prueba de habilidades, descenso de estudiantes) indica al conductor que detenga el autobús escolar por completo al menos a 10 feet de los estudiantes que están en la parada, lo que mantiene a los estudiantes a la vista del conductor."},"72":{"q":"¿Cuál es el ancho máximo legal estándar de Oklahoma para un vehículo y su carga antes de que se requiera un permiso de sobredimensión de ODOT?","options":["8 feet 0 inches","10 feet 0 inches","8 feet 6 inches","9 feet 6 inches"],"explanation":"Según las normas de tamaño y peso de ODOT, el límite legal de ancho de Oklahoma es de 8 feet 6 inches; las cargas más anchas que eso requieren un permiso de sobredimensión. El límite legal de altura es de 13 feet 6 inches."},"73":{"q":"Los traslados de cargas sobredimensionadas en Oklahoma generalmente están restringidos a qué franja horaria?","options":["Solo entre las 9:00 p.m. y las 5:00 a.m.","Horas de luz diurna, desde 30 minutos antes del amanecer hasta 30 minutos después del atardecer","Las 24 horas del día sin restricción horaria","Solo los fines de semana y días festivos"],"explanation":"Las normas de permisos de sobredimensión de ODOT limitan el traslado a las horas de luz diurna, definidas como 30 minutos antes del amanecer hasta 30 minutos después del atardecer, con restricciones adicionales por mal clima y visibilidad reducida."},"74":{"q":"Oklahoma restringe las cargas sobredimensionadas en el Sistema Interestatal durante las horas pico de los días entre semana, ¿en cuáles condados?","options":["Los condados de Comanche, Garfield y Payne","Los condados de Muskogee, Pottawatomie y Carter","Los condados de Oklahoma, Tulsa y Cleveland","Los condados de Canadian, Rogers y Wagoner"],"explanation":"Las normas de sobredimensión de ODOT prohíben las cargas sobredimensionadas en el Sistema Interestatal en los condados de Oklahoma, Tulsa y Cleveland durante las franjas de hora pico de los días entre semana de 7:00-9:00 a.m. y 3:30-6:30 p.m. (hora central), de lunes a viernes."},"75":{"q":"Una condena por una infracción en un cruce a nivel entre vía férrea y carretera en un vehículo comercial resulta en qué descalificación mínima de la CDL en Oklahoma por una primera infracción?","options":["Al menos 30 días","Al menos 120 días","Al menos un año","Al menos 60 días"],"explanation":"El Manual de CDL de Oklahoma (Sección 1.3.5) establece que un titular de CDL queda descalificado por al menos 60 días por una primera infracción de cruce ferroviario, al menos 120 días por una segunda dentro de tres años, y al menos un año por una tercera dentro de tres años."},"76":{"q":"¿Qué agencia estatal de Oklahoma emite las Licencias de Conducir Comerciales y administra las pruebas de conocimientos y habilidades de la CDL?","options":["Service Oklahoma","El Departamento de Transporte de Oklahoma (ODOT)","La Oklahoma Corporation Commission","La Oklahoma Tax Commission"],"explanation":"Service Oklahoma (que asumió las funciones de licencias de conducir antes a cargo del Department of Public Safety) emite las CDL y administra las pruebas de CDL en sus Oficinas de Licencias. Fuente: páginas de Service Oklahoma 'Commercial Driving CDL' y 'CDL First-Time Applicants' (oklahoma.gov)."},"77":{"q":"¿Dónde realiza un solicitante de CDL de Oklahoma las pruebas requeridas de visión y de conocimientos por escrito?","options":["En persona en una Oficina de Licencias de Service Oklahoma","En línea a través del portal de Service Oklahoma desde casa","En cualquier escuela del FMCSA Training Provider Registry","En el cuartel general de una tropa de la Oklahoma Highway Patrol"],"explanation":"Los solicitantes comienzan el proceso de la CDL realizando las pruebas de visión y de conocimientos por escrito en persona en una Oficina de Licencias de Service Oklahoma; las pruebas de visión y por escrito se administran juntas en la misma cita. Fuente: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"78":{"q":"¿Cuántos días debe un solicitante de Oklahoma tener un Permiso de Aprendiz Comercial (CLP) antes de que se le permita realizar la prueba de habilidades (manejo) de la CDL?","options":["14 días completos, con la prueba permitida en el día 15","30 días completos, con la prueba permitida en el día 31","7 días completos, con la prueba permitida en el día 8","10 días completos, con la prueba permitida en el día 11"],"explanation":"Oklahoma exige que el CLP se tenga durante 14 días completos antes de la prueba de habilidades; el solicitante puede realizar la prueba en el día 15. Esto refleja la regla federal de 14 días. Fuente: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.25."},"79":{"q":"La prueba de habilidades de la CDL de Oklahoma es un examen de tres partes. ¿Qué conjunto enumera correctamente esas tres partes?","options":["Inspección previaje del vehículo, habilidades básicas de control y la prueba de manejo en carretera","Prueba de conocimientos generales, prueba de frenos de aire y prueba de vehículos combinados","Prueba de visión, prueba escrita y un curso de manejo defensivo","Inspección previaje, prueba de materiales peligrosos y una prueba de retroceso"],"explanation":"La prueba de habilidades de la CDL de Oklahoma consta de tres partes: la inspección previaje del vehículo, las habilidades básicas de control (por ejemplo, maniobras de retroceso) y la prueba de manejo en carretera. Fuente: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.113."},"80":{"q":"Según las reglas federales de Capacitación para Conductores de Nivel Inicial (ELDT) que Oklahoma aplica, un solicitante por primera vez de Clase A o Clase B debe completar la ELDT de un proveedor aprobado antes de hacer qué?","options":["Realizar la prueba de habilidades de la CDL administrada por el estado","Recibir el Permiso de Aprendiz Comercial","Realizar la prueba escrita de conocimientos generales","Completar el examen de visión"],"explanation":"La ELDT (teórica y de práctica al volante) para una CDL de Clase A o B por primera vez debe completarse a través de un proveedor del FMCSA Training Provider Registry antes de que el solicitante realice la prueba de habilidades administrada por el estado. Fuente: regla ELDT de FMCSA (49 CFR Part 380); Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"81":{"q":"¿Dónde debe estar registrado el proveedor de Capacitación para Conductores de Nivel Inicial de un solicitante de CDL de Oklahoma para que la capacitación cuente?","options":["En el Training Provider Registry (TPR) de FMCSA","En la lista de escuelas del Departamento de Transporte de Oklahoma","En el directorio de proveedores aprobados de Service Oklahoma","En el National Registry of Certified Medical Examiners"],"explanation":"La ELDT debe obtenerse de un proveedor registrado en el Training Provider Registry (TPR) de FMCSA. Fuente: regla ELDT de FMCSA; Service Oklahoma 'Commercial Driving CDL' (oklahoma.gov)."},"82":{"q":"¿Qué endoso de CDL requiere que la capacitación teórica de ELDT se complete ANTES de realizar la prueba de conocimientos (no la prueba de habilidades)?","options":["Endoso de Materiales Peligrosos (HazMat) (H)","Endoso de Pasajeros (P)","Endoso de Autobús Escolar (S)","Endoso de Dobles/Triples (T)"],"explanation":"Para el endoso de Materiales Peligrosos (HazMat) (H), la ELDT es solo teórica y debe completarse antes de la prueba de conocimientos administrada por el estado. Los endosos P y S requieren ELDT antes de sus pruebas de habilidades. Fuente: regla ELDT de FMCSA (49 CFR Part 380)."},"83":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL de Oklahoma al declarar su tipo de conducción?","options":["Cuatro","Dos","Tres","Seis"],"explanation":"Los solicitantes deben autocertificarse en una de cuatro categorías: Interestatal No Exceptuada (NI), Interestatal Exceptuada (EI), Intraestatal No Exceptuada (NA) e Intraestatal Exceptuada (EA). Fuente: Service Oklahoma 'CDL First-Time Applicants' y CDL Self-Certification SOP (oklahoma.gov)."},"84":{"q":"¿Qué categoría de autocertificación REQUIERE que el conductor mantenga en archivo un Certificado de Examinador Médico de DOT para obtener la licencia?","options":["Interestatal No Exceptuada (NI)","Interestatal Exceptuada (EI)","Intraestatal Exceptuada (EA)","Intraestatal No Exceptuada (NA)"],"explanation":"Solo la categoría Interestatal No Exceptuada (NI) requiere una Tarjeta Médica de DOT para obtener la licencia. Las categorías EI, NA y EA no requieren tener una tarjeta médica en archivo con Service Oklahoma. Fuente: Service Oklahoma 'CDL First-Time Applicants' / 'Commercial Driving CDL' (oklahoma.gov)."},"85":{"q":"¿Cómo se transmite ahora el Certificado de Examinador Médico de DOT de un conductor a Service Oklahoma para su registro?","options":["Electrónicamente desde el FMCSA National Registry of Certified Medical Examiners","El conductor envía por correo una copia en papel a la sede de Service Oklahoma","El empleador lo envía por fax a la Oficina de Licencias local","La agencia de placas del condado reenvía una copia notariada"],"explanation":"El examinador médico certificado envía electrónicamente el certificado (Formulario MCSA-5876) al FMCSA National Registry, que transmite el estado de la certificación médica electrónicamente a Service Oklahoma. Fuente: Service Oklahoma CDL Self-Certification and Medical Certificates Processing SOP (oklahoma.gov); FMCSA National Registry."},"86":{"q":"¿Cuál es el número de formulario del Certificado de Examinador Médico federal que un examinador certificado envía al FMCSA National Registry?","options":["MCSA-5876","MCSA-5875","MCSA-5889","MCSA-5870"],"explanation":"El Certificado de Examinador Médico es el Formulario MCSA-5876 de FMCSA; el Informe de Examen Médico relacionado es el MCSA-5875. El examinador envía el resultado del MCSA-5876 al National Registry. Fuente: Service Oklahoma Medical Certificates Processing SOP; FMCSA."},"87":{"q":"Un titular de CDL Interestatal No Exceptuada (NI) de Oklahoma normalmente debe presentar un Certificado de Examinador Médico de DOT vigente con qué frecuencia mínima (el intervalo máximo entre exámenes según las normas de FMCSA)?","options":["Cada 24 meses","Cada 12 meses","Cada 36 meses","Cada 60 meses"],"explanation":"Un certificado de examinador médico estándar es válido por un máximo de 24 meses, por lo que los conductores NI deben tener un certificado vigente en archivo dentro de ese ciclo (se aplican intervalos más cortos para ciertas condiciones). Fuente: orientación médica de CDL de Service Oklahoma; 49 CFR 391.45."},"88":{"q":"Si se notifica a Service Oklahoma que la certificación médica de un titular de CDL ha vencido o ya no es válida, ¿dentro de cuántos días debe la agencia degradar (downgrade) la CDL según la regla federal?","options":["Dentro de 60 días","Dentro de 10 días","Dentro de 30 días","Dentro de 90 días"],"explanation":"Las agencias estatales de licencias de conducir, incluida Service Oklahoma, deben degradar una CDL dentro de los 60 días de enterarse de que el conductor ya no está certificado médicamente o de que el certificado médico ha vencido y no fue renovado. Fuente: orientación de degradación de Service Oklahoma; 49 CFR 383.73(o)."},"89":{"q":"Según el estatuto de Oklahoma, ¿por cuánto tiempo es válido inicialmente un Permiso de Aprendiz Comercial (CLP)?","options":["180 días","90 días","60 días","1 año"],"explanation":"Oklahoma emite el CLP por un periodo de 180 días; puede renovarse una vez por 180 días adicionales. Fuente: 47 O.S. Section 6-101; orientación de CLP de Service Oklahoma."},"90":{"q":"Un CLP de Oklahoma puede renovarse una sola vez. ¿Por cuánto tiempo es válida esa única renovación?","options":["180 días adicionales","30 días adicionales","1 año adicional","90 días adicionales"],"explanation":"El CLP es válido por 180 días y puede renovarse una vez por 180 días adicionales, lo que permite hasta un año en total. Fuente: 47 O.S. Section 6-101; orientación de CLP de Service Oklahoma."},"91":{"q":"¿Cuál es la edad mínima para obtener una CDL para conducción comercial INTRAESTATAL (solo dentro de Oklahoma)?","options":["18 años","21 años","16 años","19 años"],"explanation":"Un solicitante debe tener al menos 18 años para operar un CMV de manera intraestatal (dentro de Oklahoma) y al menos 21 años para conducir de manera interestatal. Fuente: orientación de CDL de Service Oklahoma; 47 O.S. Section 6-101."},"92":{"q":"Un titular de CDL de Oklahoma de 19 años que aún no ha cumplido 21 años generalmente está limitado de qué manera?","options":["Solo a conducción comercial intraestatal (dentro de Oklahoma)","Solo a conducir vehículos comerciales Clase C","Solo a conducción comercial durante el día","Solo a conducir con un titular de CDL con licencia presente"],"explanation":"Los conductores de 18 a 20 años pueden tener una CDL pero están restringidos a la operación comercial intraestatal (dentro de Oklahoma); la operación interestatal requiere tener 21 años. Fuente: orientación de CDL de Service Oklahoma; 49 CFR 383.3 / 391.11."},"93":{"q":"¿Cuál documento NO está entre los que un solicitante de CDL de Oklahoma por primera vez debe presentar en la Oficina de Licencias de Service Oklahoma?","options":["Una carta del empleador que autorice la prueba de manejo","Comprobante de identidad y presencia legal","Comprobante de residencia en Oklahoma (un comprobante de domicilio)","Una licencia de conducir Clase D de Oklahoma válida"],"explanation":"Los elementos requeridos incluyen comprobante de identidad y presencia legal, comprobante de residencia/domicilio, una licencia Clase D de Oklahoma válida y un número de Seguro Social; no se requiere una carta de autorización del empleador. Fuente: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"94":{"q":"Con respecto a la renovación de la CDL de Oklahoma, ¿qué afirmación es correcta sobre el proceso?","options":["Los titulares de CDL elegibles pueden renovar en línea, pero los titulares de Materiales Peligrosos (HazMat) (H) deben renovar en persona y volver a realizar la prueba escrita de HazMat más la verificación de antecedentes de la TSA","Todas las renovaciones de CDL, incluida la de HazMat, pueden completarse por completo en línea","Las CDL no pueden renovarse y deben volver a examinarse desde cero en cada ciclo","La renovación requiere volver a realizar la prueba completa de habilidades de tres partes cada vez"],"explanation":"Service Oklahoma ofrece renovación de CDL en línea para titulares elegibles, pero los titulares del endoso de Materiales Peligrosos (HazMat) deben renovar en persona, volver a realizar la prueba de conocimientos de HazMat y completar la verificación de antecedentes de la TSA en cada renovación. (Nota: las tarifas exactas y el plazo de la credencial elegido, por ejemplo, las opciones de 4 años frente a 8 años, pueden cambiar.) Fuente: Service Oklahoma 'CDL Renewal/Replacement Online' (oklahoma.gov)."}},"hi":{"0":{"q":"ओक्लाहोमा (Oklahoma) के राजमार्गों पर, ओवर-विड्थ परमिट की आवश्यकता पड़ने से पहले किसी वाहन की, भार के साथ या बिना, अधिकतम कुल बाहरी चौड़ाई कितनी होती है?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"ओक्लाहोमा (Oklahoma) कुल बाहरी चौड़ाई को 102 inches (8.5 ft) तक सीमित करता है; इससे अधिक चौड़ाई के लिए ओवर-विड्थ परमिट आवश्यक है। स्रोत: 47 O.S. §14-103."},"1":{"q":"ओक्लाहोमा (Oklahoma) के टर्नपाइक, इंटरस्टेट, U.S., या स्टेट हाईवे पर बिना किसी विशेष परमिट के किसी वाहन या भार की अधिकतम कानूनी ऊँचाई कितनी होती है?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"ओक्लाहोमा (Oklahoma) टर्नपाइक, इंटरस्टेट, U.S., और स्टेट हाईवे पर बिना परमिट के 14 feet तक की ऊँचाई की अनुमति देता है। स्रोत: 47 O.S. §14-103."},"2":{"q":"ओक्लाहोमा (Oklahoma) की किसी COUNTY सड़क पर बिना किसी विशेष परमिट के वाहन या भार की अधिकतम ऊँचाई कितनी होती है?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"काउंटी सड़कों पर ऊँचाई की सीमा 13.5 feet है, जो टर्नपाइक, इंटरस्टेट, U.S., और स्टेट हाईवे पर अनुमत 14-foot सीमा से कम है। स्रोत: 47 O.S. §14-103."},"3":{"q":"ओक्लाहोमा (Oklahoma) में, ओवर-वेट परमिट के बिना किसी भी सिंगल एक्सल पर अधिकतम अनुमेय भार कितना होता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"ओक्लाहोमा (Oklahoma) की सिंगल-एक्सल भार सीमा 20,000 pounds है। स्रोत: 47 O.S. §14-109(A)."},"4":{"q":"बिना किसी विशेष परमिट के ओक्लाहोमा (Oklahoma) टैंडम एक्सल के एक सेट पर अधिकतम कितना भार अनुमति देता है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"ओक्लाहोमा (Oklahoma) में टैंडम एक्सल के किसी भी सेट पर अधिकतम भार 34,000 pounds है। स्रोत: 47 O.S. §14-109(B)."},"5":{"q":"वेट टेबल के अंतर्गत बिना किसी विशेष परमिट के ओक्लाहोमा (Oklahoma) के राजमार्गों पर सामान्य अधिकतम सकल वाहन भार (gross vehicle weight) कितना होता है?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"ओक्लाहोमा (Oklahoma) की वेट टेबल कानूनी सकल भार को 80,000 pounds तक सीमित करती है, जो संघीय सीमा के अनुरूप है। स्रोत: 47 O.S. §14-109(A)."},"6":{"q":"ओक्लाहोमा (Oklahoma) में अनुमेय सकल एवं एक्सल भार एक्सल अंतराल पर आधारित एक सूत्र का उपयोग करके निर्धारित किए जाते हैं। इस सूत्र को आमतौर पर क्या कहा जाता है?","options":["Federal Bridge Formula","Gross Combination Rule","Tare Weight Formula","Axle Spread Ratio"],"explanation":"ओक्लाहोमा (Oklahoma) Federal Bridge Formula/वेट टेबल (23 U.S.C. §127) का उपयोग करता है, जो चरम एक्सल के बीच की दूरी को निकटतम फुट तक मापता है। स्रोत: 47 O.S. §14-109; ODPS Troop S."},"7":{"q":"ओक्लाहोमा (Oklahoma) की सड़कों पर बंपर सहित किसी SINGLE ट्रक (कॉम्बिनेशन नहीं) की अधिकतम कुल लंबाई कितनी होती है?","options":["40 feet","45 feet","53 feet","70 feet"],"explanation":"ओक्लाहोमा (Oklahoma) में किसी सिंगल ट्रक की कुल लंबाई, आगे और पीछे के बंपर सहित, 45 feet से अधिक नहीं हो सकती। स्रोत: 47 O.S. §14-103."},"8":{"q":"National Network पर, ओक्लाहोमा (Oklahoma) में ट्रक-ट्रैक्टर/सेमीट्रेलर कॉम्बिनेशन में (बिना परमिट के) अधिकतम सेमीट्रेलर लंबाई कितनी होती है?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"ट्रक-ट्रैक्टर/सेमीट्रेलर कॉम्बिनेशन में एक सेमीट्रेलर National Network पर 53 feet तक हो सकता है; इससे अधिक (59'6\" तक) के लिए परमिट आवश्यक है। स्रोत: 47 O.S. §14-103."},"9":{"q":"ओक्लाहोमा (Oklahoma) की सभी सड़कों और राजमार्गों पर ट्रक-ट्रैक्टर/सेमीट्रेलर के अलावा अन्य वाहन कॉम्बिनेशनों की अधिकतम कुल लंबाई कितनी होती है?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"अन्य वाहन कॉम्बिनेशनों की कुल लंबाई, बंपर सहित, ओक्लाहोमा (Oklahoma) की सभी सड़कों और राजमार्गों पर 70 feet से अधिक नहीं हो सकती। स्रोत: 47 O.S. §14-103."},"10":{"q":"ओक्लाहोमा (Oklahoma) की कौन सी एजेंसी डिवीजन स्टेट हाईवे सिस्टम पर यात्रा के लिए ओवरसाइज/ओवरवेट परमिट जारी करती है?","options":["The Oklahoma Tax Commission","The ODOT Size and Weight Permit Division","The Corporation Commission","The county sheriff's office"],"explanation":"ODOT Size and Weight Permit Division ओवरसाइज/ओवरवेट परमिट जारी करती है (swpermitsok.com पर ऑनलाइन आवेदन किया जाता है)। स्रोत: ODOT; OAC 730:50-5."},"11":{"q":"ओक्लाहोमा (Oklahoma) में एक विशेष ANNUAL ओवर-विड्थ परमिट के अंतर्गत एक ट्रक और सेमीट्रेलर कॉम्बिनेशन अधिकतम कितनी चौड़ाई तक संचालित हो सकता है?","options":["108 inches","114 inches","120 inches","144 inches"],"explanation":"जिन कॉम्बिनेशनों की चौड़ाई 102 inches से अधिक परंतु 120 inches से अधिक नहीं है, वे एक विशेष वार्षिक ओवर-विड्थ परमिट के अंतर्गत संचालित हो सकते हैं। स्रोत: OAC 730:50-5; 47 O.S. §14-103G."},"12":{"q":"ओक्लाहोमा (Oklahoma) के नियमों के अंतर्गत, 12 feet से अधिक परंतु 14 feet से अधिक नहीं चौड़े परमिटेड भार के लिए दो-लेन राजमार्ग पर कौन सी एस्कॉर्ट व्यवस्था होनी चाहिए?","options":["No escort required","A front escort vehicle","A rear escort vehicle","Both front and rear escorts"],"explanation":"12 ft से अधिक परंतु 14 ft से अधिक चौड़े नहीं भार के लिए दो-लेन/सुपर दो-लेन राजमार्गों पर एक फ्रंट एस्कॉर्ट आवश्यक है (मल्टी-लेन पर रियर एस्कॉर्ट)। स्रोत: OAC 730:50-5-18(b)."},"13":{"q":"किस कुल HEIGHT पर ओक्लाहोमा (Oklahoma) के परमिटेड भार के लिए दो एस्कॉर्ट वाहन (एक आगे, एक पीछे) और यूटिलिटीज़ तथा रेलरोड को अग्रिम सूचना आवश्यक होती है?","options":["14 feet or more","14 feet 6 inches or more","15 feet or more","15 feet 9 inches or more"],"explanation":"जिन भारों की कुल ऊँचाई 15 feet 9 inches या अधिक है, उनके लिए दो एस्कॉर्ट और प्रभावित यूटिलिटीज़/रेलरोड से अग्रिम संपर्क आवश्यक है। स्रोत: OAC 730:50-5-18(b)."},"14":{"q":"किस कुल लंबाई का ट्रक-ट्रैक्टर/सेमीट्रेलर कॉम्बिनेशन ओक्लाहोमा (Oklahoma) के दो-लेन राजमार्गों पर एक आवश्यक फ्रंट एस्कॉर्ट को सक्रिय करता है?","options":["More than 70 feet","More than 75 feet","More than 80 feet","More than 100 feet"],"explanation":"80 feet से अधिक कुल लंबाई वाले ट्रक-ट्रैक्टर/सेमीट्रेलर कॉम्बिनेशन के लिए दो-लेन राजमार्गों पर एक फ्रंट एस्कॉर्ट आवश्यक है। स्रोत: OAC 730:50-5-18(b)(4)."},"15":{"q":"ओक्लाहोमा (Oklahoma) के कृषि-उत्पाद भार विचलन (ODPS Troop S के अनुसार) के अंतर्गत, कौन सी सहनशीलताएँ लागू होती हैं, और कहाँ यात्रा प्रतिबंधित है?","options":["5% over gross and 8% over axle limits; not on interstate highways","10% over gross and 10% over axle; not on turnpikes","8% over gross and 5% over axle; not on county roads","5% over gross and 5% over axle; interstate allowed"],"explanation":"अधिकतम पंजीकरण पर कृषि उत्पाद ढोने वाले वाहन सकल सीमाओं से 5% तक अधिक और एक्सल सीमाओं से 8% तक अधिक चल सकते हैं, परंतु Interstate सिस्टम पर नहीं। स्रोत: ODPS Troop S; 47 O.S. §14-109."},"16":{"q":"एक कृषि भार विचलन परमिट के साथ जो एक्सल सीमा से लगभग 8% अधिक की अनुमति देता है, 20,000 pounds का सिंगल-एक्सल आँकड़ा लगभग कितना हो जाता है?","options":["20,800 pounds","21,600 pounds","22,400 pounds","24,000 pounds"],"explanation":"विचलन (एक्सल से 8% अधिक) के साथ, 20,000-lb सिंगल-एक्सल सीमा 21,600 lbs हो जाती है; किसी भी श्रेणी से अधिक होने पर उस यात्रा के लिए परमिट अमान्य हो जाता है। स्रोत: ODPS Troop S axle table."},"17":{"q":"ओक्लाहोमा (Oklahoma) का ODOT Annual Envelope Vehicle Permit स्टेट हाईवे सिस्टम पर किसी वाहन को किन अधिकतम आयामों तक अधिकृत करता है?","options":["10 ft wide, 13.5 ft high, 90 ft long","12 ft wide, 14 ft high, 110 ft long","14 ft wide, 15 ft high, 120 ft long","12 ft wide, 16 ft high, 100 ft long"],"explanation":"Annual Envelope Vehicle Permit 12 ft wide, 14 ft high, और 110 ft long तक के वाहनों को कवर करता है (शुल्क $4,000), जो केवल स्टेट हाईवे सिस्टम पर मान्य है। स्रोत: OAC 730:50-5-13."},"18":{"q":"ओक्लाहोमा (Oklahoma) में अपनी प्राकृतिक अवस्था में कच्चे वन उत्पादों के हॉलर्स $25 वार्षिक कृषि परमिट प्राप्त कर सकते हैं, परंतु किस मार्ग सीमा के साथ?","options":["No travel on the Interstate system","No travel on any turnpike","No travel on county roads","No travel at night only"],"explanation":"$25 वार्षिक कृषि परमिट के अंतर्गत कच्चे वन-उत्पाद ढुलाई की National System of Interstate and Defense Highways पर अनुमति नहीं है। स्रोत: OAC 730:50-5-22; 47 O.S. §14-118(e)."},"19":{"q":"ओक्लाहोमा (Oklahoma) में, जब टो किए जाने वाले वाहन का GVWR 10,000 pounds से अधिक हो, तब 26,001 या अधिक pounds के सकल कॉम्बिनेशन भार रेटिंग (GCWR) वाले किसी भी वाहन कॉम्बिनेशन को चलाने के लिए कौन सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class D"],"explanation":"ओक्लाहोमा (Oklahoma) संघीय वर्गीकरण को अपनाता है: एक Class A CDL उन सभी वाहन कॉम्बिनेशनों को कवर करता है जिनका GCWR 26,001+ lbs हो और जहाँ टो किया गया यूनिट 10,000 lbs GVWR से अधिक हो। स्रोत: Oklahoma Statutes Title 47 Sec. 6-101 और Oklahoma CDL Manual (Service Oklahoma)."},"20":{"q":"एक ओक्लाहोमा (Oklahoma) चालक 30,000 pounds GVWR वाला एक सिंगल स्ट्रेट ट्रक चलाता है जो कोई ट्रेलर टो नहीं करता। इसके लिए कौन सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","No CDL is required"],"explanation":"एक Class B CDL 26,001+ lbs GVWR वाले किसी भी सिंगल वाहन को कवर करता है (या ऐसा वाहन जो 10,000 lbs GVWR से अधिक नहीं की यूनिट टो करता हो)। एक 30,000-lb स्ट्रेट ट्रक Class B के अंतर्गत आता है। स्रोत: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"21":{"q":"ओक्लाहोमा (Oklahoma) के नियमों के अंतर्गत, एक वाहन जो Class A या Class B भार सीमा को पूरा नहीं करता, फिर भी Class C CDL की आवश्यकता होती है यदि वह क्या करता है?","options":["Has a GVWR over 16,000 pounds","Is designed to transport 16 or more people including the driver, or carries placardable hazardous materials","Tows any trailer rated over 5,000 pounds","Is operated for hire across county lines"],"explanation":"एक Class C CDL उस वाहन पर लागू होता है जो Class A या B को पूरा नहीं करता परंतु चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है या जो प्लेकार्ड आवश्यक करने वाली खतरनाक सामग्री ले जाता है। स्रोत: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"22":{"q":"खतरनाक के रूप में नामित और प्लेकार्डिंग आवश्यक करने वाली सामग्री को ले जाने के लिए ओक्लाहोमा (Oklahoma) CDL में कौन सा एंडोर्समेंट कोड जोड़ा जाना चाहिए?","options":["N","T","H","P"],"explanation":"प्लेकार्ड योग्य खतरनाक सामग्री ढोने के लिए H (Hazardous Materials) एंडोर्समेंट आवश्यक है। स्रोत: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"23":{"q":"वह संघीय/ओक्लाहोमा (Oklahoma) क्षमता सीमा क्या है जो N (Tanker) एंडोर्समेंट आवश्यक करने वाले 'टैंक वाहन' को परिभाषित करती है?","options":["A tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more","A tank with an individual rated capacity of more than 100 gallons","Any tank carrying 500 gallons or more total","A tank with an aggregate capacity of 2,000 gallons or more"],"explanation":"N एंडोर्समेंट उन वाहनों के लिए आवश्यक है जो ऐसे टैंक में तरल या गैस ले जाते हैं जिसकी individual rated capacity 119 gallons से अधिक हो और aggregate rated capacity 1,000 gallons या अधिक हो। स्रोत: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.5."},"24":{"q":"डबल या ट्रिपल ट्रेलर खींचने के लिए कौन सा ओक्लाहोमा (Oklahoma) CDL एंडोर्समेंट आवश्यक है, और चालक के पास पहले से कौन सा CDL वर्ग होना चाहिए?","options":["T endorsement, held with a Class A CDL","T endorsement, held with a Class B CDL","N endorsement, held with a Class A CDL","P endorsement, held with a Class C CDL"],"explanation":"T (Doubles/Triples) एंडोर्समेंट कई ट्रेलर खींचने की अनुमति देता है और Class A चालकों द्वारा जोड़ा जाता है, जिन्हें आवश्यक अतिरिक्त ज्ञान प्रदर्शित करना होता है। स्रोत: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"25":{"q":"एक ओक्लाहोमा (Oklahoma) चालक चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किया गया वाहन चलाना चाहता है। कौन सा एंडोर्समेंट आवश्यक है?","options":["S (School Bus)","P (Passenger)","N (Tanker)","T (Doubles/Triples)"],"explanation":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है; इसके लिए एक ज्ञान परीक्षा और एक प्रतिनिधि वाहन में कौशल परीक्षा पास करना आवश्यक है। स्रोत: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"26":{"q":"इससे पहले कि एक ओक्लाहोमा (Oklahoma) चालक School Bus (S) एंडोर्समेंट प्राप्त कर सके, कौन सा अन्य एंडोर्समेंट एक पूर्व-आवश्यकता है?","options":["The H (HazMat) endorsement","The N (Tanker) endorsement","The P (Passenger) endorsement","The T (Doubles/Triples) endorsement"],"explanation":"S (School Bus) एंडोर्समेंट के लिए चालक को पहले P (Passenger) एंडोर्समेंट धारण करना आवश्यक है, फिर एक स्कूल बस ज्ञान परीक्षा और एक स्कूल बस में कौशल परीक्षा पास करनी होती है। स्रोत: Oklahoma CDL Manual / Endorsements (Service Oklahoma); 49 CFR 383.93."},"27":{"q":"केवल इंट्रास्टेट (ओक्लाहोमा के भीतर) संचालन तक सीमित ओक्लाहोमा (Oklahoma) CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16","18","21","25"],"explanation":"केवल इंट्रास्टेट ओक्लाहोमा (Oklahoma) CDL धारण करने के लिए चालक की आयु कम से कम 18 होनी चाहिए; 21 से कम आयु के चालकों को 'K' इंट्रास्टेट-ओनली प्रतिबंध मिलता है। स्रोत: Oklahoma CDL Manual (Service Oklahoma); 47 O.S. Sec. 6-101."},"28":{"q":"ओक्लाहोमा (Oklahoma) से इंटरस्टेट कॉमर्स (राज्य की सीमाओं के पार) में CDL वाहन चलाने के लिए न्यूनतम आयु क्या आवश्यक है?","options":["18","19","21","23"],"explanation":"इंटरस्टेट CDL संचालन के लिए न्यूनतम आयु 21 आवश्यक है; 18 से 20 आयु के चालक ओक्लाहोमा (Oklahoma) के भीतर इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: Oklahoma CDL Manual (Service Oklahoma); 49 CFR 391.11."},"29":{"q":"ओक्लाहोमा (Oklahoma) में आवश्यक ज्ञान परीक्षाएँ पास करने के बाद, CDL कौशल (ड्राइव) परीक्षा देने से पहले आवेदक को कितने समय तक Commercial Learner Permit (CLP) धारण करना आवश्यक है?","options":["7 full days","10 full days","14 full days","30 full days"],"explanation":"संघीय और ओक्लाहोमा (Oklahoma) नियमों के अनुसार कौशल परीक्षा से पहले 14 full days तक CLP धारण करना आवश्यक है; परीक्षा 15वें दिन ली जा सकती है। स्रोत: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.25."},"30":{"q":"ओक्लाहोमा (Oklahoma) Commercial Learner Permit (CLP) कितने समय के लिए मान्य होता है, और इसे कैसे बढ़ाया जा सकता है?","options":["90 days, non-renewable","180 days, renewable one time for an additional 180 days","1 year, renewable annually","60 days, renewable up to three times"],"explanation":"एक ओक्लाहोमा (Oklahoma) CLP 180 days के लिए जारी किया जाता है और अतिरिक्त 180 days के लिए एक बार नवीनीकृत किया जा सकता है। स्रोत: Oklahoma CDL Manual / Service Oklahoma; 49 CFR 383.25."},"31":{"q":"एक पहली बार के ओक्लाहोमा (Oklahoma) CDL आवेदक को Service Oklahoma लाइसेंसिंग कार्यालय में कौन से दस्तावेज़ों का सेट प्रस्तुत करना आवश्यक है?","options":["Only a valid Class D license and a birth certificate","Proof of identity, proof of lawful presence, Social Security number, and proof of Oklahoma residency","Only a Social Security card and an employer letter","A passport and proof of vehicle insurance"],"explanation":"Service Oklahoma को पहचान का प्रमाण, वैध उपस्थिति, आवेदक का SSN, और ओक्लाहोमा (Oklahoma) निवास (मानक के लिए एक निवास दस्तावेज़, REAL ID के लिए दो) के साथ एक वैध Class D लाइसेंस आवश्यक है। स्रोत: Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"32":{"q":"एक पहली बार के ओक्लाहोमा (Oklahoma) CDL आवेदक के लिए Entry-Level Driver Training (ELDT) किस आधिकारिक प्रणाली के माध्यम से पूरा किया जाना चाहिए?","options":["The Oklahoma Department of Education portal","The FMCSA Training Provider Registry","The TSA Hazmat Threat Assessment Program","The Oklahoma Tax Commission registry"],"explanation":"ELDT एक ऐसे स्कूल द्वारा प्रदान किया जाना चाहिए जो FMCSA Training Provider Registry में सूचीबद्ध हो, जो पूर्णता की रिपोर्ट इलेक्ट्रॉनिक रूप से करती है। स्रोत: FMCSA ELDT rule (49 CFR Part 380); Oklahoma CDL First-Time Applicants (Service Oklahoma)."},"33":{"q":"ओक्लाहोमा (Oklahoma) में लागू FMCSA नियमों के अंतर्गत निम्न में से किसके लिए कौशल/ज्ञान परीक्षा से पहले ELDT (Entry-Level Driver Training) आवश्यक है?","options":["Obtaining the Tanker (N) endorsement","Obtaining the Doubles/Triples (T) endorsement","Obtaining the Passenger (P) or School Bus (S) endorsement for the first time","Renewing an existing Class A CDL"],"explanation":"ELDT पहली बार के Class A या B CDL, B-से-A अपग्रेड, और पहली बार के H, P, या S एंडोर्समेंट के लिए आवश्यक है। N और T एंडोर्समेंट ELDT-विनियमित नहीं हैं। स्रोत: FMCSA ELDT rule (49 CFR Part 380); Service Oklahoma."},"34":{"q":"Hazardous Materials (H) एंडोर्समेंट के लिए, ओक्लाहोमा (Oklahoma) में लागू ELDT आवश्यकता किसमें शामिल होती है?","options":["Theory instruction only","Behind-the-wheel instruction only","Both theory and behind-the-wheel instruction","No training at all"],"explanation":"H एंडोर्समेंट के लिए ELDT केवल सिद्धांत है; केवल Class A/B CDL और P तथा S एंडोर्समेंट के लिए सिद्धांत और बिहाइंड-द-व्हील दोनों प्रशिक्षण आवश्यक हैं। स्रोत: FMCSA ELDT rule (49 CFR Part 380)."},"35":{"q":"HazMat ज्ञान परीक्षा पास करने के अलावा, एक ओक्लाहोमा (Oklahoma) चालक को H एंडोर्समेंट प्राप्त करने या बनाए रखने के लिए क्या आवश्यक है?","options":["A TSA security threat assessment (background check) that is valid for 5 years","A second skills test in a tank vehicle","A notarized employer sponsorship letter","A separate state HazMat permit renewed annually"],"explanation":"H एंडोर्समेंट के लिए एक TSA Hazmat Threat Assessment (बैकग्राउंड चेक/फिंगरप्रिंटिंग) आवश्यक है; क्लियरेंस 5 years के लिए मान्य होती है और एंडोर्समेंट के साथ नवीनीकृत की जानी चाहिए। स्रोत: TSA HTAP; 49 CFR 1572; Service Oklahoma CDL."},"36":{"q":"एक ओक्लाहोमा (Oklahoma) CDL पर किस एंडोर्समेंट कोड के साथ एक चालक को प्लेकार्ड योग्य खतरनाक सामग्री ले जाने वाले टैंक वाहन को संचालित करने के लिए अधिकृत किया जाता है (संयुक्त HazMat और Tank)?","options":["HN","X","T","Z"],"explanation":"ओक्लाहोमा (Oklahoma) उन चालकों के लिए संयुक्त एंडोर्समेंट कोड 'X' जारी करता है जो Tank (N) और Hazardous Materials (H) दोनों प्राधिकार धारण करते हैं। स्रोत: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma); 49 CFR 383.153."},"37":{"q":"एक ओक्लाहोमा (Oklahoma) CDL आवेदक कितनी मेडिकल सेल्फ-सर्टिफिकेशन श्रेणियों में से चुनता है, और किसके लिए एक DOT मेडिकल परीक्षक का प्रमाणपत्र आवश्यक है?","options":["Two categories; the Excepted Interstate category requires the medical card","Four categories; the Non-Excepted Interstate (NI) category requires the medical card","Three categories; the Non-Excepted Intrastate category requires the medical card","Four categories; the Excepted Intrastate (EA) category requires the medical card"],"explanation":"चार सेल्फ-सर्टिफिकेशन श्रेणियाँ हैं (NI, EI, NA, EA)। केवल Non-Excepted Interstate (NI) चालकों को एक वैध DOT मेडिकल परीक्षक प्रमाणपत्र प्रदान करना और बनाए रखना आवश्यक है। स्रोत: Oklahoma CDL First-Time Applicants (Service Oklahoma); 49 CFR 383.71."},"38":{"q":"जब धारक ओक्लाहोमा (Oklahoma) राज्य के बाहर वाणिज्यिक वाहन संचालित नहीं कर सकता, तब एक ओक्लाहोमा (Oklahoma) CDL या CLP पर कौन सा प्रतिबंध कोड लगता है?","options":["E","L","K","Z"],"explanation":"'K' प्रतिबंध का अर्थ है केवल इंट्रास्टेट - चालक CDL वाहन में ओक्लाहोमा (Oklahoma) नहीं छोड़ सकता (आमतौर पर 21 से कम आयु के चालकों पर लागू)। 'E' = कोई मैनुअल ट्रांसमिशन नहीं, 'L' = कोई एयर ब्रेक नहीं, 'Z' = कोई फुल एयर ब्रेक नहीं। स्रोत: Oklahoma CDL Endorsements & Restrictions (Service Oklahoma)."},"39":{"q":"ओक्लाहोमा (Oklahoma) में एक वाणिज्यिक मोटर वाहन (CMV) संचालित करते समय, किस रक्त एल्कोहल सांद्रता (BAC) पर एक चालक को कानूनी रूप से अक्षम माना जाता है और एक प्रमुख अपराध करता है?","options":["0.02 or greater","0.04 or greater","0.08 or greater","0.10 or greater"],"explanation":"ओक्लाहोमा (Oklahoma) CMV BAC सीमा को 0.04 या अधिक पर निर्धारित करता है, जो गैर-वाणिज्यिक चालकों की 0.08 सीमा का आधा है। 0.04 या उससे अधिक पर CMV संचालित करना एक प्रमुख अपराध है। स्रोत: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 जैसा ओक्लाहोमा (Oklahoma) द्वारा अपनाया गया।"},"40":{"q":"ओक्लाहोमा (Oklahoma) के निहित सहमति (implied consent) कानून के अंतर्गत, एक वाणिज्यिक मोटर वाहन चलाकर एक CDL धारक को किस बात पर सहमत माना जाता है?","options":["A vehicle inspection at any weigh station","Chemical testing for alcohol or drugs when lawfully requested","Random employer drug testing only","A waiver of the right to a hearing"],"explanation":"ओक्लाहोमा (Oklahoma) का निहित सहमति कानून किसी भी CMV संचालक को, जब कानूनी रूप से अनुरोध किया जाए, एल्कोहल या नियंत्रित पदार्थों के लिए रासायनिक (साँस, रक्त, या मूत्र) परीक्षण के लिए सहमत माना जाता है। इनकार करने पर अयोग्यता होती है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 47 O.S. Section 753 (implied consent)."},"41":{"q":"ओक्लाहोमा (Oklahoma) में, जब आप एक CDL धारण करते हैं और निहित सहमति कानून द्वारा आवश्यक एल्कोहल या ड्रग परीक्षण से इनकार करते हैं, तो इसे क्या माना जाता है?","options":["A serious traffic violation","A minor administrative infraction","A major offense subject to disqualification","No CDL consequence, only a fine"],"explanation":"एक आवश्यक परीक्षण से इनकार करना ओक्लाहोमा (Oklahoma) में एक प्रमुख अपराध के रूप में वर्गीकृत है, जो एक सकारात्मक परीक्षण के समान अयोग्यता रखता है। पहली बार इनकार करने पर 1-year CDL अयोग्यता होती है। स्रोत: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"42":{"q":"जब प्लेकार्डेड खतरनाक सामग्री का परिवहन नहीं किया जा रहा हो, तब किसी चालक के पहले प्रमुख अपराध (जैसे CMV में DUI) के लिए ओक्लाहोमा (Oklahoma) CDL अयोग्यता अवधि क्या है?","options":["60 days","120 days","1 year","3 years"],"explanation":"पहला प्रमुख अपराध ओक्लाहोमा (Oklahoma) में 1-year CDL अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"43":{"q":"यदि कोई चालक एक ऐसे CMV को संचालित करते समय पहला प्रमुख अपराध करता है जिसके लिए खतरनाक सामग्री के लिए प्लेकार्ड आवश्यक है, तो ओक्लाहोमा (Oklahoma) अयोग्यता अवधि कितनी बढ़ जाती है?","options":["18 months","2 years","3 years","Lifetime"],"explanation":"प्लेकार्डेड खतरनाक सामग्री का परिवहन करते समय किया गया पहला प्रमुख अपराध ओक्लाहोमा (Oklahoma) में अयोग्यता को 1 year से बढ़ाकर 3 years कर देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"44":{"q":"किसी चालक के दूसरे प्रमुख अपराध के लिए ओक्लाहोमा (Oklahoma) CDL अयोग्यता क्या है?","options":["3 years","5 years","10 years","Lifetime"],"explanation":"एक दूसरा प्रमुख अपराध ओक्लाहोमा (Oklahoma) में आजीवन (lifetime) CDL अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 Table 1."},"45":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े अपराध (felony) के निष्पादन में CMV का उपयोग करने पर कौन सा ओक्लाहोमा (Oklahoma) CDL दंड लगता है?","options":["1-year disqualification","3-year disqualification","10-year disqualification","Lifetime disqualification with no reinstatement"],"explanation":"नियंत्रित-पदार्थ निर्माण या वितरण से जुड़े अपराध (felony) में CMV का उपयोग ओक्लाहोमा (Oklahoma) में बिना किसी पुनर्बहाली की संभावना के एक अनिवार्य आजीवन अयोग्यता रखता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"46":{"q":"3-year अवधि के भीतर कितने गंभीर यातायात उल्लंघन ओक्लाहोमा (Oklahoma) में पहली अयोग्यता अवधि को सक्रिय करते हैं, और यह कितनी लंबी होती है?","options":["1 violation; 30 days","2 violations; 60 days","2 violations; 90 days","3 violations; 60 days"],"explanation":"3 years के भीतर एक दूसरा गंभीर यातायात उल्लंघन (CMV में किया गया) ओक्लाहोमा (Oklahoma) में 60-day अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"47":{"q":"3-year अवधि के भीतर किए गए तीसरे गंभीर यातायात उल्लंघन के लिए ओक्लाहोमा (Oklahoma) CDL अयोग्यता क्या है?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर एक तीसरा गंभीर यातायात उल्लंघन ओक्लाहोमा (Oklahoma) में 120-day अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"48":{"q":"निम्न में से कौन सा एक ओक्लाहोमा (Oklahoma) CDL धारक के लिए एक गंभीर यातायात उल्लंघन है?","options":["Parking in a no-parking zone","Speeding 15 mph or more over the posted limit","Driving with an expired registration sticker","Failing to signal a lane change with no traffic present"],"explanation":"अत्यधिक गति (निर्धारित सीमा से 15 mph या अधिक) एक सूचीबद्ध गंभीर यातायात उल्लंघन है। अन्य में लापरवाह ड्राइविंग, अनुचित लेन परिवर्तन, बहुत पास से चलना, और टेक्स्टिंग/हैंडहेल्ड फोन का उपयोग शामिल हैं। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2."},"49":{"q":"CMV चलाते समय टेक्स्टिंग या हैंड-हेल्ड मोबाइल फोन का उपयोग ओक्लाहोमा (Oklahoma) में किस प्रकार के उल्लंघन के रूप में वर्गीकृत है?","options":["A minor moving violation","A serious traffic violation","A major offense","An out-of-service order violation"],"explanation":"CMV चलाते समय टेक्स्टिंग और हैंड-हेल्ड मोबाइल फोन का उपयोग गंभीर यातायात उल्लंघन हैं जो 3 years में 2-या-3 अयोग्यता की ओर गिने जाते हैं। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 2, 392.80 और 392.82."},"50":{"q":"ओक्लाहोमा (Oklahoma) में एक CMV चालक जो CMV चलाते समय हैंड-हेल्ड मोबाइल फोन का उपयोग करते पकड़ा जाता है, उसे अधिकतम कितनी राशि का एक संघीय सिविल दंड (चालक जुर्माना) हो सकता है?","options":["$250","$1,000","$2,750","$11,000"],"explanation":"CMV चलाते समय हैंड-हेल्ड मोबाइल फोन के उपयोग के लिए चालक का जुर्माना $2,750 तक हो सकता है (नियोक्ता जो इसकी अनुमति देते हैं उन पर $11,000 तक का जुर्माना हो सकता है)। स्रोत: 49 CFR 392.82; ओक्लाहोमा (Oklahoma) में लागू FMCSA mobile phone rule."},"51":{"q":"3-year अवधि के भीतर पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए ओक्लाहोमा (Oklahoma) CDL अयोग्यता क्या है?","options":["No less than 60 days","No less than 120 days","No less than 1 year","No less than 3 years"],"explanation":"पहला रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन ओक्लाहोमा (Oklahoma) में 60 days से कम नहीं की अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"52":{"q":"3-year अवधि के भीतर दूसरे रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए ओक्लाहोमा (Oklahoma) CDL अयोग्यता क्या है?","options":["60 days","No less than 120 days","No less than 1 year","No less than 2 years"],"explanation":"3 years के भीतर एक दूसरा रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन ओक्लाहोमा (Oklahoma) में 120 days से कम नहीं की अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"53":{"q":"3-year अवधि के भीतर तीसरे या उसके बाद के रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए ओक्लाहोमा (Oklahoma) CDL अयोग्यता क्या है?","options":["120 days","180 days","No less than 1 year","Lifetime"],"explanation":"3 years के भीतर एक तीसरा या उसके बाद का रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन ओक्लाहोमा (Oklahoma) में 1 year से कम नहीं की अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 3."},"54":{"q":"10-year अवधि के भीतर तीसरे या उसके बाद के आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के लिए ओक्लाहोमा (Oklahoma) CDL अयोग्यता क्या है?","options":["1 year","2 years","No less than 3 years but not more than 5 years","Lifetime"],"explanation":"10 years के भीतर एक तीसरा या उसके बाद का आउट-ऑफ-सर्विस ऑर्डर उल्लंघन ओक्लाहोमा (Oklahoma) में 3 years से कम नहीं परंतु 5 years से अधिक नहीं की अयोग्यता का परिणाम देता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 4."},"55":{"q":"एक ओक्लाहोमा (Oklahoma) CDL धारक को एक ऐसी दुर्घटना के स्थल से भागने का दोषी ठहराया जाता है जिसमें वह जो CMV चला रहा था वह शामिल था। अयोग्यता के प्रयोजनों के लिए इसे कैसे वर्गीकृत किया जाता है?","options":["A serious traffic violation (60-day minimum)","A major offense (1-year minimum, 3 years if hazmat)","An out-of-service order violation","A railroad crossing violation"],"explanation":"एक CMV से जुड़ी दुर्घटना के स्थल से भागना (हिट-एंड-रन) एक प्रमुख अपराध है, जो पहले अपराध के लिए 1-year अयोग्यता (प्लेकार्डेड हैज़मैट होने पर 3 years) और दूसरे के लिए आजीवन रखता है। स्रोत: Oklahoma CDL Driver Manual, Section 1; 49 CFR 383.51 Table 1."},"56":{"q":"ओक्लाहोमा में, जब रुकने के लिए आवश्यक कोई वाणिज्यिक वाहन किसी रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग के पास पहुँचता है, तो चालक को कहाँ रुकना चाहिए?","options":["निकटतम रेल से 5 feet से अधिक पास नहीं और 25 feet से अधिक दूर नहीं","निकटतम रेल से 15 feet से अधिक पास नहीं और 50 feet से अधिक दूर नहीं","निकटतम रेल से 25 feet से अधिक पास नहीं और 75 feet से अधिक दूर नहीं","निकटतम रेल से 10 feet से अधिक पास नहीं और 100 feet से अधिक दूर नहीं"],"explanation":"ओक्लाहोमा CDL मैनुअल (Sections 2.15 और 9.6.12) के अनुसार जिन चालकों को रेलमार्ग क्रॉसिंग पर रुकना ही है, उन्हें निकटतम रेल से 15 से 50 feet के भीतर रुकना चाहिए, और तभी आगे बढ़ना चाहिए जब यह सुनिश्चित हो जाए कि कोई ट्रेन नहीं आ रही। यह ओक्लाहोमा में लागू 49 CFR 392.10 के अनुरूप है।"},"57":{"q":"ओक्लाहोमा नियमों के तहत निम्नलिखित में से किस वाणिज्यिक वाहन को हर रेलमार्ग क्रॉसिंग पर रुकना आवश्यक नहीं है?","options":["यात्रियों को ले जाने वाली एक बस","एक खाली ड्राई-वैन ट्रेलर जिसमें न कोई खतरनाक सामग्री हो और न ही कोई यात्री","खतरनाक सामग्री प्लेकार्ड प्रदर्शित करने वाला एक वाहन","खतरनाक सामग्री के लिए उपयोग किया जाने वाला कार्गो टैंक, चाहे भरा हो या खाली"],"explanation":"ओक्लाहोमा CDL मैनुअल (Section 9.6.12) में उन वाहनों की सूची दी गई है जिन्हें हमेशा रुकना चाहिए: प्लेकार्ड वाले वाहन, क्लोरीन ले जाने वाला कोई भी वाहन, खतरनाक सामग्री के लिए उपयोग किए जाने वाले कार्गो टैंक (भरे या खाली), और यात्रियों वाली बसें। बिना प्लेकार्ड वाली मालवाहक वैन जिसमें कोई यात्री नहीं है, अनिवार्य-रुकने वाली सूची में नहीं है।"},"58":{"q":"ओक्लाहोमा के Move Over कानून के तहत, एक ही दिशा में दो या अधिक लेन वाले राजमार्ग पर चलने वाले चालक को चमकती रोशनी प्रदर्शित करने वाले रुके हुए आपातकालीन वाहन या रेकर के पास पहुँचने पर सबसे पहले क्या करना आवश्यक है?","options":["यदि सुरक्षित रूप से किया जा सके, तो स्थिर वाहन से सटी हुई लेन के अलावा किसी अन्य लेन में बदल जाएँ","आपातकालीन वाहन के जाने तक पूरी तरह रुक जाएँ","आपातकालीन कर्मियों को चेतावनी देने के लिए हॉर्न बजाएँ","गति बनाए रखें लेकिन उसी लेन के भीतर केंद्र रेखा की ओर सरक जाएँ"],"explanation":"ओक्लाहोमा का Move Over कानून (47 O.S. Section 11-314) बहु-लेन सड़क पर चालक से अपेक्षा करता है कि जब सुरक्षित हो, तो वह चमकती रोशनी प्रदर्शित करने वाले स्थिर आपातकालीन वाहन, लाइसेंसशुदा रेकर, या DOT/Turnpike रखरखाव वाहन से सटी हुई लेन के अलावा किसी अन्य लेन में बदल जाए।"},"59":{"q":"ओक्लाहोमा के Move Over कानून के तहत, जब कोई चालक रुके हुए आपातकालीन वाहन से दूर सुरक्षित रूप से लेन नहीं बदल सकता, तो चालक को क्या करना चाहिए?","options":["सभी मामलों में गति को ठीक 20 mph तक कम करें","पूरी तरह रुकें और आगे बढ़ने के संकेत की प्रतीक्षा करें","निर्धारित गति सीमा पर चलते रहें लेकिन फोर-वे फ्लैशर्स का उपयोग करें","मौजूदा सड़क, मौसम और यातायात स्थितियों के लिए सुरक्षित गति तक धीमे हो जाएँ"],"explanation":"ओक्लाहोमा का Move Over कानून (47 O.S. Section 11-314) उस चालक से अपेक्षा करता है जो लेन नहीं बदल सकता कि वह मौजूदा परिस्थितियों के लिए सुरक्षित गति तक धीमा हो जाए। यह कानून किसी एक निश्चित संख्या के बजाय परिस्थिति-आधारित मानक का उपयोग करता है।"},"60":{"q":"यदि किसी प्लेकार्ड वाले वाणिज्यिक वाहन को ओक्लाहोमा में किसी एक-तरफा या विभाजित राजमार्ग पर रुकना पड़े, तो आती हुई ट्रैफ़िक की ओर किन दूरियों पर चेतावनी उपकरण रखे जाने चाहिए?","options":["10 feet, 50 feet, और 150 feet","25 feet, 75 feet, और 250 feet","10 feet, 100 feet, और 200 feet","10 feet, 100 feet, और 500 feet"],"explanation":"ओक्लाहोमा CDL मैनुअल (Section 2, चेतावनी उपकरण) के अनुसार एक-तरफा या विभाजित राजमार्ग पर चेतावनी उपकरण आती हुई ट्रैफ़िक की ओर 10 feet, 100 feet, और 200 feet पर रखे जाने चाहिए।"},"61":{"q":"दोनों दिशाओं में ट्रैफ़िक ले जाने वाली (अविभाजित) दो-लेन ओक्लाहोमा सड़क पर, रुके हुए CMV को अपने तीन चेतावनी उपकरण कहाँ रखने चाहिए?","options":["केवल वाहन के पीछे 10 feet, 100 feet, और 200 feet पर","वाहन के 10 feet के भीतर, और वाहन के 100 feet पीछे और 100 feet आगे","कंधे (shoulder) पर 50 feet, 100 feet, और 200 feet पर","वाहन के 10 feet के भीतर, और वाहन के 200 feet पीछे और 200 feet आगे"],"explanation":"ओक्लाहोमा CDL मैनुअल के अनुसार दो-लेन दो-तरफा या अविभाजित राजमार्ग पर एक उपकरण वाहन के स्थान को चिह्नित करने के लिए वाहन के 10 feet के भीतर रखा जाता है और एक-एक उपकरण वाहन के 100 feet आगे और 100 feet पीछे रखा जाता है।"},"62":{"q":"ओक्लाहोमा में किसी सड़क या कंधे (shoulder) पर रुकने के बाद, CMV चालक को कितने मिनट के भीतर आवश्यक चेतावनी उपकरण रखने चाहिए?","options":["5 मिनट","15 मिनट","30 मिनट","10 मिनट"],"explanation":"ओक्लाहोमा CDL मैनुअल (Section 2) के अनुसार यदि आपको किसी सड़क या किसी सड़क के कंधे पर रुकना पड़े, तो आपको दस मिनट के भीतर अपने आपातकालीन चेतावनी उपकरण रखने होंगे।"},"63":{"q":"वाहन के पार्क किए जाने या खराब होने पर उपयोग के लिए ओक्लाहोमा CMV को कितने चेतावनी उपकरण साथ रखने चाहिए?","options":["दो परावर्तक त्रिकोण, या 4 फ्यूज़, या 2 तरल-जलने वाली flares","चार परावर्तक त्रिकोण, या 8 फ्यूज़, या 4 तरल-जलने वाली flares","एक परावर्तक त्रिकोण, या 3 फ्यूज़, या 1 तरल-जलने वाली flare","तीन परावर्तक त्रिकोण, या 6 फ्यूज़, या 3 तरल-जलने वाली flares"],"explanation":"ओक्लाहोमा CDL मैनुअल पार्क किए गए वाहनों के लिए आवश्यक चेतावनी उपकरणों की सूची तीन लाल परावर्तक त्रिकोण, या कम से कम 6 फ्यूज़, या 3 तरल-जलने वाली flares के रूप में देता है।"},"64":{"q":"ओक्लाहोमा कानून (47 O.S. Section 11-705) के तहत, विपरीत दिशा में चल रहे चालक को लाल रोशनी चमकाते हुए बच्चों को चढ़ाने या उतारने वाली स्कूल बस के लिए कब रुकना आवश्यक नहीं है?","options":["जब बस किसी भी पेंट की गई केंद्र रेखा के दूसरी ओर हो","जब ट्रैफ़िक भारी हो और रुकना असुविधाजनक हो","जब एक केंद्रीय दो-तरफा बाएँ-मोड़ वाली लेन यात्रा की दिशाओं को अलग करती हो","जब सड़क किसी भौतिक अवरोध या बिना पक्की मध्यिका (median) द्वारा विभाजित हो जो यात्रा की दिशाओं को अलग करती हो"],"explanation":"ओक्लाहोमा क़ानून 47 O.S. Section 11-705 विपरीत ट्रैफ़िक को रुकने से केवल तभी छूट देता है जब किसी भौतिक अवरोध या बिना पक्की मध्यिका वाला विभाजित राजमार्ग सड़कों को अलग करता हो। एक पेंट की गई रेखा या केंद्रीय मोड़ वाली लेन इसके योग्य नहीं है, इसलिए उन मामलों में विपरीत ट्रैफ़िक को फिर भी रुकना ही होगा।"},"65":{"q":"एक अविभाजित दो-लेन ओक्लाहोमा राजमार्ग पर, चमकती लाल रोशनी और बढ़ाई गई stop arm वाली रुकी हुई स्कूल बस के सामने आने पर चालक को क्या करना चाहिए?","options":["यात्रा की दिशा चाहे जो भी हो, रुकें, जब तक बस stop arm वापस न ले ले और लाल रोशनी बंद न कर दे","25 mph तक धीमे हो जाएँ और सावधानी से पार करें","केवल तभी रुकें जब बस के समान दिशा में यात्रा कर रहे हों","सामान्य रूप से आगे बढ़ें क्योंकि केवल समान-दिशा वाले ट्रैफ़िक को रुकना है"],"explanation":"47 O.S. Section 11-705 के तहत, अविभाजित राजमार्ग पर दोनों दिशाओं के ट्रैफ़िक को चमकती लाल रोशनी और बढ़ाई गई stop arm प्रदर्शित करने वाली स्कूल बस के लिए रुकना चाहिए, और तब तक रुके रहना चाहिए जब तक बस संकेत वापस न ले ले।"},"66":{"q":"बच्चों को चढ़ाने या उतारने वाली रुकी हुई ओक्लाहोमा स्कूल बस को अवैध रूप से पार करने पर पहली दोषसिद्धि का जुर्माना कितना है?","options":["एकमुश्त $50","न्यूनतम $100 और अधिकतम $500 तक","न्यूनतम $250 और अधिकतम $1,000 तक","एकमुश्त $1,500 और अनिवार्य जेल"],"explanation":"ओक्लाहोमा क़ानून 47 O.S. Section 11-705 रुकी हुई स्कूल बस को गैरकानूनी रूप से पार करने के पहले अपराध के लिए $100 से कम नहीं और $500 तक का जुर्माना निर्धारित करता है, और दोहराए जाने वाले अपराधों के लिए बढ़ते दंड (जिसमें संभावित लाइसेंस निलंबन शामिल है) के साथ।"},"67":{"q":"ओक्लाहोमा के लेन-उपयोग कानून (47 O.S. Section 11-309) के तहत, चार या अधिक लेन वाली सड़क पर कोई वाहन सबसे-बाईं लेन में उचित रूप से कब चल सकता है?","options":["केवल तब जब किसी अन्य वाहन को आगे निकलते और पास करते समय, बाएँ मोड़ की तैयारी करते समय, या जब ट्रैफ़िक/सड़क स्थितियाँ इसकी आवश्यकता हों","किसी भी समय, जब तक चालक निर्धारित गति सीमा बनाए रखे","केवल तब जब दाईं लेन पूरी तरह खाली हों","केवल सूर्योदय और सूर्यास्त के बीच"],"explanation":"ओक्लाहोमा क़ानून 47 O.S. Section 11-309 बाईं लेन को पास करने, बाएँ मोड़ की तैयारी करने, या उन परिस्थितियों तक सीमित करता है जहाँ ट्रैफ़िक प्रवाह या सड़क की बनावट इसकी आवश्यकता हो। कोई वाहन बाईं लेन में धीरे-धीरे चलकर ट्रैफ़िक के सामान्य प्रवाह में बाधा नहीं डाल सकता, भले ही निर्धारित सीमा पर हो।"},"68":{"q":"क़ानून द्वारा अधिकृत के अनुसार ओक्लाहोमा टर्नपाइक के खंडों पर निर्धारित की जा सकने वाली सबसे अधिक गति सीमा क्या है?","options":["85 mph","75 mph","80 mph","70 mph"],"explanation":"47 O.S. Section 11-801 के तहत, ओक्लाहोमा Turnpike Authority टर्नपाइक प्रणाली के अनुमोदित खंडों पर 80 mph तक की गति सीमा निर्धारित कर सकता है। कई हिस्से (उदाहरण के लिए Turner और Indian Nation टर्नपाइक के भाग) 80 mph पर निर्धारित हैं।"},"69":{"q":"ओक्लाहोमा में किसी रेलमार्ग क्रॉसिंग के पास पहुँचते समय, किसी बस या प्लेकार्ड वाले वाहन के चालक को फोर-वे फ्लैशर्स कब चालू करने चाहिए?","options":["क्रॉसिंग से लगभग 200 feet पहले","क्रॉसिंग से लगभग 50 feet पहले","क्रॉसिंग से लगभग 500 feet पहले","केवल क्रॉसिंग पर पूरी तरह रुकने के बाद"],"explanation":"ओक्लाहोमा CDL मैनुअल (Section 10.4, स्कूल बस क्रॉसिंग प्रक्रियाएँ) चालक को निर्देश देता है कि वह क्रॉसिंग से लगभग 200 feet पहले हैज़र्ड लाइट चालू करे ताकि पीछे आ रहे ट्रैफ़िक को आने वाले स्टॉप की चेतावनी मिल सके।"},"70":{"q":"जब किसी ओक्लाहोमा वाणिज्यिक वाहन का कोई भी हिस्सा किसी रेलमार्ग क्रॉसिंग पर हो, तो कौन-सी क्रिया निषिद्ध है?","options":["गियर बदलना या शिफ्ट करना","दोनों हाथ स्टीयरिंग व्हील पर रखना","ट्रेनों के लिए देखना और सुनना","एक स्थिर गति बनाए रखना"],"explanation":"ओक्लाहोमा CDL मैनुअल चालकों को निर्देश देता है कि वे पटरियों को पार करते समय गियर न बदलें, क्योंकि कोई चूका हुआ शिफ्ट वाहन को क्रॉसिंग पर रुका हुआ छोड़ सकता है। चालकों को क्रॉसिंग से पहले एक गियर चुनना चाहिए और पटरियों के पार उसे बनाए रखना चाहिए।"},"71":{"q":"जब कोई ओक्लाहोमा स्कूल बस छात्रों को उतारने के लिए रुकती है, तो बस को स्टॉप पर मौजूद छात्रों से कितनी दूरी पर पूरी तरह रोका जाना चाहिए?","options":["छात्रों से कम से कम 3 feet दूर","छात्रों से कम से कम 25 feet दूर","छात्रों से कम से कम 10 feet दूर","छात्रों से कम से कम 50 feet दूर"],"explanation":"ओक्लाहोमा CDL मैनुअल (Section 13 कौशल परीक्षण, छात्र उतारना) चालक को निर्देश देता है कि वह स्कूल बस को स्टॉप पर मौजूद छात्रों से कम से कम 10 feet दूर पूरी तरह रोके, जिससे छात्र चालक की स्पष्ट दृष्टि में बने रहें।"},"72":{"q":"ODOT से ओवरसाइज़ परमिट आवश्यक होने से पहले किसी वाहन और भार के लिए ओक्लाहोमा की मानक कानूनी अधिकतम चौड़ाई क्या है?","options":["8 feet 0 inches","10 feet 0 inches","8 feet 6 inches","9 feet 6 inches"],"explanation":"ODOT आकार-और-वज़न नियमों के अनुसार, ओक्लाहोमा की कानूनी चौड़ाई सीमा 8 feet 6 inches है; इससे अधिक चौड़े भार के लिए ओवरसाइज़ परमिट आवश्यक है। कानूनी ऊँचाई सीमा 13 feet 6 inches है।"},"73":{"q":"ओक्लाहोमा में ओवरसाइज़-भार की आवाजाही आम तौर पर किस समयावधि तक सीमित होती है?","options":["केवल रात 9:00 बजे और सुबह 5:00 बजे के बीच","दिन के उजाले के घंटे, सूर्योदय से 30 मिनट पहले से सूर्यास्त के 30 मिनट बाद तक","बिना किसी समय प्रतिबंध के दिन में 24 घंटे","केवल सप्ताहांत और छुट्टियों पर"],"explanation":"ODOT ओवरसाइज़-परमिट नियम आवाजाही को दिन के उजाले के घंटों तक सीमित करते हैं, जिसे सूर्योदय से 30 मिनट पहले से सूर्यास्त के 30 मिनट बाद तक परिभाषित किया गया है, और प्रतिकूल मौसम तथा कम दृश्यता के लिए अतिरिक्त प्रतिबंधों के साथ।"},"74":{"q":"ओक्लाहोमा सप्ताह के दिनों के व्यस्त-समय (rush hours) के दौरान किन काउंटियों में Interstate System पर ओवरसाइज़ भार को प्रतिबंधित करता है?","options":["Comanche, Garfield, और Payne काउंटियाँ","Muskogee, Pottawatomie, और Carter काउंटियाँ","Oklahoma, Tulsa, और Cleveland काउंटियाँ","Canadian, Rogers, और Wagoner काउंटियाँ"],"explanation":"ODOT ओवरसाइज़ नियम Oklahoma, Tulsa, और Cleveland काउंटियों में Interstate System पर सप्ताह के दिनों के व्यस्त-समय की अवधियों 7:00-9:00 a.m. और 3:30-6:30 p.m. (Central Time) के दौरान, सोमवार से शुक्रवार तक, ओवरसाइज़ भार पर रोक लगाते हैं।"},"75":{"q":"किसी वाणिज्यिक वाहन में रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की दोषसिद्धि के परिणामस्वरूप ओक्लाहोमा में पहले अपराध के लिए न्यूनतम CDL अयोग्यता कितनी होती है?","options":["कम से कम 30 दिन","कम से कम 120 दिन","कम से कम एक वर्ष","कम से कम 60 दिन"],"explanation":"ओक्लाहोमा CDL मैनुअल (Section 1.3.5) के अनुसार किसी CDL धारक को पहले रेलमार्ग-क्रॉसिंग उल्लंघन के लिए कम से कम 60 दिन, तीन वर्षों के भीतर दूसरे के लिए कम से कम 120 दिन, और तीन वर्षों के भीतर तीसरे के लिए कम से कम एक वर्ष के लिए अयोग्य ठहराया जाता है।"},"76":{"q":"कौन-सी ओक्लाहोमा राज्य एजेंसी वाणिज्यिक चालक लाइसेंस जारी करती है और CDL ज्ञान तथा कौशल परीक्षण का संचालन करती है?","options":["Service Oklahoma","Oklahoma Department of Transportation (ODOT)","Oklahoma Corporation Commission","Oklahoma Tax Commission"],"explanation":"Service Oklahoma (जिसने पहले Department of Public Safety द्वारा संभाली जाने वाली चालक लाइसेंसिंग जिम्मेदारियाँ ले लीं) CDL जारी करता है और अपने Licensing Offices में CDL परीक्षण का संचालन करता है। स्रोत: Service Oklahoma 'Commercial Driving CDL' और 'CDL First-Time Applicants' पृष्ठ (oklahoma.gov)।"},"77":{"q":"ओक्लाहोमा CDL आवेदक आवश्यक दृष्टि और लिखित ज्ञान परीक्षण कहाँ देता है?","options":["किसी Service Oklahoma Licensing Office में व्यक्तिगत रूप से","घर से Service Oklahoma पोर्टल के माध्यम से ऑनलाइन","किसी भी FMCSA Training Provider Registry स्कूल में","किसी Oklahoma Highway Patrol troop मुख्यालय में"],"explanation":"आवेदक CDL प्रक्रिया की शुरुआत किसी Service Oklahoma Licensing Office में व्यक्तिगत रूप से दृष्टि और लिखित ज्ञान परीक्षण देकर करते हैं; दृष्टि और लिखित परीक्षण एक ही अपॉइंटमेंट पर एक साथ कराए जाते हैं। स्रोत: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)।"},"78":{"q":"ओक्लाहोमा आवेदक को CDL कौशल (ड्राइव) परीक्षण देने की अनुमति मिलने से पहले Commercial Learner Permit (CLP) को कितने दिनों तक रखना आवश्यक है?","options":["14 पूरे दिन, 15वें दिन परीक्षण की अनुमति के साथ","30 पूरे दिन, 31वें दिन परीक्षण की अनुमति के साथ","7 पूरे दिन, 8वें दिन परीक्षण की अनुमति के साथ","10 पूरे दिन, 11वें दिन परीक्षण की अनुमति के साथ"],"explanation":"ओक्लाहोमा को कौशल परीक्षण से पहले CLP को 14 पूरे दिन रखना आवश्यक है; आवेदक 15वें दिन परीक्षण दे सकता है। यह संघीय 14-दिन नियम के अनुरूप है। स्रोत: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.25।"},"79":{"q":"ओक्लाहोमा CDL कौशल परीक्षण एक तीन-भाग वाली परीक्षा है। कौन-सा समूह उन तीन भागों को सही ढंग से सूचीबद्ध करता है?","options":["प्री-ट्रिप वाहन निरीक्षण, बुनियादी नियंत्रण कौशल, और ऑन-रोड ड्राइविंग परीक्षण","सामान्य ज्ञान परीक्षण, एयर ब्रेक परीक्षण, और संयोजन वाहन परीक्षण","दृष्टि परीक्षण, लिखित परीक्षण, और एक रक्षात्मक ड्राइविंग पाठ्यक्रम","प्री-ट्रिप निरीक्षण, खतरनाक सामग्री परीक्षण, और एक बैकिंग परीक्षण"],"explanation":"ओक्लाहोमा CDL कौशल परीक्षण तीन भागों से मिलकर बनता है: प्री-ट्रिप वाहन निरीक्षण, बुनियादी नियंत्रण कौशल (जैसे, बैकिंग युक्तियाँ), और ऑन-रोड ड्राइविंग परीक्षण। स्रोत: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov); 49 CFR 383.113।"},"80":{"q":"ओक्लाहोमा द्वारा लागू संघीय Entry-Level Driver Training (ELDT) नियमों के तहत, पहली बार के Class A या Class B आवेदक को किसी अनुमोदित प्रदाता से ELDT पूरा करना चाहिए, इससे पहले कि वह क्या करे?","options":["राज्य-संचालित CDL कौशल परीक्षण देना","Commercial Learner Permit प्राप्त करना","सामान्य ज्ञान लिखित परीक्षण देना","दृष्टि जाँच पूरी करना"],"explanation":"पहली बार के Class A या B CDL के लिए ELDT (सैद्धांतिक और व्हील-के-पीछे) किसी FMCSA Training Provider Registry प्रदाता के माध्यम से पूरा किया जाना चाहिए, इससे पहले कि आवेदक राज्य-संचालित कौशल परीक्षण दे। स्रोत: FMCSA ELDT नियम (49 CFR Part 380); Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)।"},"81":{"q":"प्रशिक्षण की गणना के लिए किसी ओक्लाहोमा CDL आवेदक का Entry-Level Driver Training प्रदाता कहाँ सूचीबद्ध होना चाहिए?","options":["FMCSA की Training Provider Registry (TPR)","Oklahoma Department of Transportation स्कूल सूची","Service Oklahoma अनुमोदित-विक्रेता निर्देशिका","National Registry of Certified Medical Examiners"],"explanation":"ELDT किसी ऐसे प्रदाता से प्राप्त किया जाना चाहिए जो FMCSA की Training Provider Registry (TPR) पर सूचीबद्ध हो। स्रोत: FMCSA ELDT नियम; Service Oklahoma 'Commercial Driving CDL' (oklahoma.gov)।"},"82":{"q":"कौन-सा CDL एंडोर्समेंट ELDT सैद्धांतिक प्रशिक्षण को ज्ञान परीक्षण से पहले (न कि कौशल परीक्षण से) पूरा करना आवश्यक बनाता है?","options":["Hazardous Materials (H) एंडोर्समेंट","Passenger (P) एंडोर्समेंट","School Bus (S) एंडोर्समेंट","Doubles/Triples (T) एंडोर्समेंट"],"explanation":"Hazardous Materials (H) एंडोर्समेंट के लिए, ELDT केवल सैद्धांतिक है और राज्य-संचालित ज्ञान परीक्षण से पहले पूरा किया जाना चाहिए। P और S एंडोर्समेंट को उनके कौशल परीक्षण से पहले ELDT की आवश्यकता होती है। स्रोत: FMCSA ELDT नियम (49 CFR Part 380)।"},"83":{"q":"ओक्लाहोमा CDL आवेदक को अपनी ड्राइविंग के प्रकार की घोषणा करते समय कितनी स्व-प्रमाणन (self-certification) श्रेणियों में से चुनना होता है?","options":["चार","दो","तीन","छह"],"explanation":"आवेदकों को चार श्रेणियों में से एक में स्व-प्रमाणन करना चाहिए: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। स्रोत: Service Oklahoma 'CDL First-Time Applicants' और CDL Self-Certification SOP (oklahoma.gov)।"},"84":{"q":"किस स्व-प्रमाणन श्रेणी में चालक को लाइसेंसिंग के लिए DOT Medical Examiner's Certificate फ़ाइल पर बनाए रखना आवश्यक है?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"केवल Non-Excepted Interstate (NI) श्रेणी में लाइसेंसिंग के लिए DOT Medical Card आवश्यक है। EI, NA, और EA श्रेणियों में Service Oklahoma के पास मेडिकल कार्ड फ़ाइल पर रखने की आवश्यकता नहीं है। स्रोत: Service Oklahoma 'CDL First-Time Applicants' / 'Commercial Driving CDL' (oklahoma.gov)।"},"85":{"q":"रिकॉर्ड-रखरखाव के लिए किसी चालक का DOT Medical Examiner's Certificate अब Service Oklahoma को किस प्रकार भेजा जाता है?","options":["FMCSA National Registry of Certified Medical Examiners से इलेक्ट्रॉनिक रूप से","चालक द्वारा Service Oklahoma मुख्यालय को एक कागज़ी प्रति डाक से भेजकर","नियोक्ता द्वारा इसे स्थानीय Licensing Office को फ़ैक्स करके","काउंटी टैग एजेंसी द्वारा एक नोटरीकृत प्रति अग्रेषित करके"],"explanation":"प्रमाणित मेडिकल परीक्षक प्रमाणपत्र (Form MCSA-5876) को FMCSA National Registry को इलेक्ट्रॉनिक रूप से प्रस्तुत करता है, जो मेडिकल प्रमाणन स्थिति को इलेक्ट्रॉनिक रूप से Service Oklahoma को भेजता है। स्रोत: Service Oklahoma CDL Self-Certification and Medical Certificates Processing SOP (oklahoma.gov); FMCSA National Registry।"},"86":{"q":"वह संघीय Medical Examiner's Certificate किस फ़ॉर्म नंबर का है जिसे कोई प्रमाणित परीक्षक FMCSA National Registry को प्रस्तुत करता है?","options":["MCSA-5876","MCSA-5875","MCSA-5889","MCSA-5870"],"explanation":"Medical Examiner's Certificate FMCSA Form MCSA-5876 है; संबंधित Medical Examination Report MCSA-5875 है। परीक्षक MCSA-5876 परिणाम को National Registry को प्रस्तुत करता है। स्रोत: Service Oklahoma Medical Certificates Processing SOP; FMCSA।"},"87":{"q":"किसी ओक्लाहोमा Non-Excepted Interstate (NI) CDL धारक को आमतौर पर कम से कम कितनी बार एक वर्तमान DOT Medical Examiner's Certificate प्रदान करना होता है (FMCSA मानकों के तहत परीक्षाओं के बीच अधिकतम अंतराल)?","options":["हर 24 महीने","हर 12 महीने","हर 36 महीने","हर 60 महीने"],"explanation":"एक मानक मेडिकल परीक्षक प्रमाणपत्र अधिकतम 24 महीनों के लिए वैध होता है, इसलिए NI चालकों के पास उस चक्र के भीतर एक वर्तमान प्रमाणपत्र फ़ाइल पर होना चाहिए (कुछ स्थितियों के लिए कम अंतराल लागू होते हैं)। स्रोत: Service Oklahoma CDL मेडिकल मार्गदर्शन; 49 CFR 391.45।"},"88":{"q":"यदि Service Oklahoma को सूचित किया जाता है कि किसी CDL धारक का मेडिकल प्रमाणन समाप्त हो गया है या अब वैध नहीं है, तो संघीय नियम के तहत एजेंसी को कितने दिनों के भीतर CDL को डाउनग्रेड करना होगा?","options":["60 दिनों के भीतर","10 दिनों के भीतर","30 दिनों के भीतर","90 दिनों के भीतर"],"explanation":"Service Oklahoma सहित राज्य चालक लाइसेंसिंग एजेंसियों को यह जानने के 60 दिनों के भीतर CDL को डाउनग्रेड करना चाहिए कि चालक अब चिकित्सकीय रूप से प्रमाणित नहीं है या मेडिकल प्रमाणपत्र समाप्त हो गया है और नवीनीकृत नहीं हुआ। स्रोत: Service Oklahoma डाउनग्रेड मार्गदर्शन; 49 CFR 383.73(o)।"},"89":{"q":"ओक्लाहोमा क़ानून के तहत, Commercial Learner Permit (CLP) शुरू में कितने समय के लिए वैध होता है?","options":["180 दिन","90 दिन","60 दिन","1 वर्ष"],"explanation":"ओक्लाहोमा CLP को 180 दिनों की अवधि के लिए जारी करता है; इसे एक अतिरिक्त 180 दिनों के लिए एक बार नवीनीकृत किया जा सकता है। स्रोत: 47 O.S. Section 6-101; Service Oklahoma CLP मार्गदर्शन।"},"90":{"q":"किसी ओक्लाहोमा CLP को एक बार नवीनीकृत किया जा सकता है। वह एकल नवीनीकरण कितने समय के लिए वैध होता है?","options":["एक अतिरिक्त 180 दिन","एक अतिरिक्त 30 दिन","एक अतिरिक्त 1 वर्ष","एक अतिरिक्त 90 दिन"],"explanation":"CLP 180 दिनों के लिए वैध होता है और इसे एक बार एक अतिरिक्त 180 दिनों के लिए नवीनीकृत किया जा सकता है, जिससे कुल मिलाकर एक वर्ष तक की अनुमति मिलती है। स्रोत: 47 O.S. Section 6-101; Service Oklahoma CLP मार्गदर्शन।"},"91":{"q":"INTRASTATE (केवल ओक्लाहोमा-भीतर) वाणिज्यिक ड्राइविंग के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","16 वर्ष","19 वर्ष"],"explanation":"किसी आवेदक की आयु CMV को intrastate (ओक्लाहोमा के भीतर) चलाने के लिए कम से कम 18 और interstate चलाने के लिए कम से कम 21 होनी चाहिए। स्रोत: Service Oklahoma CDL मार्गदर्शन; 47 O.S. Section 6-101।"},"92":{"q":"एक 19 वर्षीय ओक्लाहोमा CDL धारक जो अभी 21 वर्ष का नहीं हुआ है, आमतौर पर किस तरह सीमित होता है?","options":["केवल intrastate (ओक्लाहोमा-भीतर) वाणिज्यिक ड्राइविंग तक","केवल Class C वाणिज्यिक वाहन चलाने तक","केवल दिन के समय वाणिज्यिक ड्राइविंग तक","केवल किसी लाइसेंसशुदा CDL धारक की उपस्थिति में ड्राइविंग तक"],"explanation":"18 से 20 वर्ष की आयु के चालक CDL रख सकते हैं लेकिन वे intrastate (ओक्लाहोमा-भीतर) वाणिज्यिक संचालन तक सीमित होते हैं; interstate संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Service Oklahoma CDL मार्गदर्शन; 49 CFR 383.3 / 391.11।"},"93":{"q":"कौन-सा दस्तावेज़ उन दस्तावेज़ों में शामिल नहीं है जिन्हें पहली बार के ओक्लाहोमा CDL आवेदक को Service Oklahoma Licensing Office में प्रस्तुत करना आवश्यक है?","options":["रोड टेस्ट को अधिकृत करने वाला नियोक्ता का पत्र","पहचान और वैध उपस्थिति का प्रमाण","ओक्लाहोमा निवास का प्रमाण (पते का एक प्रमाण)","एक वैध Oklahoma Class D चालक लाइसेंस"],"explanation":"आवश्यक वस्तुओं में पहचान और वैध उपस्थिति का प्रमाण, निवास/पते का प्रमाण, एक वैध Oklahoma Class D लाइसेंस, और एक Social Security number शामिल हैं; नियोक्ता प्राधिकरण पत्र आवश्यक नहीं है। स्रोत: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)।"},"94":{"q":"ओक्लाहोमा CDL नवीनीकरण के संबंध में, प्रक्रिया के बारे में कौन-सा कथन सटीक है?","options":["पात्र CDL धारक ऑनलाइन नवीनीकरण कर सकते हैं, लेकिन Hazardous Materials (H) धारकों को व्यक्तिगत रूप से नवीनीकरण करना चाहिए और HazMat लिखित परीक्षण के साथ-साथ TSA पृष्ठभूमि जाँच फिर से देनी चाहिए","HazMat सहित सभी CDL नवीनीकरण पूरी तरह ऑनलाइन पूरे किए जा सकते हैं","CDL नवीनीकृत नहीं किए जा सकते और हर चक्र में शुरू से फिर से परीक्षण किया जाना चाहिए","नवीनीकरण के लिए हर बार पूरा तीन-भाग वाला कौशल परीक्षण फिर से देना आवश्यक है"],"explanation":"Service Oklahoma पात्र धारकों के लिए ऑनलाइन CDL नवीनीकरण प्रदान करता है, लेकिन Hazardous Materials एंडोर्समेंट धारकों को व्यक्तिगत रूप से नवीनीकरण करना चाहिए, HazMat ज्ञान परीक्षण फिर से देना चाहिए, और प्रत्येक नवीनीकरण पर TSA पृष्ठभूमि जाँच पूरी करनी चाहिए। (ध्यान दें: सटीक शुल्क और चुनी गई क्रेडेंशियल अवधि, जैसे 4-वर्ष बनाम 8-वर्ष विकल्प, बदल सकते हैं।) स्रोत: Service Oklahoma 'CDL Renewal/Replacement Online' (oklahoma.gov)।"}},"ar":{"0":{"q":"على الطرق السريعة في أوكلاهوما، ما هو أقصى عرض خارجي إجمالي للمركبة، بحمولة أو بدونها، قبل أن يصبح تصريح زيادة العرض مطلوبًا؟","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"تحدد أوكلاهوما العرض الخارجي الإجمالي بـ 102 inches (8.5 ft)؛ ويتطلب العرض الأكبر تصريح زيادة العرض. المصدر: 47 O.S. §14-103."},"1":{"q":"ما هو أقصى ارتفاع قانوني للمركبة أو الحمولة على طريق برسوم أو طريق سريع بين الولايات أو طريق سريع أمريكي أو طريق سريع تابع للولاية في أوكلاهوما دون تصريح خاص؟","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"تسمح أوكلاهوما بارتفاع يصل إلى 14 feet على الطرق ذات الرسوم والطرق السريعة بين الولايات والطرق السريعة الأمريكية والطرق السريعة التابعة للولاية دون تصريح. المصدر: 47 O.S. §14-103."},"2":{"q":"ما هو أقصى ارتفاع للمركبة أو الحمولة على طريق المقاطعة (COUNTY) في أوكلاهوما دون تصريح خاص؟","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"على طرق المقاطعات يكون حد الارتفاع 13.5 feet، وهو أقل من حد 14-foot المسموح به على الطرق ذات الرسوم والطرق السريعة بين الولايات والطرق السريعة الأمريكية والطرق السريعة التابعة للولاية. المصدر: 47 O.S. §14-103."},"3":{"q":"في أوكلاهوما، ما هو أقصى وزن مسموح به على أي محور مفرد دون تصريح زيادة الوزن؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"حد وزن المحور المفرد في أوكلاهوما هو 20,000 pounds. المصدر: 47 O.S. §14-109(A)."},"4":{"q":"ما هو أقصى وزن تسمح به أوكلاهوما على مجموعة من المحاور الترادفية دون تصريح خاص؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"الحمولة القصوى على أي مجموعة من المحاور الترادفية في أوكلاهوما هي 34,000 pounds. المصدر: 47 O.S. §14-109(B)."},"5":{"q":"ما هو الحد الأقصى العام لإجمالي وزن المركبة على الطرق السريعة في أوكلاهوما بموجب جدول الأوزان دون تصريح خاص؟","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"يحدد جدول الأوزان في أوكلاهوما الوزن الإجمالي القانوني بحد أقصى 80,000 pounds، بما يتوافق مع الحد الفيدرالي. المصدر: 47 O.S. §14-109(A)."},"6":{"q":"تُحدَّد الأوزان الإجمالية وأوزان المحاور المسموح بها في أوكلاهوما باستخدام معادلة تستند إلى تباعد المحاور. ماذا تُسمى هذه المعادلة عادةً؟","options":["Federal Bridge Formula","Gross Combination Rule","Tare Weight Formula","Axle Spread Ratio"],"explanation":"تستخدم أوكلاهوما معادلة الجسر الفيدرالية/جدول الأوزان (23 U.S.C. §127)، بقياس المسافة بين المحاور الطرفية إلى أقرب قدم. المصدر: 47 O.S. §14-109؛ ODPS Troop S."},"7":{"q":"ما هو أقصى طول إجمالي لشاحنة مفردة (وليست مجموعة مركبات)، بما في ذلك المصدّات، على الطرق في أوكلاهوما؟","options":["40 feet","45 feet","53 feet","70 feet"],"explanation":"لا يجوز أن يتجاوز طول الشاحنة المفردة 45 feet من الطول الإجمالي، بما في ذلك المصدّات الأمامية والخلفية، في أوكلاهوما. المصدر: 47 O.S. §14-103."},"8":{"q":"على الشبكة الوطنية، ما هو أقصى طول لنصف المقطورة في مجموعة جرّار-شاحنة/نصف مقطورة في أوكلاهوما (دون تصريح)؟","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"يمكن أن يصل طول نصف المقطورة في مجموعة جرّار-شاحنة/نصف مقطورة إلى 53 feet على الشبكة الوطنية؛ ويتطلب الطول الأكبر (حتى 59'6\") تصريحًا. المصدر: 47 O.S. §14-103."},"9":{"q":"ما هو أقصى طول إجمالي لمجموعات المركبات بخلاف جرّار-شاحنة/نصف مقطورة على جميع الطرق والطرق السريعة في أوكلاهوما؟","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"لا يجوز أن تتجاوز مجموعات المركبات الأخرى 70 feet من الطول الإجمالي، بما في ذلك المصدّات، على جميع الطرق والطرق السريعة في أوكلاهوما. المصدر: 47 O.S. §14-103."},"10":{"q":"أي قسم من أقسام الجهات الحكومية في أوكلاهوما يصدر تصاريح الحجم الزائد/الوزن الزائد للسفر على شبكة الطرق السريعة التابعة للولاية؟","options":["The Oklahoma Tax Commission","The ODOT Size and Weight Permit Division","The Corporation Commission","The county sheriff's office"],"explanation":"يصدر قسم تصاريح الحجم والوزن التابع لـ ODOT (ODOT Size and Weight Permit Division) تصاريح الحجم الزائد/الوزن الزائد (يُقدَّم الطلب عبر الإنترنت على swpermitsok.com). المصدر: ODOT؛ OAC 730:50-5."},"11":{"q":"يجوز لمجموعة شاحنة ونصف مقطورة العمل بموجب تصريح سنوي خاص لزيادة العرض في أوكلاهوما حتى أي عرض أقصى؟","options":["108 inches","114 inches","120 inches","144 inches"],"explanation":"يجوز للمجموعات التي يتجاوز عرضها 102 ولكن لا يتجاوز 120 inches العمل بموجب تصريح سنوي خاص لزيادة العرض. المصدر: OAC 730:50-5؛ 47 O.S. §14-103G."},"12":{"q":"بموجب قواعد أوكلاهوما، يجب أن تكون لدى الحمولة المصرَّح بها التي يزيد عرضها عن 12 feet ولكن لا يزيد عن 14 feet أي ترتيب مرافقة على طريق سريع ذي مسارين؟","options":["No escort required","A front escort vehicle","A rear escort vehicle","Both front and rear escorts"],"explanation":"تحتاج الحمولات التي يزيد عرضها عن 12 ft ولكن لا يزيد عن 14 ft إلى مركبة مرافقة أمامية على الطرق السريعة ذات المسارين/الطرق السريعة الفائقة ذات المسارين (ومرافقة خلفية على الطرق متعددة المسارات). المصدر: OAC 730:50-5-18(b)."},"13":{"q":"عند أي ارتفاع إجمالي تتطلب الحمولة المصرَّح بها في أوكلاهوما مركبتي مرافقة (واحدة أمامية وواحدة خلفية) وإشعارًا مسبقًا لشركات المرافق وشركات السكك الحديدية؟","options":["14 feet or more","14 feet 6 inches or more","15 feet or more","15 feet 9 inches or more"],"explanation":"تتطلب الحمولات ذات الارتفاع الإجمالي البالغ 15 feet 9 inches أو أكثر مركبتي مرافقة واتصالًا مسبقًا بشركات المرافق/السكك الحديدية المتأثرة. المصدر: OAC 730:50-5-18(b)."},"14":{"q":"ما هو الطول الإجمالي لمجموعة جرّار-شاحنة/نصف مقطورة الذي يستوجب مركبة مرافقة أمامية على الطرق السريعة ذات المسارين في أوكلاهوما؟","options":["More than 70 feet","More than 75 feet","More than 80 feet","More than 100 feet"],"explanation":"تتطلب مجموعة جرّار-شاحنة/نصف مقطورة يزيد طولها الإجمالي عن 80 feet مركبة مرافقة أمامية على الطرق السريعة ذات المسارين. المصدر: OAC 730:50-5-18(b)(4)."},"15":{"q":"بموجب تباين وزن المنتجات الزراعية في أوكلاهوما (وفقًا لـ ODPS Troop S)، ما هي حدود التسامح المطبقة، وأين يُحظر السفر؟","options":["5% over gross and 8% over axle limits; not on interstate highways","10% over gross and 10% over axle; not on turnpikes","8% over gross and 5% over axle; not on county roads","5% over gross and 5% over axle; interstate allowed"],"explanation":"يجوز للمركبات التي تنقل المنتجات الزراعية بالحد الأقصى للتسجيل تجاوز حدود الوزن الإجمالي بنسبة تصل إلى 5% وحدود المحاور بنسبة تصل إلى 8%، ولكن ليس على نظام الطرق السريعة بين الولايات. المصدر: ODPS Troop S؛ 47 O.S. §14-109."},"16":{"q":"مع تصريح تباين الوزن الزراعي الذي يسمح بنحو 8% فوق حد المحور، يصبح رقم المحور المفرد البالغ 20,000 pounds نحو كم تقريبًا؟","options":["20,800 pounds","21,600 pounds","22,400 pounds","24,000 pounds"],"explanation":"مع التباين (8% فوق المحور)، يصبح حد المحور المفرد البالغ 20,000-lb مقداره 21,600 lbs؛ وتجاوز أي فئة يُبطل التصريح لتلك الرحلة. المصدر: ODPS Troop S axle table."},"17":{"q":"يُجيز تصريح المركبة السنوي الشامل (Annual Envelope Vehicle Permit) الصادر عن ODOT في أوكلاهوما لمركبة الوصول إلى أي أبعاد قصوى على شبكة الطرق السريعة التابعة للولاية؟","options":["10 ft wide, 13.5 ft high, 90 ft long","12 ft wide, 14 ft high, 110 ft long","14 ft wide, 15 ft high, 120 ft long","12 ft wide, 16 ft high, 100 ft long"],"explanation":"يغطي تصريح المركبة السنوي الشامل المركبات التي يصل عرضها إلى 12 ft وارتفاعها إلى 14 ft وطولها إلى 110 ft (رسم $4,000)، وهو صالح فقط على شبكة الطرق السريعة التابعة للولاية. المصدر: OAC 730:50-5-13."},"18":{"q":"يجوز لناقلي المنتجات الحرجية الخام بحالتها الطبيعية في أوكلاهوما الحصول على تصريح زراعي سنوي بقيمة $25، ولكن مع أي قيد على المسار؟","options":["No travel on the Interstate system","No travel on any turnpike","No travel on county roads","No travel at night only"],"explanation":"لا يُسمح بنقل المنتجات الحرجية الخام بموجب التصريح الزراعي السنوي بقيمة $25 على النظام الوطني للطرق السريعة بين الولايات والدفاع. المصدر: OAC 730:50-5-22؛ 47 O.S. §14-118(e)."},"19":{"q":"في أوكلاهوما، أي فئة من فئات CDL مطلوبة لتشغيل أي مجموعة مركبات ذات تصنيف وزن إجمالي مركّب (GCWR) يبلغ 26,001 رطلًا أو أكثر عندما تكون المركبة المقطورة ذات تصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 رطل؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تتبنى أوكلاهوما التصنيف الفيدرالي: تغطي رخصة CDL من الفئة Class A أي مجموعة مركبات ذات GCWR يبلغ 26,001+ lbs حيث تتجاوز الوحدة (الوحدات) المقطورة 10,000 lbs من GVWR. المصدر: Oklahoma Statutes Title 47 Sec. 6-101 ودليل CDL في أوكلاهوما (Service Oklahoma)."},"20":{"q":"يقود سائق في أوكلاهوما شاحنة مستقيمة مفردة ذات GVWR يبلغ 30,000 رطل ولا تقطر أي مقطورة. أي فئة من فئات CDL يتطلبها ذلك؟","options":["Class A","Class B","Class C","No CDL is required"],"explanation":"تغطي رخصة CDL من الفئة Class B أي مركبة مفردة ذات GVWR يبلغ 26,001+ lbs (أو مثل هذه المركبة التي تقطر وحدة لا تتجاوز 10,000 lbs من GVWR). تقع الشاحنة المستقيمة البالغة 30,000-lb ضمن الفئة Class B. المصدر: دليل CDL في أوكلاهوما (Service Oklahoma)؛ 47 O.S. Sec. 6-101."},"21":{"q":"بموجب قواعد أوكلاهوما، فإن المركبة التي لا تستوفي حدود الوزن للفئة Class A أو Class B لا تزال تتطلب رخصة CDL من الفئة Class C إذا كانت تفعل ماذا؟","options":["Has a GVWR over 16,000 pounds","Is designed to transport 16 or more people including the driver, or carries placardable hazardous materials","Tows any trailer rated over 5,000 pounds","Is operated for hire across county lines"],"explanation":"تنطبق رخصة CDL من الفئة Class C على المركبة التي لا تستوفي الفئة Class A أو B والمصمَّمة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو التي تحمل مواد خطرة تتطلب لوحات تحذيرية. المصدر: دليل CDL في أوكلاهوما (Service Oklahoma)؛ 47 O.S. Sec. 6-101."},"22":{"q":"أي رمز تصديق يجب إضافته إلى رخصة CDL في أوكلاهوما لنقل المواد المصنَّفة على أنها خطرة وتتطلب لوحات تحذيرية؟","options":["N","T","H","P"],"explanation":"تصديق H (المواد الخطرة) مطلوب لنقل المواد الخطرة التي تتطلب لوحات تحذيرية. المصدر: تصديقات وقيود CDL في أوكلاهوما (Service Oklahoma)."},"23":{"q":"ما هو حد السعة الفيدرالي/في أوكلاهوما الذي يُعرِّف 'مركبة الصهريج' التي تتطلب تصديق N (الصهريج)؟","options":["A tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more","A tank with an individual rated capacity of more than 100 gallons","Any tank carrying 500 gallons or more total","A tank with an aggregate capacity of 2,000 gallons or more"],"explanation":"تصديق N مطلوب للمركبات التي تنقل السوائل أو الغازات في صهريج ذي سعة مقدَّرة فردية تزيد عن 119 gallons وسعة مقدَّرة إجمالية تبلغ 1,000 gallons أو أكثر. المصدر: تصديقات وقيود CDL في أوكلاهوما (Service Oklahoma)؛ 49 CFR 383.5."},"24":{"q":"أي تصديق CDL في أوكلاهوما مطلوب لقطر مقطورات مزدوجة أو ثلاثية، وأي فئة CDL يجب أن يحملها السائق بالفعل؟","options":["T endorsement, held with a Class A CDL","T endorsement, held with a Class B CDL","N endorsement, held with a Class A CDL","P endorsement, held with a Class C CDL"],"explanation":"يسمح تصديق T (المزدوجة/الثلاثية) بقطر عدة مقطورات ويضيفه سائقو الفئة Class A، الذين يجب أن يثبتوا المعرفة الإضافية المطلوبة. المصدر: تصديقات وقيود CDL في أوكلاهوما (Service Oklahoma)."},"25":{"q":"يرغب سائق في أوكلاهوما في قيادة مركبة مصمَّمة لنقل 16 شخصًا أو أكثر بما في ذلك السائق. أي تصديق مطلوب؟","options":["S (School Bus)","P (Passenger)","N (Tanker)","T (Doubles/Triples)"],"explanation":"تصديق P (الركاب) مطلوب لتشغيل مركبة مصمَّمة لنقل 16 شخصًا أو أكثر بما في ذلك السائق؛ ويتطلب اجتياز اختبار معرفي واختبار مهارات في مركبة ممثِّلة. المصدر: تصديقات وقيود CDL في أوكلاهوما (Service Oklahoma)."},"26":{"q":"قبل أن يتمكن سائق في أوكلاهوما من الحصول على تصديق الحافلة المدرسية (S)، أي تصديق آخر يُعد شرطًا مسبقًا؟","options":["The H (HazMat) endorsement","The N (Tanker) endorsement","The P (Passenger) endorsement","The T (Doubles/Triples) endorsement"],"explanation":"يتطلب تصديق S (الحافلة المدرسية) أن يحمل السائق أولًا تصديق P (الركاب)، ثم اجتياز اختبار معرفي للحافلة المدرسية واختبار مهارات في حافلة مدرسية. المصدر: دليل/تصديقات CDL في أوكلاهوما (Service Oklahoma)؛ 49 CFR 383.93."},"27":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في أوكلاهوما مقيَّدة بالتشغيل داخل الولاية (ضمن أوكلاهوما) فقط؟","options":["16","18","21","25"],"explanation":"يجب أن يكون عمر السائق 18 على الأقل لحمل رخصة CDL داخل الولاية فقط في أوكلاهوما؛ ويحصل السائقون دون 21 على قيد 'K' للتشغيل داخل الولاية فقط. المصدر: دليل CDL في أوكلاهوما (Service Oklahoma)؛ 47 O.S. Sec. 6-101."},"28":{"q":"ما هو الحد الأدنى للعمر المطلوب لتشغيل مركبة CDL في التجارة بين الولايات (عبر حدود الولايات) انطلاقًا من أوكلاهوما؟","options":["18","19","21","23"],"explanation":"يتطلب تشغيل CDL بين الولايات حدًا أدنى للعمر يبلغ 21؛ ويقتصر السائقون من 18 إلى 20 على التشغيل داخل الولاية ضمن أوكلاهوما. المصدر: دليل CDL في أوكلاهوما (Service Oklahoma)؛ 49 CFR 391.11."},"29":{"q":"بعد اجتياز الاختبارات المعرفية المطلوبة في أوكلاهوما، كم من الوقت يجب أن يحمل مقدم الطلب تصريح المتعلم التجاري (CLP) قبل خوض اختبار مهارات CDL (القيادة)؟","options":["7 full days","10 full days","14 full days","30 full days"],"explanation":"تتطلب القواعد الفيدرالية وقواعد أوكلاهوما حمل تصريح CLP لمدة 14 full days قبل اختبار المهارات؛ ويمكن خوض الاختبار في اليوم الخامس عشر. المصدر: مقدمو طلبات CDL لأول مرة في أوكلاهوما (Service Oklahoma)؛ 49 CFR 383.25."},"30":{"q":"إلى متى يكون تصريح المتعلم التجاري (CLP) في أوكلاهوما صالحًا، وكيف يمكن تمديده؟","options":["90 days, non-renewable","180 days, renewable one time for an additional 180 days","1 year, renewable annually","60 days, renewable up to three times"],"explanation":"يُصدر تصريح CLP في أوكلاهوما لمدة 180 days ويمكن تجديده مرة واحدة لمدة إضافية قدرها 180 days. المصدر: دليل CDL في أوكلاهوما / Service Oklahoma؛ 49 CFR 383.25."},"31":{"q":"أي مجموعة من المستندات يجب أن يقدمها مقدم طلب CDL لأول مرة في أوكلاهوما في مكتب ترخيص Service Oklahoma؟","options":["Only a valid Class D license and a birth certificate","Proof of identity, proof of lawful presence, Social Security number, and proof of Oklahoma residency","Only a Social Security card and an employer letter","A passport and proof of vehicle insurance"],"explanation":"يتطلب Service Oklahoma إثبات الهوية والوجود القانوني ورقم الضمان الاجتماعي (SSN) لمقدم الطلب والإقامة في أوكلاهوما (مستند إقامة واحد قياسيًا، ومستندان لـ REAL ID)، بالإضافة إلى رخصة سارية من الفئة Class D. المصدر: مقدمو طلبات CDL لأول مرة في أوكلاهوما (Service Oklahoma)."},"32":{"q":"يجب إكمال تدريب السائق المبتدئ (ELDT) لمقدم طلب CDL لأول مرة في أوكلاهوما من خلال أي نظام رسمي؟","options":["The Oklahoma Department of Education portal","The FMCSA Training Provider Registry","The TSA Hazmat Threat Assessment Program","The Oklahoma Tax Commission registry"],"explanation":"يجب أن يقدِّم تدريب ELDT مدرسة مدرجة في سجل مقدمي التدريب التابع لـ FMCSA (FMCSA Training Provider Registry)، الذي يُبلِّغ عن الإكمال إلكترونيًا. المصدر: قاعدة ELDT الصادرة عن FMCSA (49 CFR Part 380)؛ مقدمو طلبات CDL لأول مرة في أوكلاهوما (Service Oklahoma)."},"33":{"q":"أي مما يلي يتطلب تدريب ELDT (تدريب السائق المبتدئ) قبل اختبار المهارات/المعرفة بموجب قواعد FMCSA المطبَّقة في أوكلاهوما؟","options":["Obtaining the Tanker (N) endorsement","Obtaining the Doubles/Triples (T) endorsement","Obtaining the Passenger (P) or School Bus (S) endorsement for the first time","Renewing an existing Class A CDL"],"explanation":"تدريب ELDT مطلوب لرخصة CDL من الفئة Class A أو B لأول مرة، وللترقية من B إلى A، ولتصديقات H أو P أو S لأول مرة. تصديقا N و T غير خاضعين لـ ELDT. المصدر: قاعدة ELDT الصادرة عن FMCSA (49 CFR Part 380)؛ Service Oklahoma."},"34":{"q":"بالنسبة لتصديق المواد الخطرة (H)، مما يتكون شرط ELDT المطبَّق في أوكلاهوما؟","options":["Theory instruction only","Behind-the-wheel instruction only","Both theory and behind-the-wheel instruction","No training at all"],"explanation":"تدريب ELDT لتصديق H نظري فقط؛ ووحدها رخص CDL من الفئتين A/B وتصديقا P و S تتطلب كلًا من التدريب النظري والتدريب خلف المقود. المصدر: قاعدة ELDT الصادرة عن FMCSA (49 CFR Part 380)."},"35":{"q":"بالإضافة إلى اجتياز اختبار معرفة المواد الخطرة، ماذا يحتاج السائق في أوكلاهوما للحصول على تصديق H أو الاحتفاظ به؟","options":["A TSA security threat assessment (background check) that is valid for 5 years","A second skills test in a tank vehicle","A notarized employer sponsorship letter","A separate state HazMat permit renewed annually"],"explanation":"يتطلب تصديق H تقييمًا أمنيًا للتهديد من TSA (التحقق من الخلفية/بصمات الأصابع)؛ والموافقة صالحة لمدة 5 years ويجب تجديدها مع التصديق. المصدر: TSA HTAP؛ 49 CFR 1572؛ Service Oklahoma CDL."},"36":{"q":"أي رمز تصديق يُصدر على رخصة CDL في أوكلاهوما لسائق مخوَّل بتشغيل مركبة صهريج تحمل مواد خطرة تتطلب لوحات تحذيرية (مواد خطرة وصهريج مدمجان)؟","options":["HN","X","T","Z"],"explanation":"تُصدر أوكلاهوما رمز التصديق المدمج 'X' للسائقين الذين يحملون صلاحية كل من الصهريج (N) والمواد الخطرة (H). المصدر: تصديقات وقيود CDL في أوكلاهوما (Service Oklahoma)؛ 49 CFR 383.153."},"37":{"q":"كم عدد فئات الإقرار الذاتي الطبي التي يختار منها مقدم طلب CDL في أوكلاهوما، وأي منها يتطلب شهادة فاحص طبي معتمد من DOT؟","options":["Two categories; the Excepted Interstate category requires the medical card","Four categories; the Non-Excepted Interstate (NI) category requires the medical card","Three categories; the Non-Excepted Intrastate category requires the medical card","Four categories; the Excepted Intrastate (EA) category requires the medical card"],"explanation":"هناك أربع فئات للإقرار الذاتي (NI, EI, NA, EA). وحدهم سائقو الفئة Non-Excepted Interstate (NI) يجب أن يقدّموا شهادة فاحص طبي سارية من DOT ويحتفظوا بها. المصدر: مقدمو طلبات CDL لأول مرة في أوكلاهوما (Service Oklahoma)؛ 49 CFR 383.71."},"38":{"q":"تحمل رخصة CDL أو تصريح CLP في أوكلاهوما أي رمز قيد عندما لا يجوز لحاملها تشغيل المركبات التجارية خارج ولاية أوكلاهوما؟","options":["E","L","K","Z"],"explanation":"يعني القيد 'K' داخل الولاية فقط - لا يمكن للسائق مغادرة أوكلاهوما في مركبة CDL (يُطبَّق عادةً على السائقين دون 21). 'E' = لا ناقل حركة يدوي، 'L' = لا فرامل هوائية، 'Z' = لا فرامل هوائية كاملة. المصدر: تصديقات وقيود CDL في أوكلاهوما (Service Oklahoma)."},"39":{"q":"أثناء تشغيل مركبة آلية تجارية (CMV) في أوكلاهوما، يُعتبر السائق ضعيفًا قانونيًا ويرتكب مخالفة كبرى عند أي تركيز للكحول في الدم (BAC)؟","options":["0.02 or greater","0.04 or greater","0.08 or greater","0.10 or greater"],"explanation":"تحدد أوكلاهوما حد BAC للمركبة التجارية CMV بـ 0.04 أو أكثر، أي نصف حد 0.08 للسائقين غير التجاريين. تشغيل CMV عند 0.04 أو أعلى مخالفة كبرى. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1 (إسقاط أهلية السائقين)؛ 49 CFR 383.51 بصيغته المعتمدة في أوكلاهوما."},"40":{"q":"بموجب قانون الموافقة الضمنية في أوكلاهوما، يُعتبر حامل رخصة CDL، بقيادته مركبة آلية تجارية، أنه قد وافق على ماذا؟","options":["A vehicle inspection at any weigh station","Chemical testing for alcohol or drugs when lawfully requested","Random employer drug testing only","A waiver of the right to a hearing"],"explanation":"يَعتبر قانون الموافقة الضمنية في أوكلاهوما أي شخص يشغّل مركبة CMV قد وافق على الفحص الكيميائي (النفَس أو الدم أو البول) للكحول أو المواد الخاضعة للرقابة عند الطلب القانوني. ويؤدي الرفض إلى إسقاط الأهلية. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 47 O.S. Section 753 (الموافقة الضمنية)."},"41":{"q":"في أوكلاهوما، يُعامَل رفض الخضوع لفحص الكحول أو المخدرات كما يقتضيه قانون الموافقة الضمنية أثناء حملك رخصة CDL على أنه ماذا؟","options":["A serious traffic violation","A minor administrative infraction","A major offense subject to disqualification","No CDL consequence, only a fine"],"explanation":"يُصنَّف رفض الفحص المطلوب على أنه مخالفة كبرى في أوكلاهوما، ويحمل إسقاط الأهلية نفسه المترتب على النتيجة الإيجابية. ويؤدي الرفض الأول إلى إسقاط أهلية CDL لمدة 1-year. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1 (إسقاط أهلية السائقين)؛ 49 CFR 383.51 Table 1."},"42":{"q":"ما هي مدة إسقاط أهلية CDL في أوكلاهوما لأول مخالفة كبرى للسائق (مثل القيادة تحت تأثير الكحول في مركبة CMV) عند عدم نقل مواد خطرة تحمل لوحات تحذيرية؟","options":["60 days","120 days","1 year","3 years"],"explanation":"تؤدي أول مخالفة كبرى إلى إسقاط أهلية CDL لمدة 1-year في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1 (إسقاط أهلية السائقين)؛ 49 CFR 383.51 Table 1."},"43":{"q":"إذا ارتكب سائق أول مخالفة كبرى أثناء تشغيل مركبة CMV يلزم أن تحمل لوحات تحذيرية للمواد الخطرة، فإلى كم تزداد مدة إسقاط الأهلية في أوكلاهوما؟","options":["18 months","2 years","3 years","Lifetime"],"explanation":"ترفع أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة تحمل لوحات تحذيرية إسقاط الأهلية من 1 year إلى 3 years في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 1."},"44":{"q":"ما هو إسقاط أهلية CDL في أوكلاهوما لثاني مخالفة كبرى للسائق؟","options":["3 years","5 years","10 years","Lifetime"],"explanation":"تؤدي ثاني مخالفة كبرى إلى إسقاط أهلية CDL مدى الحياة في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1 (إسقاط أهلية السائقين)؛ 49 CFR 383.51 Table 1."},"45":{"q":"استخدام مركبة CMV في ارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها يحمل أي عقوبة CDL في أوكلاهوما؟","options":["1-year disqualification","3-year disqualification","10-year disqualification","Lifetime disqualification with no reinstatement"],"explanation":"استخدام مركبة CMV في جناية تتعلق بتصنيع أو توزيع مادة خاضعة للرقابة يحمل إسقاط أهلية إلزاميًا مدى الحياة دون إمكانية إعادة الأهلية في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 1."},"46":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3-year التي تستوجب أول مدة لإسقاط الأهلية في أوكلاهوما، وكم تبلغ مدتها؟","options":["1 violation; 30 days","2 violations; 60 days","2 violations; 90 days","3 violations; 60 days"],"explanation":"تؤدي ثاني مخالفة مرورية خطيرة خلال 3 years (تُرتكب في مركبة CMV) إلى إسقاط الأهلية لمدة 60-day في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 2."},"47":{"q":"ما هو إسقاط أهلية CDL في أوكلاهوما لثالث مخالفة مرورية خطيرة تُرتكب خلال فترة 3-year؟","options":["60 days","90 days","120 days","1 year"],"explanation":"تؤدي ثالث مخالفة مرورية خطيرة خلال 3 years إلى إسقاط الأهلية لمدة 120-day في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 2."},"48":{"q":"أي مما يلي يُعد مخالفة مرورية خطيرة لحامل رخصة CDL في أوكلاهوما؟","options":["Parking in a no-parking zone","Speeding 15 mph or more over the posted limit","Driving with an expired registration sticker","Failing to signal a lane change with no traffic present"],"explanation":"تجاوز السرعة المفرط (15 mph أو أكثر فوق الحد) مخالفة مرورية خطيرة مدرجة. وتشمل أخرى القيادة المتهورة، وتغييرات المسار غير السليمة، والاقتراب الشديد من المركبة الأمامية، والرسائل النصية/استخدام الهاتف باليد. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 2."},"49":{"q":"إرسال الرسائل النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة CMV يُصنَّف في أوكلاهوما على أنه أي نوع من المخالفات؟","options":["A minor moving violation","A serious traffic violation","A major offense","An out-of-service order violation"],"explanation":"إرسال الرسائل النصية واستخدام الهاتف المحمول باليد أثناء قيادة مركبة CMV مخالفتان مروريتان خطيرتان تُحتسبان ضمن إسقاط الأهلية بمعدل 2 أو 3 خلال 3 سنوات. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 2، 392.80 و 392.82."},"50":{"q":"سائق مركبة CMV في أوكلاهوما يُضبط وهو يستخدم هاتفًا محمولًا باليد أثناء القيادة يمكن أن يواجه عقوبة مدنية فيدرالية (غرامة على السائق) تصل إلى أي مبلغ؟","options":["$250","$1,000","$2,750","$11,000"],"explanation":"يمكن أن تصل غرامة السائق لاستخدام هاتف محمول باليد أثناء قيادة مركبة CMV إلى $2,750 (ويمكن تغريم أصحاب العمل الذين يسمحون بذلك حتى $11,000). المصدر: 49 CFR 392.82؛ قاعدة الهاتف المحمول الصادرة عن FMCSA المطبَّقة في أوكلاهوما."},"51":{"q":"ما هو إسقاط أهلية CDL في أوكلاهوما لأول مخالفة عبور سكة حديد-طريق سريع خلال فترة 3-year؟","options":["No less than 60 days","No less than 120 days","No less than 1 year","No less than 3 years"],"explanation":"تؤدي أول مخالفة عبور سكة حديد-طريق سريع إلى إسقاط الأهلية لمدة لا تقل عن 60 days في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 3."},"52":{"q":"ما هو إسقاط أهلية CDL في أوكلاهوما لثاني مخالفة عبور سكة حديد-طريق سريع خلال فترة 3-year؟","options":["60 days","No less than 120 days","No less than 1 year","No less than 2 years"],"explanation":"تؤدي ثاني مخالفة عبور سكة حديد-طريق سريع خلال 3 years إلى إسقاط الأهلية لمدة لا تقل عن 120 days في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 3."},"53":{"q":"ما هو إسقاط أهلية CDL في أوكلاهوما لثالث مخالفة عبور سكة حديد-طريق سريع أو ما بعدها خلال فترة 3-year؟","options":["120 days","180 days","No less than 1 year","Lifetime"],"explanation":"تؤدي ثالث مخالفة عبور سكة حديد-طريق سريع أو ما بعدها خلال 3 years إلى إسقاط الأهلية لمدة لا تقل عن 1 year في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 3."},"54":{"q":"ما هو إسقاط أهلية CDL في أوكلاهوما لثالث مخالفة لأمر إيقاف عن الخدمة أو ما بعدها خلال فترة 10-year؟","options":["1 year","2 years","No less than 3 years but not more than 5 years","Lifetime"],"explanation":"تؤدي ثالث مخالفة لأمر إيقاف عن الخدمة أو ما بعدها خلال 10 years إلى إسقاط الأهلية لمدة لا تقل عن 3 years ولكن لا تزيد عن 5 years في أوكلاهوما. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 4."},"55":{"q":"يُدان حامل رخصة CDL في أوكلاهوما بمغادرة موقع حادث متورطة فيه مركبة CMV كان يقودها. كيف يُصنَّف ذلك لأغراض إسقاط الأهلية؟","options":["A serious traffic violation (60-day minimum)","A major offense (1-year minimum, 3 years if hazmat)","An out-of-service order violation","A railroad crossing violation"],"explanation":"مغادرة موقع حادث (الصدم والهروب) متورطة فيه مركبة CMV مخالفة كبرى، تحمل إسقاط أهلية لمدة 1-year (3 years إذا كانت مواد خطرة تحمل لوحات تحذيرية) لأول مخالفة، ومدى الحياة لثانيها. المصدر: دليل سائق CDL في أوكلاهوما، القسم 1؛ 49 CFR 383.51 Table 1."},"56":{"q":"في ولاية أوكلاهوما، عندما تقترب مركبة تجارية ملزمة بالتوقف من تقاطع سكة حديد مع طريق سريع، أين يجب على السائق أن يتوقف؟","options":["على مسافة لا تقل عن 5 أقدام ولا تزيد عن 25 قدمًا من أقرب قضيب سكة","على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب قضيب سكة","على مسافة لا تقل عن 25 قدمًا ولا تزيد عن 75 قدمًا من أقرب قضيب سكة","على مسافة لا تقل عن 10 أقدام ولا تزيد عن 100 قدم من أقرب قضيب سكة"],"explanation":"يُلزم دليل CDL لولاية أوكلاهوما (القسمان 2.15 و9.6.12) السائقين الذين يجب عليهم التوقف عند تقاطع سكة الحديد بالتوقف ضمن مسافة تتراوح بين 15 و50 قدمًا من أقرب قضيب سكة، ثم المتابعة فقط عند التأكد من عدم قدوم أي قطار. وهذا يطابق القاعدة 49 CFR 392.10 كما تُطبَّق في أوكلاهوما."},"57":{"q":"أي من المركبات التجارية التالية غير ملزمة بالتوقف عند كل تقاطع سكة حديد بموجب قواعد أوكلاهوما؟","options":["حافلة تقل ركابًا","مقطورة جافة فارغة (دراي-فان) لا تحمل مواد خطرة ولا ركابًا","مركبة تعرض لافتات المواد الخطرة","صهريج شحن يُستخدم للمواد الخطرة، سواء كان محمَّلًا أو فارغًا"],"explanation":"يُدرج دليل CDL لولاية أوكلاهوما (القسم 9.6.12) المركبات التي يجب أن تتوقف دائمًا وهي: المركبات التي تحمل اللافتات، وأي مركبة تنقل الكلور، وصهاريج الشحن المستخدمة للمواد الخطرة (محمَّلة أو فارغة)، والحافلات التي تقل ركابًا. أما شاحنة الشحن (الفان) غير الحاملة للافتات والتي لا تنقل ركابًا فليست ضمن قائمة التوقف الإلزامي."},"58":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في أوكلاهوما، ما الذي يُطلب من السائق على طريق سريع به مساران أو أكثر في الاتجاه نفسه القيام به أولًا عند الاقتراب من مركبة طوارئ متوقفة أو شاحنة سحب (ونش) تعرض أضواءً وامضة؟","options":["الانتقال إلى مسار غير ملاصق للمركبة الثابتة، إن أمكن ذلك بأمان","التوقف توقفًا تامًا حتى تغادر مركبة الطوارئ","إطلاق البوق لتحذير أفراد الطوارئ","الحفاظ على السرعة مع التحرك ضمن المسار نفسه باتجاه الخط الأوسط"],"explanation":"يُلزم قانون \"أفسح الطريق\" في أوكلاهوما (47 O.S. القسم 11-314) السائق على طريق متعدد المسارات، عندما يكون ذلك آمنًا، بالانتقال إلى مسار غير ملاصق لمركبة الطوارئ الثابتة، أو شاحنة السحب المرخَّصة، أو مركبة صيانة DOT أو هيئة الطرق السريعة برسوم (Turnpike) التي تعرض أضواءً وامضة."},"59":{"q":"بموجب قانون \"أفسح الطريق\" في أوكلاهوما، عندما لا يستطيع السائق تغيير المسار بأمان بعيدًا عن مركبة طوارئ متوقفة، ماذا يجب على السائق فعله؟","options":["تخفيض السرعة إلى 20 mph تمامًا في جميع الحالات","التوقف توقفًا تامًا والانتظار حتى تلقّي إشارة بالمتابعة","المتابعة بحد السرعة المعلن مع استخدام الأضواء الوامضة الرباعية","تخفيض السرعة إلى سرعة آمنة تتناسب مع ظروف الطريق والطقس وحركة المرور القائمة"],"explanation":"يُلزم قانون \"أفسح الطريق\" في أوكلاهوما (47 O.S. القسم 11-314) السائق الذي لا يستطيع تغيير المسار بأن يبطئ إلى سرعة آمنة تتناسب مع الظروف القائمة. ويعتمد القانون معيارًا قائمًا على الظروف بدلًا من رقم ثابت واحد."},"60":{"q":"إذا اضطرت مركبة تجارية تحمل لافتات إلى التوقف على طريق سريع باتجاه واحد أو مقسوم في أوكلاهوما، فعلى أي مسافات باتجاه حركة المرور القادمة يجب وضع أجهزة التحذير؟","options":["10 أقدام و50 قدمًا و150 قدمًا","25 قدمًا و75 قدمًا و250 قدمًا","10 أقدام و100 قدم و200 قدم","10 أقدام و100 قدم و500 قدم"],"explanation":"يُلزم دليل CDL لولاية أوكلاهوما (القسم 2، أجهزة التحذير) بأن تُوضع أجهزة التحذير على طريق باتجاه واحد أو مقسوم على مسافات 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة."},"61":{"q":"على طريق في أوكلاهوما ذي مسارين ينقل حركة المرور في الاتجاهين (غير مقسوم)، أين يجب على مركبة تجارية متوقفة (CMV) أن تضع أجهزة التحذير الثلاثة الخاصة بها؟","options":["على مسافات 10 أقدام و100 قدم و200 قدم خلف المركبة فقط","ضمن 10 أقدام من المركبة، و100 قدم خلف المركبة و100 قدم أمامها","على مسافات 50 قدمًا و100 قدم و200 قدم على الكتف","ضمن 10 أقدام من المركبة، و200 قدم خلف المركبة و200 قدم أمامها"],"explanation":"يذكر دليل CDL لولاية أوكلاهوما أنه على طريق ذي مسارين باتجاهين أو غير مقسوم، يُوضع جهاز واحد ضمن 10 أقدام من المركبة لتحديد موقعها، وجهاز واحد على بُعد 100 قدم أمام المركبة وآخر على بُعد 100 قدم خلفها."},"62":{"q":"بعد التوقف على الطريق أو الكتف في أوكلاهوما، خلال كم دقيقة يجب على سائق المركبة التجارية (CMV) وضع أجهزة التحذير المطلوبة؟","options":["5 دقائق","15 دقيقة","30 دقيقة","10 دقائق"],"explanation":"يذكر دليل CDL لولاية أوكلاهوما (القسم 2) أنه إذا اضطررت إلى التوقف على طريق أو كتف أي طريق، فيجب عليك وضع أجهزة التحذير من حالات الطوارئ خلال عشر دقائق."},"63":{"q":"كم عدد أجهزة التحذير التي يجب أن تحملها المركبة التجارية (CMV) في أوكلاهوما لاستخدامها عند ركن المركبة أو تعطلها؟","options":["مثلثان عاكسان، أو 4 شعلات (فيوزات)، أو شعلتان سائلتان الاحتراق","أربعة مثلثات عاكسة، أو 8 شعلات (فيوزات)، أو 4 شعلات سائلة الاحتراق","مثلث عاكس واحد، أو 3 شعلات (فيوزات)، أو شعلة سائلة الاحتراق واحدة","ثلاثة مثلثات عاكسة، أو 6 شعلات (فيوزات)، أو 3 شعلات سائلة الاحتراق"],"explanation":"يُدرج دليل CDL لولاية أوكلاهوما أجهزة التحذير المطلوبة للمركبات المركونة على أنها ثلاثة مثلثات حمراء عاكسة، أو 6 شعلات (فيوزات) على الأقل، أو 3 شعلات سائلة الاحتراق."},"64":{"q":"بموجب قانون أوكلاهوما (47 O.S. القسم 11-705)، متى لا يُطلب من السائق المتجه في الاتجاه المعاكس التوقف لحافلة مدرسية تقوم بتحميل أو إنزال الأطفال مع وميض الأضواء الحمراء؟","options":["عندما تكون الحافلة على الجانب البعيد من أي خط أوسط مرسوم","عندما تكون حركة المرور كثيفة ويكون التوقف غير مريح","عندما يفصل بين اتجاهي السير مسار وسطي للانعطاف يسارًا في الاتجاهين","عندما يكون الطريق مقسومًا بحاجز مادي أو جزيرة وسطية غير معبَّدة تفصل بين اتجاهي السير"],"explanation":"يُعفي القانون النظامي لأوكلاهوما 47 O.S. القسم 11-705 حركة المرور المعاكسة من التوقف فقط عندما يفصل بين الطريقين طريق مقسوم بحاجز مادي أو جزيرة وسطية غير معبَّدة. أما الخط المرسوم أو مسار الانعطاف الأوسط فلا يستوفي ذلك، ولذلك يجب على حركة المرور المعاكسة التوقف في تلك الحالات."},"65":{"q":"على طريق سريع غير مقسوم بمسارين في أوكلاهوما، ماذا يجب على السائق الذي يقابل حافلة مدرسية متوقفة بأضواء حمراء وامضة وذراع توقف ممتدة أن يفعل؟","options":["أن يتوقف، بغض النظر عن اتجاه السير، حتى تسحب الحافلة ذراع التوقف وتطفئ الأضواء الحمراء","أن يبطئ إلى 25 mph ويتجاوز بحذر","أن يتوقف فقط إذا كان يسير في الاتجاه نفسه للحافلة","أن يتابع سيره بشكل طبيعي لأن حركة المرور في الاتجاه نفسه فقط هي التي يجب أن تتوقف"],"explanation":"بموجب 47 O.S. القسم 11-705، على طريق سريع غير مقسوم يجب أن تتوقف حركة المرور في الاتجاهين لحافلة مدرسية تعرض أضواءً حمراء وامضة وذراع توقف ممتدة، وأن تبقى متوقفة حتى تسحب الحافلة الإشارات."},"66":{"q":"ما الغرامة المقررة عند الإدانة الأولى بتجاوز حافلة مدرسية متوقفة بشكل غير قانوني في أوكلاهوما أثناء قيامها بتحميل أو إنزال الأطفال؟","options":["مبلغ ثابت قدره $50","ما لا يقل عن $100 ويصل إلى $500","ما لا يقل عن $250 ويصل إلى $1,000","مبلغ ثابت قدره $1,500 بالإضافة إلى السجن الإلزامي"],"explanation":"يحدد القانون النظامي لأوكلاهوما 47 O.S. القسم 11-705 غرامة لا تقل عن $100 وتصل إلى $500 للمخالفة الأولى المتمثلة في التجاوز غير القانوني لحافلة مدرسية متوقفة، مع عقوبات متصاعدة (بما في ذلك إمكانية تعليق الرخصة) للمخالفات المتكررة."},"67":{"q":"بموجب قانون استخدام المسارات في أوكلاهوما (47 O.S. القسم 11-309)، على طريق به أربعة مسارات أو أكثر، متى يجوز لمركبة أن تسير بشكل صحيح في أقصى المسار الأيسر؟","options":["فقط عند تجاوز مركبة أخرى والمرور بها، أو الاستعداد للانعطاف يسارًا، أو عندما تقتضي ظروف المرور أو الطريق ذلك","في أي وقت، طالما حافظ السائق على حد السرعة المعلن","فقط عندما تكون المسارات اليمنى فارغة تمامًا","فقط بين شروق الشمس وغروبها"],"explanation":"يقيّد القانون النظامي لأوكلاهوما 47 O.S. القسم 11-309 المسار الأيسر بالتجاوز، أو الاستعداد للانعطاف يسارًا، أو الحالات التي تتطلب فيها انسيابية المرور أو تكوين الطريق ذلك. ولا يجوز للمركبة أن تعيق التدفق الطبيعي لحركة المرور بالسير في المسار الأيسر، حتى عند حد السرعة المعلن."},"68":{"q":"ما أعلى حد للسرعة يمكن أن يُعلَن على أقسام من الطرق السريعة برسوم (turnpikes) في أوكلاهوما وفق ما يجيزه القانون النظامي؟","options":["85 mph","75 mph","80 mph","70 mph"],"explanation":"بموجب 47 O.S. القسم 11-801، يجوز لهيئة الطرق السريعة برسوم في أوكلاهوما (Oklahoma Turnpike Authority) تحديد حد سرعة يصل إلى 80 mph على الأقسام المعتمدة من نظام الطرق برسوم. وعدة مقاطع (مثل أجزاء من طريقي تيرنر وإنديان نيشن برسوم) معلنة بسرعة 80 mph."},"69":{"q":"عند الاقتراب من تقاطع سكة حديد في أوكلاهوما، متى ينبغي على سائق حافلة أو مركبة تحمل لافتات تشغيل الأضواء الوامضة الرباعية؟","options":["على بُعد حوالي 200 قدم قبل التقاطع","على بُعد حوالي 50 قدمًا قبل التقاطع","على بُعد حوالي 500 قدم قبل التقاطع","فقط بعد التوقف توقفًا تامًا عند التقاطع"],"explanation":"يوجّه دليل CDL لولاية أوكلاهوما (القسم 10.4، إجراءات عبور الحافلة المدرسية) السائق إلى تشغيل أضواء الخطر على بُعد حوالي 200 قدم قبل التقاطع لتحذير حركة المرور التابعة من التوقف الوشيك."},"70":{"q":"أثناء وجود أي جزء من مركبة تجارية في أوكلاهوما على تقاطع سكة حديد، أي إجراء يُمنع القيام به؟","options":["تبديل أو تغيير التروس","إبقاء كلتا اليدين على عجلة القيادة","النظر والإصغاء لاكتشاف القطارات","الحفاظ على سرعة ثابتة"],"explanation":"يوجّه دليل CDL لولاية أوكلاهوما السائقين بعدم تبديل التروس أثناء عبور السكة، لأن إخفاق التبديل قد يترك المركبة متعطلة على التقاطع. وينبغي على السائقين اختيار ترس قبل التقاطع والإبقاء عليه أثناء عبور السكة."},"71":{"q":"عندما تتوقف حافلة مدرسية في أوكلاهوما لإنزال الطلاب، على أي بُعد من الطلاب عند المحطة يجب أن تتوقف الحافلة توقفًا تامًا؟","options":["على بُعد 3 أقدام على الأقل من الطلاب","على بُعد 25 قدمًا على الأقل من الطلاب","على بُعد 10 أقدام على الأقل من الطلاب","على بُعد 50 قدمًا على الأقل من الطلاب"],"explanation":"يوجّه دليل CDL لولاية أوكلاهوما (القسم 13، اختبار المهارات، إنزال الطلاب) السائق إلى إيقاف الحافلة المدرسية توقفًا تامًا على بُعد 10 أقدام على الأقل من الطلاب عند المحطة، مما يبقي الطلاب في مجال رؤية السائق الواضح."},"72":{"q":"ما الحد الأقصى القانوني المعياري لعرض المركبة والحمولة في أوكلاهوما قبل أن يُطلب تصريح للأحجام الزائدة من ODOT؟","options":["8 أقدام و0 بوصة","10 أقدام و0 بوصة","8 أقدام و6 بوصات","9 أقدام و6 بوصات"],"explanation":"وفقًا لقواعد ODOT المتعلقة بالأحجام والأوزان، فإن حد العرض القانوني في أوكلاهوما هو 8 أقدام و6 بوصات؛ والحمولات الأعرض من ذلك تتطلب تصريحًا للأحجام الزائدة. أما حد الارتفاع القانوني فهو 13 قدمًا و6 بوصات."},"73":{"q":"تقتصر حركة الحمولات الزائدة الحجم في أوكلاهوما عمومًا على أي فترة زمنية؟","options":["فقط بين الساعة 9:00 مساءً و5:00 صباحًا","ساعات النهار، من 30 دقيقة قبل شروق الشمس إلى 30 دقيقة بعد غروبها","24 ساعة في اليوم دون قيد زمني","فقط في عطلات نهاية الأسبوع والإجازات"],"explanation":"تقصر قواعد تصاريح الأحجام الزائدة الخاصة بـ ODOT الحركة على ساعات النهار، المعرَّفة بأنها من 30 دقيقة قبل شروق الشمس إلى 30 دقيقة بعد غروبها، مع قيود إضافية في حالات الطقس السيئ وانخفاض الرؤية."},"74":{"q":"تقيّد أوكلاهوما الحمولات الزائدة الحجم على نظام الطرق بين الولايات (Interstate) خلال ساعات الذروة في أيام الأسبوع في أي مقاطعات؟","options":["مقاطعات كومانتش وغارفيلد وباين","مقاطعات ماسكوغي وبوتاواتومي وكارتر","مقاطعات أوكلاهوما وتولسا وكليفلاند","مقاطعات كندي وروجرز وواغونر"],"explanation":"تحظر قواعد ODOT للأحجام الزائدة الحمولات الزائدة الحجم على نظام الطرق بين الولايات في مقاطعات أوكلاهوما وتولسا وكليفلاند خلال نافذتي ساعات الذروة في أيام الأسبوع من 7:00-9:00 صباحًا ومن 3:30-6:30 مساءً (بالتوقيت المركزي)، من الإثنين إلى الجمعة."},"75":{"q":"تؤدي الإدانة بمخالفة عبور تقاطع سكة حديد مع طريق سريع في مركبة تجارية إلى أي حد أدنى من فقدان أهلية CDL في أوكلاهوما عن المخالفة الأولى؟","options":["30 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل","60 يومًا على الأقل"],"explanation":"يذكر دليل CDL لولاية أوكلاهوما (القسم 1.3.5) أن حامل CDL يفقد أهليته لمدة 60 يومًا على الأقل عن مخالفة عبور سكة الحديد الأولى، و120 يومًا على الأقل عن مخالفة ثانية خلال ثلاث سنوات، وسنة واحدة على الأقل عن مخالفة ثالثة خلال ثلاث سنوات."},"76":{"q":"أي جهة حكومية في ولاية أوكلاهوما تصدر رخص القيادة التجارية وتدير اختبارات المعرفة والمهارات الخاصة بـ CDL؟","options":["Service Oklahoma","وزارة النقل في أوكلاهوما (ODOT)","لجنة الشركات في أوكلاهوما","لجنة الضرائب في أوكلاهوما"],"explanation":"تتولى Service Oklahoma (التي تولّت مهام ترخيص السائقين التي كانت تتولاها سابقًا وزارة الأمن العام) إصدار رخص CDL وإدارة اختبارات CDL في مكاتب الترخيص التابعة لها. المصدر: صفحتا Service Oklahoma بعنوان 'Commercial Driving CDL' و'CDL First-Time Applicants' (oklahoma.gov)."},"77":{"q":"أين يجري مقدّم طلب CDL في أوكلاهوما اختباري النظر والمعرفة التحريري المطلوبين؟","options":["شخصيًا في أحد مكاتب الترخيص التابعة لـ Service Oklahoma","عبر الإنترنت من خلال بوابة Service Oklahoma من المنزل","في أي مدرسة مدرجة في سجل مزوّدي التدريب التابع لـ FMCSA","في مقر إحدى فرق دورية الطرق السريعة في أوكلاهوما"],"explanation":"يبدأ مقدّمو الطلبات عملية CDL بإجراء اختباري النظر والمعرفة التحريري شخصيًا في أحد مكاتب الترخيص التابعة لـ Service Oklahoma؛ ويُجرى اختبارا النظر والتحرير معًا في الموعد نفسه. المصدر: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"78":{"q":"كم يومًا يجب على مقدّم الطلب في أوكلاهوما أن يحمل تصريح المتعلّم التجاري (CLP) قبل أن يُسمح له بإجراء اختبار مهارات القيادة الخاص بـ CDL؟","options":["14 يومًا كاملًا، مع السماح بإجراء الاختبار في اليوم الخامس عشر","30 يومًا كاملًا، مع السماح بإجراء الاختبار في اليوم الحادي والثلاثين","7 أيام كاملة، مع السماح بإجراء الاختبار في اليوم الثامن","10 أيام كاملة، مع السماح بإجراء الاختبار في اليوم الحادي عشر"],"explanation":"تشترط أوكلاهوما حمل CLP لمدة 14 يومًا كاملًا قبل اختبار المهارات؛ ويجوز لمقدّم الطلب إجراء الاختبار في اليوم الخامس عشر. وهذا يطابق القاعدة الفيدرالية للـ 14 يومًا. المصدر: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)؛ 49 CFR 383.25."},"79":{"q":"اختبار مهارات CDL في أوكلاهوما اختبار من ثلاثة أجزاء. أي مجموعة تُدرج تلك الأجزاء الثلاثة بشكل صحيح؟","options":["فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية، واختبار القيادة على الطريق","اختبار المعرفة العامة، واختبار الفرامل الهوائية، واختبار المركبات المركّبة","اختبار النظر، والاختبار التحريري، ودورة القيادة الدفاعية","فحص ما قبل الرحلة، واختبار المواد الخطرة، واختبار الرجوع للخلف"],"explanation":"يتكون اختبار مهارات CDL في أوكلاهوما من ثلاثة أجزاء: فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية (مثل مناورات الرجوع للخلف)، واختبار القيادة على الطريق. المصدر: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)؛ 49 CFR 383.113."},"80":{"q":"بموجب قواعد تدريب السائقين المبتدئين الفيدرالية (ELDT) التي تطبّقها أوكلاهوما، يجب على مقدّم الطلب لأول مرة من الفئة A أو الفئة B إكمال ELDT من مزوّد معتمد قبل القيام بماذا؟","options":["إجراء اختبار مهارات CDL الذي تديره الولاية","تلقّي تصريح المتعلّم التجاري","إجراء اختبار المعرفة العامة التحريري","إكمال فحص النظر"],"explanation":"يجب إكمال ELDT (النظري والتدريب خلف المقود) لرخصة CDL من الفئة A أو B لأول مرة من خلال مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل أن يجري مقدّم الطلب اختبار المهارات الذي تديره الولاية. المصدر: قاعدة ELDT الخاصة بـ FMCSA (49 CFR Part 380)؛ Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"81":{"q":"أين يجب أن يكون مزوّد تدريب السائقين المبتدئين الخاص بمقدّم طلب CDL في أوكلاهوما مدرَجًا حتى يُحتسب التدريب؟","options":["سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","قائمة المدارس التابعة لوزارة النقل في أوكلاهوما","دليل البائعين المعتمدين لدى Service Oklahoma","السجل الوطني لفاحصي الطب المعتمدين"],"explanation":"يجب الحصول على ELDT من مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR). المصدر: قاعدة ELDT الخاصة بـ FMCSA؛ Service Oklahoma 'Commercial Driving CDL' (oklahoma.gov)."},"82":{"q":"أي تصديق (Endorsement) لـ CDL يتطلب إكمال التدريب النظري لـ ELDT قبل إجراء اختبار المعرفة (وليس اختبار المهارات)؟","options":["تصديق المواد الخطرة (H)","تصديق الركاب (P)","تصديق الحافلة المدرسية (S)","تصديق المقطورات المزدوجة/الثلاثية (T)"],"explanation":"بالنسبة لتصديق المواد الخطرة (H)، يكون ELDT نظريًا فقط ويجب إكماله قبل اختبار المعرفة الذي تديره الولاية. أما تصديقا P وS فيتطلبان ELDT قبل اختبارات المهارات الخاصة بهما. المصدر: قاعدة ELDT الخاصة بـ FMCSA (49 CFR Part 380)."},"83":{"q":"كم عدد فئات التصديق الذاتي التي يجب على مقدّم طلب CDL في أوكلاهوما الاختيار من بينها عند إعلان نوع القيادة الخاص به؟","options":["أربع","اثنتان","ثلاث","ست"],"explanation":"يجب على مقدّمي الطلبات التصديق ذاتيًا ضمن واحدة من أربع فئات: غير المستثناة بين الولايات (NI)، والمستثناة بين الولايات (EI)، وغير المستثناة داخل الولاية (NA)، والمستثناة داخل الولاية (EA). المصدر: Service Oklahoma 'CDL First-Time Applicants' وإجراء التشغيل المعياري للتصديق الذاتي لـ CDL (oklahoma.gov)."},"84":{"q":"أي فئة تصديق ذاتي تتطلب من السائق الاحتفاظ بشهادة فاحص طبي DOT في الملف لأغراض الترخيص؟","options":["غير المستثناة بين الولايات (NI)","المستثناة بين الولايات (EI)","المستثناة داخل الولاية (EA)","غير المستثناة داخل الولاية (NA)"],"explanation":"فئة غير المستثناة بين الولايات (NI) وحدها هي التي تتطلب بطاقة طبية DOT للترخيص. أما فئات EI وNA وEA فلا تتطلب وجود بطاقة طبية في الملف لدى Service Oklahoma. المصدر: Service Oklahoma 'CDL First-Time Applicants' / 'Commercial Driving CDL' (oklahoma.gov)."},"85":{"q":"كيف يتم الآن إرسال شهادة الفاحص الطبي DOT الخاصة بالسائق إلى Service Oklahoma لأغراض حفظ السجلات؟","options":["إلكترونيًا من السجل الوطني لفاحصي الطب المعتمدين التابع لـ FMCSA","عن طريق إرسال السائق نسخة ورقية بالبريد إلى مقر Service Oklahoma","عن طريق إرسال صاحب العمل لها بالفاكس إلى مكتب الترخيص المحلي","عن طريق إحالة وكالة لوحات المقاطعة نسخة موثَّقة"],"explanation":"يقدّم الفاحص الطبي المعتمد الشهادة (النموذج MCSA-5876) إلكترونيًا إلى السجل الوطني التابع لـ FMCSA، الذي ينقل حالة التصديق الطبي إلكترونيًا إلى Service Oklahoma. المصدر: إجراء التشغيل المعياري للتصديق الذاتي لـ CDL ومعالجة الشهادات الطبية لدى Service Oklahoma (oklahoma.gov)؛ السجل الوطني لـ FMCSA."},"86":{"q":"ما رقم النموذج الخاص بشهادة الفاحص الطبي الفيدرالية التي يقدّمها الفاحص المعتمد إلى السجل الوطني التابع لـ FMCSA؟","options":["MCSA-5876","MCSA-5875","MCSA-5889","MCSA-5870"],"explanation":"شهادة الفاحص الطبي هي نموذج FMCSA رقم MCSA-5876؛ أما تقرير الفحص الطبي ذو الصلة فهو MCSA-5875. ويقدّم الفاحص نتيجة النموذج MCSA-5876 إلى السجل الوطني. المصدر: إجراء التشغيل المعياري لمعالجة الشهادات الطبية لدى Service Oklahoma؛ FMCSA."},"87":{"q":"يجب عادةً على حامل CDL من فئة غير المستثناة بين الولايات (NI) في أوكلاهوما تقديم شهادة فاحص طبي DOT حديثة كل كم من الوقت على الأقل (الحد الأقصى للفاصل الزمني بين الفحوصات وفق معايير FMCSA)؟","options":["كل 24 شهرًا","كل 12 شهرًا","كل 36 شهرًا","كل 60 شهرًا"],"explanation":"تظل شهادة الفاحص الطبي القياسية سارية لمدة أقصاها 24 شهرًا، لذا يجب على سائقي فئة NI الاحتفاظ بشهادة حديثة في الملف ضمن تلك الدورة (وتنطبق فترات أقصر على حالات معينة). المصدر: التوجيهات الطبية لـ CDL لدى Service Oklahoma؛ 49 CFR 391.45."},"88":{"q":"إذا أُبلِغت Service Oklahoma بأن التصديق الطبي لحامل CDL قد انتهت صلاحيته أو لم يعد ساريًا، فخلال كم يومًا يجب على الجهة تخفيض درجة CDL بموجب القاعدة الفيدرالية؟","options":["خلال 60 يومًا","خلال 10 أيام","خلال 30 يومًا","خلال 90 يومًا"],"explanation":"يجب على جهات ترخيص السائقين في الولايات، بما فيها Service Oklahoma، تخفيض درجة CDL خلال 60 يومًا من علمها بأن السائق لم يعد مصدَّقًا طبيًا أو أن الشهادة الطبية انتهت صلاحيتها ولم تُجدَّد. المصدر: توجيهات التخفيض لدى Service Oklahoma؛ 49 CFR 383.73(o)."},"89":{"q":"بموجب القانون النظامي لأوكلاهوما، لكم من الوقت يكون تصريح المتعلّم التجاري (CLP) ساريًا في البداية؟","options":["180 يومًا","90 يومًا","60 يومًا","سنة واحدة"],"explanation":"تصدر أوكلاهوما CLP لمدة 180 يومًا؛ ويمكن تجديده مرة واحدة لمدة 180 يومًا إضافية. المصدر: 47 O.S. القسم 6-101؛ توجيهات CLP لدى Service Oklahoma."},"90":{"q":"يجوز تجديد CLP في أوكلاهوما مرة واحدة. لكم من الوقت يكون ذلك التجديد الواحد ساريًا؟","options":["180 يومًا إضافية","30 يومًا إضافية","سنة واحدة إضافية","90 يومًا إضافية"],"explanation":"يكون CLP ساريًا لمدة 180 يومًا ويمكن تجديده مرة واحدة لمدة 180 يومًا إضافية، بما يتيح ما يصل إلى سنة واحدة إجمالًا. المصدر: 47 O.S. القسم 6-101؛ توجيهات CLP لدى Service Oklahoma."},"91":{"q":"ما الحد الأدنى للعمر للحصول على CDL للقيادة التجارية داخل الولاية (INTRASTATE) (داخل أوكلاهوما فقط)؟","options":["18 عامًا","21 عامًا","16 عامًا","19 عامًا"],"explanation":"يجب أن يكون عمر مقدّم الطلب 18 عامًا على الأقل لتشغيل مركبة تجارية داخل الولاية (داخل أوكلاهوما) و21 عامًا على الأقل للقيادة بين الولايات. المصدر: توجيهات CDL لدى Service Oklahoma؛ 47 O.S. القسم 6-101."},"92":{"q":"حامل CDL في أوكلاهوما يبلغ من العمر 19 عامًا ولم يبلغ بعد 21 عامًا يكون عمومًا مقيَّدًا بأي شكل؟","options":["بالقيادة التجارية داخل الولاية (داخل أوكلاهوما) فقط","بقيادة مركبات تجارية من الفئة C فقط","بالقيادة التجارية النهارية فقط","بالقيادة فقط بوجود حامل CDL مرخَّص"],"explanation":"يجوز للسائقين الذين تتراوح أعمارهم بين 18 و20 عامًا حمل CDL لكنهم مقيَّدون بالتشغيل التجاري داخل الولاية (داخل أوكلاهوما)؛ ويتطلب التشغيل بين الولايات بلوغ سن 21. المصدر: توجيهات CDL لدى Service Oklahoma؛ 49 CFR 383.3 / 391.11."},"93":{"q":"أي مستند ليس من بين المستندات المطلوب من مقدّم طلب CDL لأول مرة في أوكلاهوما تقديمها في مكتب الترخيص التابع لـ Service Oklahoma؟","options":["خطاب من صاحب العمل يأذن باختبار الطريق","إثبات الهوية والوجود القانوني","إثبات الإقامة في أوكلاهوما (إثبات عنوان واحد)","رخصة قيادة سارية من الفئة D في أوكلاهوما"],"explanation":"تشمل المستندات المطلوبة إثبات الهوية والوجود القانوني، وإثبات الإقامة/العنوان، ورخصة سارية من الفئة D في أوكلاهوما، ورقم الضمان الاجتماعي؛ أما خطاب الإذن من صاحب العمل فليس مطلوبًا. المصدر: Service Oklahoma 'CDL First-Time Applicants' (oklahoma.gov)."},"94":{"q":"فيما يتعلق بتجديد CDL في أوكلاهوما، أي عبارة دقيقة بشأن العملية؟","options":["يجوز لحاملي CDL المؤهلين التجديد عبر الإنترنت، لكن على حاملي تصديق المواد الخطرة (H) التجديد شخصيًا وإعادة اجتياز الاختبار التحريري للمواد الخطرة بالإضافة إلى التحقق من الخلفية لدى TSA","يمكن إتمام جميع تجديدات CDL، بما في ذلك المواد الخطرة، بالكامل عبر الإنترنت","لا يمكن تجديد رخص CDL ويجب إعادة الاختبار من البداية في كل دورة","يتطلب التجديد إعادة اجتياز اختبار المهارات الكامل المكوّن من ثلاثة أجزاء في كل مرة"],"explanation":"تتيح Service Oklahoma تجديد CDL عبر الإنترنت للحاملين المؤهلين، لكن على حاملي تصديق المواد الخطرة التجديد شخصيًا وإعادة اجتياز اختبار المعرفة للمواد الخطرة وإتمام التحقق من الخلفية لدى TSA في كل تجديد. (ملاحظة: قد تتغير الرسوم الدقيقة ومدة الوثيقة المختارة، مثل خياري 4 سنوات مقابل 8 سنوات.) المصدر: Service Oklahoma 'CDL Renewal/Replacement Online' (oklahoma.gov)."}}};
